(window.__KJV_BOOKS__=window.__KJV_BOOKS__||[]).push({"name":"Psalms","chapters":[{"chapter":1,"verses":[{"verse":1,"text":"Blessed is the man that walketh not in the counsel of the ungodly, nor standeth in the way of sinners, nor sitteth in the seat of the scornful."},{"verse":2,"text":"But his delight is in the law of the Lord; and in his law doth he meditate day and night."},{"verse":3,"text":"And he shall be like a tree planted by the rivers of water, that bringeth forth his fruit in his season; his leaf also shall not wither; and whatsoever he doeth shall prosper."},{"verse":4,"text":"The ungodly are not so: but are like the chaff which the wind driveth away."},{"verse":5,"text":"Therefore the ungodly shall not stand in the judgment, nor sinners in the congregation of the righteous."},{"verse":6,"text":"For the Lord knoweth the way of the righteous: but the way of the ungodly shall perish. "}]},{"chapter":2,"verses":[{"verse":1,"text":"Why do the heathen rage, and the people imagine a vain thing?"},{"verse":2,"text":"The kings of the earth set themselves, and the rulers take counsel together, against the Lord, and against his anointed, saying,"},{"verse":3,"text":"Let us break their bands asunder, and cast away their cords from us."},{"verse":4,"text":"He that sitteth in the heavens shall laugh: the Lord shall have them in derision."},{"verse":5,"text":"Then shall he speak unto them in his wrath, and vex them in his sore displeasure."},{"verse":6,"text":"Yet have I set my king upon my holy hill of Zion."},{"verse":7,"text":"I will declare the decree: the Lord hath said unto me, Thou art my Son; this day have I begotten thee."},{"verse":8,"text":"Ask of me, and I shall give thee the heathen for thine inheritance, and the uttermost parts of the earth for thy possession."},{"verse":9,"text":"Thou shalt break them with a rod of iron; thou shalt dash them in pieces like a potter’s vessel."},{"verse":10,"text":"Be wise now therefore, O ye kings: be instructed, ye judges of the earth."},{"verse":11,"text":"Serve the Lord with fear, and rejoice with trembling."},{"verse":12,"text":"Kiss the Son, lest he be angry, and ye perish from the way, when his wrath is kindled but a little. Blessed are all they that put their trust in him. "}]},{"chapter":3,"verses":[{"verse":1,"text":"Lord, how are they increased that trouble me! many are they that rise up against me."},{"verse":2,"text":"Many there be which say of my soul, There is no help for him in God. Selah."},{"verse":3,"text":"But thou, O Lord, art a shield for me; my glory, and the lifter up of mine head."},{"verse":4,"text":"I cried unto the Lord with my voice, and he heard me out of his holy hill. Selah."},{"verse":5,"text":"I laid me down and slept; I awaked; for the Lord sustained me."},{"verse":6,"text":"I will not be afraid of ten thousands of people, that have set themselves against me round about."},{"verse":7,"text":"Arise, O Lord; save me, O my God: for thou hast smitten all mine enemies upon the cheek bone; thou hast broken the teeth of the ungodly."},{"verse":8,"text":"Salvation belongeth unto the Lord: thy blessing is upon thy people. Selah. "}]},{"chapter":4,"verses":[{"verse":1,"text":"Hear me when I call, O God of my righteousness: thou hast enlarged me when I was in distress; have mercy upon me, and hear my prayer."},{"verse":2,"text":"O ye sons of men, how long will ye turn my glory into shame? how long will ye love vanity, and seek after leasing? Selah."},{"verse":3,"text":"But know that the Lord hath set apart him that is godly for himself: the Lord will hear when I call unto him."},{"verse":4,"text":"Stand in awe, and sin not: commune with your own heart upon your bed, and be still. Selah."},{"verse":5,"text":"Offer the sacrifices of righteousness, and put your trust in the Lord."},{"verse":6,"text":"There be many that say, Who will shew us any good? Lord, lift thou up the light of thy countenance upon us."},{"verse":7,"text":"Thou hast put gladness in my heart, more than in the time that their corn and their wine increased."},{"verse":8,"text":"I will both lay me down in peace, and sleep: for thou, Lord, only makest me dwell in safety. "}]},{"chapter":5,"verses":[{"verse":1,"text":"Give ear to my words, O Lord, consider my meditation."},{"verse":2,"text":"Hearken unto the voice of my cry, my King, and my God: for unto thee will I pray."},{"verse":3,"text":"My voice shalt thou hear in the morning, O Lord; in the morning will I direct my prayer unto thee, and will look up."},{"verse":4,"text":"For thou art not a God that hath pleasure in wickedness: neither shall evil dwell with thee."},{"verse":5,"text":"The foolish shall not stand in thy sight: thou hatest all workers of iniquity."},{"verse":6,"text":"Thou shalt destroy them that speak leasing: the Lord will abhor the bloody and deceitful man."},{"verse":7,"text":"But as for me, I will come into thy house in the multitude of thy mercy: and in thy fear will I worship toward thy holy temple."},{"verse":8,"text":"Lead me, O Lord, in thy righteousness because of mine enemies; make thy way straight before my face."},{"verse":9,"text":"For there is no faithfulness in their mouth; their inward part is very wickedness; their throat is an open sepulchre; they flatter with their tongue."},{"verse":10,"text":"Destroy thou them, O God; let them fall by their own counsels; cast them out in the multitude of their transgressions; for they have rebelled against thee."},{"verse":11,"text":"But let all those that put their trust in thee rejoice: let them ever shout for joy, because thou defendest them: let them also that love thy name be joyful in thee."},{"verse":12,"text":"For thou, Lord, wilt bless the righteous; with favour wilt thou compass him as with a shield. "}]},{"chapter":6,"verses":[{"verse":1,"text":"O Lord, rebuke me not in thine anger, neither chasten me in thy hot displeasure."},{"verse":2,"text":"Have mercy upon me, O Lord; for I am weak: O Lord, heal me; for my bones are vexed."},{"verse":3,"text":"My soul is also sore vexed: but thou, O Lord, how long?"},{"verse":4,"text":"Return, O Lord, deliver my soul: oh save me for thy mercies’ sake."},{"verse":5,"text":"For in death there is no remembrance of thee: in the grave who shall give thee thanks?"},{"verse":6,"text":"I am weary with my groaning; all the night make I my bed to swim; I water my couch with my tears."},{"verse":7,"text":"Mine eye is consumed because of grief; it waxeth old because of all mine enemies."},{"verse":8,"text":"Depart from me, all ye workers of iniquity; for the Lord hath heard the voice of my weeping."},{"verse":9,"text":"The Lord hath heard my supplication; the Lord will receive my prayer."},{"verse":10,"text":"Let all mine enemies be ashamed and sore vexed: let them return and be ashamed suddenly. "}]},{"chapter":7,"verses":[{"verse":1,"text":"O Lord my God, in thee do I put my trust: save me from all them that persecute me, and deliver me:"},{"verse":2,"text":"Lest he tear my soul like a lion, rending it in pieces, while there is none to deliver."},{"verse":3,"text":"O Lord my God, if I have done this; if there be iniquity in my hands;"},{"verse":4,"text":"If I have rewarded evil unto him that was at peace with me; (yea, I have delivered him that without cause is mine enemy:)"},{"verse":5,"text":"Let the enemy persecute my soul, and take it; yea, let him tread down my life upon the earth, and lay mine honour in the dust. Selah."},{"verse":6,"text":"Arise, O Lord, in thine anger, lift up thyself because of the rage of mine enemies: and awake for me to the judgment that thou hast commanded."},{"verse":7,"text":"So shall the congregation of the people compass thee about: for their sakes therefore return thou on high."},{"verse":8,"text":"The Lord shall judge the people: judge me, O Lord, according to my righteousness, and according to mine integrity that is in me."},{"verse":9,"text":"Oh let the wickedness of the wicked come to an end; but establish the just: for the righteous God trieth the hearts and reins."},{"verse":10,"text":"My defence is of God, which saveth the upright in heart."},{"verse":11,"text":"God judgeth the righteous, and God is angry with the wicked every day."},{"verse":12,"text":"If he turn not, he will whet his sword; he hath bent his bow, and made it ready."},{"verse":13,"text":"He hath also prepared for him the instruments of death; he ordaineth his arrows against the persecutors."},{"verse":14,"text":"Behold, he travaileth with iniquity, and hath conceived mischief, and brought forth falsehood."},{"verse":15,"text":"He made a pit, and digged it, and is fallen into the ditch which he made."},{"verse":16,"text":"His mischief shall return upon his own head, and his violent dealing shall come down upon his own pate."},{"verse":17,"text":"I will praise the Lord according to his righteousness: and will sing praise to the name of the Lord most high. "}]},{"chapter":8,"verses":[{"verse":1,"text":"O Lord our Lord, how excellent is thy name in all the earth! who hast set thy glory above the heavens."},{"verse":2,"text":"Out of the mouth of babes and sucklings hast thou ordained strength because of thine enemies, that thou mightest still the enemy and the avenger."},{"verse":3,"text":"When I consider thy heavens, the work of thy fingers, the moon and the stars, which thou hast ordained;"},{"verse":4,"text":"What is man, that thou art mindful of him? and the son of man, that thou visitest him?"},{"verse":5,"text":"For thou hast made him a little lower than the angels, and hast crowned him with glory and honour."},{"verse":6,"text":"Thou madest him to have dominion over the works of thy hands; thou hast put all things under his feet:"},{"verse":7,"text":"All sheep and oxen, yea, and the beasts of the field;"},{"verse":8,"text":"The fowl of the air, and the fish of the sea, and whatsoever passeth through the paths of the seas."},{"verse":9,"text":"O Lord our Lord, how excellent is thy name in all the earth! "}]},{"chapter":9,"verses":[{"verse":1,"text":"I will praise thee, O Lord, with my whole heart; I will shew forth all thy marvellous works."},{"verse":2,"text":"I will be glad and rejoice in thee: I will sing praise to thy name, O thou most High."},{"verse":3,"text":"When mine enemies are turned back, they shall fall and perish at thy presence."},{"verse":4,"text":"For thou hast maintained my right and my cause; thou satest in the throne judging right."},{"verse":5,"text":"Thou hast rebuked the heathen, thou hast destroyed the wicked, thou hast put out their name for ever and ever."},{"verse":6,"text":"O thou enemy, destructions are come to a perpetual end: and thou hast destroyed cities; their memorial is perished with them."},{"verse":7,"text":"But the Lord shall endure for ever: he hath prepared his throne for judgment."},{"verse":8,"text":"And he shall judge the world in righteousness, he shall minister judgment to the people in uprightness."},{"verse":9,"text":"The Lord also will be a refuge for the oppressed, a refuge in times of trouble."},{"verse":10,"text":"And they that know thy name will put their trust in thee: for thou, Lord, hast not forsaken them that seek thee."},{"verse":11,"text":"Sing praises to the Lord, which dwelleth in Zion: declare among the people his doings."},{"verse":12,"text":"When he maketh inquisition for blood, he remembereth them: he forgetteth not the cry of the humble."},{"verse":13,"text":"Have mercy upon me, O Lord; consider my trouble which I suffer of them that hate me, thou that liftest me up from the gates of death:"},{"verse":14,"text":"That I may shew forth all thy praise in the gates of the daughter of Zion: I will rejoice in thy salvation."},{"verse":15,"text":"The heathen are sunk down in the pit that they made: in the net which they hid is their own foot taken."},{"verse":16,"text":"The Lord is known by the judgment which he executeth: the wicked is snared in the work of his own hands. Higgaion. Selah."},{"verse":17,"text":"The wicked shall be turned into hell, and all the nations that forget God."},{"verse":18,"text":"For the needy shall not alway be forgotten: the expectation of the poor shall not perish for ever."},{"verse":19,"text":"Arise, O Lord; let not man prevail: let the heathen be judged in thy sight."},{"verse":20,"text":"Put them in fear, O Lord: that the nations may know themselves to be but men. Selah. "}]},{"chapter":10,"verses":[{"verse":1,"text":"Why standest thou afar off, O Lord? why hidest thou thyself in times of trouble?"},{"verse":2,"text":"The wicked in his pride doth persecute the poor: let them be taken in the devices that they have imagined."},{"verse":3,"text":"For the wicked boasteth of his heart’s desire, and blesseth the covetous, whom the Lord abhorreth."},{"verse":4,"text":"The wicked, through the pride of his countenance, will not seek after God: God is not in all his thoughts."},{"verse":5,"text":"His ways are always grievous; thy judgments are far above out of his sight: as for all his enemies, he puffeth at them."},{"verse":6,"text":"He hath said in his heart, I shall not be moved: for I shall never be in adversity."},{"verse":7,"text":"His mouth is full of cursing and deceit and fraud: under his tongue is mischief and vanity."},{"verse":8,"text":"He sitteth in the lurking places of the villages: in the secret places doth he murder the innocent: his eyes are privily set against the poor."},{"verse":9,"text":"He lieth in wait secretly as a lion in his den: he lieth in wait to catch the poor: he doth catch the poor, when he draweth him into his net."},{"verse":10,"text":"He croucheth, and humbleth himself, that the poor may fall by his strong ones."},{"verse":11,"text":"He hath said in his heart, God hath forgotten: he hideth his face; he will never see it."},{"verse":12,"text":"Arise, O Lord; O God, lift up thine hand: forget not the humble."},{"verse":13,"text":"Wherefore doth the wicked contemn God? he hath said in his heart, Thou wilt not require it."},{"verse":14,"text":"Thou hast seen it; for thou beholdest mischief and spite, to requite it with thy hand: the poor committeth himself unto thee; thou art the helper of the fatherless."},{"verse":15,"text":"Break thou the arm of the wicked and the evil man: seek out his wickedness till thou find none."},{"verse":16,"text":"The Lord is King for ever and ever: the heathen are perished out of his land."},{"verse":17,"text":"Lord, thou hast heard the desire of the humble: thou wilt prepare their heart, thou wilt cause thine ear to hear:"},{"verse":18,"text":"To judge the fatherless and the oppressed, that the man of the earth may no more oppress. "}]},{"chapter":11,"verses":[{"verse":1,"text":"In the Lord put I my trust: how say ye to my soul, Flee as a bird to your mountain?"},{"verse":2,"text":"For, lo, the wicked bend their bow, they make ready their arrow upon the string, that they may privily shoot at the upright in heart."},{"verse":3,"text":"If the foundations be destroyed, what can the righteous do?"},{"verse":4,"text":"The Lord is in his holy temple, the Lord’s throne is in heaven: his eyes behold, his eyelids try, the children of men."},{"verse":5,"text":"The Lord trieth the righteous: but the wicked and him that loveth violence his soul hateth."},{"verse":6,"text":"Upon the wicked he shall rain snares, fire and brimstone, and an horrible tempest: this shall be the portion of their cup."},{"verse":7,"text":"For the righteous Lord loveth righteousness; his countenance doth behold the upright. "}]},{"chapter":12,"verses":[{"verse":1,"text":"Help, Lord; for the godly man ceaseth; for the faithful fail from among the children of men."},{"verse":2,"text":"They speak vanity every one with his neighbour: with flattering lips and with a double heart do they speak."},{"verse":3,"text":"The Lord shall cut off all flattering lips, and the tongue that speaketh proud things:"},{"verse":4,"text":"Who have said, With our tongue will we prevail; our lips are our own: who is lord over us?"},{"verse":5,"text":"For the oppression of the poor, for the sighing of the needy, now will I arise, saith the Lord; I will set him in safety from him that puffeth at him."},{"verse":6,"text":"The words of the Lord are pure words: as silver tried in a furnace of earth, purified seven times."},{"verse":7,"text":"Thou shalt keep them, O Lord, thou shalt preserve them from this generation for ever."},{"verse":8,"text":"The wicked walk on every side, when the vilest men are exalted. "}]},{"chapter":13,"verses":[{"verse":1,"text":"How long wilt thou forget me, O Lord? for ever? how long wilt thou hide thy face from me?"},{"verse":2,"text":"How long shall I take counsel in my soul, having sorrow in my heart daily? how long shall mine enemy be exalted over me?"},{"verse":3,"text":"Consider and hear me, O Lord my God: lighten mine eyes, lest I sleep the sleep of death;"},{"verse":4,"text":"Lest mine enemy say, I have prevailed against him; and those that trouble me rejoice when I am moved."},{"verse":5,"text":"But I have trusted in thy mercy; my heart shall rejoice in thy salvation."},{"verse":6,"text":"I will sing unto the Lord, because he hath dealt bountifully with me. "}]},{"chapter":14,"verses":[{"verse":1,"text":"The fool hath said in his heart, There is no God. They are corrupt, they have done abominable works, there is none that doeth good."},{"verse":2,"text":"The Lord looked down from heaven upon the children of men, to see if there were any that did understand, and seek God."},{"verse":3,"text":"They are all gone aside, they are all together become filthy: there is none that doeth good, no, not one."},{"verse":4,"text":"Have all the workers of iniquity no knowledge? who eat up my people as they eat bread, and call not upon the Lord."},{"verse":5,"text":"There were they in great fear: for God is in the generation of the righteous."},{"verse":6,"text":"Ye have shamed the counsel of the poor, because the Lord is his refuge."},{"verse":7,"text":"Oh that the salvation of Israel were come out of Zion! when the Lord bringeth back the captivity of his people, Jacob shall rejoice, and Israel shall be glad. "}]},{"chapter":15,"verses":[{"verse":1,"text":"Lord, who shall abide in thy tabernacle? who shall dwell in thy holy hill?"},{"verse":2,"text":"He that walketh uprightly, and worketh righteousness, and speaketh the truth in his heart."},{"verse":3,"text":"He that backbiteth not with his tongue, nor doeth evil to his neighbour, nor taketh up a reproach against his neighbour."},{"verse":4,"text":"In whose eyes a vile person is contemned; but he honoureth them that fear the Lord. He that sweareth to his own hurt, and changeth not."},{"verse":5,"text":"He that putteth not out his money to usury, nor taketh reward against the innocent. He that doeth these things shall never be moved. "}]},{"chapter":16,"verses":[{"verse":1,"text":"Preserve me, O God: for in thee do I put my trust."},{"verse":2,"text":"O my soul, thou hast said unto the Lord, Thou art my Lord: my goodness extendeth not to thee;"},{"verse":3,"text":"But to the saints that are in the earth, and to the excellent, in whom is all my delight."},{"verse":4,"text":"Their sorrows shall be multiplied that hasten after another god: their drink offerings of blood will I not offer, nor take up their names into my lips."},{"verse":5,"text":"The Lord is the portion of mine inheritance and of my cup: thou maintainest my lot."},{"verse":6,"text":"The lines are fallen unto me in pleasant places; yea, I have a goodly heritage."},{"verse":7,"text":"I will bless the Lord, who hath given me counsel: my reins also instruct me in the night seasons."},{"verse":8,"text":"I have set the Lord always before me: because he is at my right hand, I shall not be moved."},{"verse":9,"text":"Therefore my heart is glad, and my glory rejoiceth: my flesh also shall rest in hope."},{"verse":10,"text":"For thou wilt not leave my soul in hell; neither wilt thou suffer thine Holy One to see corruption."},{"verse":11,"text":"Thou wilt shew me the path of life: in thy presence is fulness of joy; at thy right hand there are pleasures for evermore. "}]},{"chapter":17,"verses":[{"verse":1,"text":"Hear the right, O Lord, attend unto my cry, give ear unto my prayer, that goeth not out of feigned lips."},{"verse":2,"text":"Let my sentence come forth from thy presence; let thine eyes behold the things that are equal."},{"verse":3,"text":"Thou hast proved mine heart; thou hast visited me in the night; thou hast tried me, and shalt find nothing; I am purposed that my mouth shall not transgress."},{"verse":4,"text":"Concerning the works of men, by the word of thy lips I have kept me from the paths of the destroyer."},{"verse":5,"text":"Hold up my goings in thy paths, that my footsteps slip not."},{"verse":6,"text":"I have called upon thee, for thou wilt hear me, O God: incline thine ear unto me, and hear my speech."},{"verse":7,"text":"Shew thy marvellous lovingkindness, O thou that savest by thy right hand them which put their trust in thee from those that rise up against them."},{"verse":8,"text":"Keep me as the apple of the eye, hide me under the shadow of thy wings,"},{"verse":9,"text":"From the wicked that oppress me, from my deadly enemies, who compass me about."},{"verse":10,"text":"They are inclosed in their own fat: with their mouth they speak proudly."},{"verse":11,"text":"They have now compassed us in our steps: they have set their eyes bowing down to the earth;"},{"verse":12,"text":"Like as a lion that is greedy of his prey, and as it were a young lion lurking in secret places."},{"verse":13,"text":"Arise, O Lord, disappoint him, cast him down: deliver my soul from the wicked, which is thy sword:"},{"verse":14,"text":"From men which are thy hand, O Lord, from men of the world, which have their portion in this life, and whose belly thou fillest with thy hid treasure: they are full of children, and leave the rest of their substance to their babes."},{"verse":15,"text":"As for me, I will behold thy face in righteousness: I shall be satisfied, when I awake, with thy likeness. "}]},{"chapter":18,"verses":[{"verse":1,"text":"I will love thee, O Lord, my strength."},{"verse":2,"text":"The Lord is my rock, and my fortress, and my deliverer; my God, my strength, in whom I will trust; my buckler, and the horn of my salvation, and my high tower."},{"verse":3,"text":"I will call upon the Lord, who is worthy to be praised: so shall I be saved from mine enemies."},{"verse":4,"text":"The sorrows of death compassed me, and the floods of ungodly men made me afraid."},{"verse":5,"text":"The sorrows of hell compassed me about: the snares of death prevented me."},{"verse":6,"text":"In my distress I called upon the Lord, and cried unto my God: he heard my voice out of his temple, and my cry came before him, even into his ears."},{"verse":7,"text":"Then the earth shook and trembled; the foundations also of the hills moved and were shaken, because he was wroth."},{"verse":8,"text":"There went up a smoke out of his nostrils, and fire out of his mouth devoured: coals were kindled by it."},{"verse":9,"text":"He bowed the heavens also, and came down: and darkness was under his feet."},{"verse":10,"text":"And he rode upon a cherub, and did fly: yea, he did fly upon the wings of the wind."},{"verse":11,"text":"He made darkness his secret place; his pavilion round about him were dark waters and thick clouds of the skies."},{"verse":12,"text":"At the brightness that was before him his thick clouds passed, hail stones and coals of fire."},{"verse":13,"text":"The Lord also thundered in the heavens, and the Highest gave his voice; hail stones and coals of fire."},{"verse":14,"text":"Yea, he sent out his arrows, and scattered them; and he shot out lightnings, and discomfited them."},{"verse":15,"text":"Then the channels of waters were seen, and the foundations of the world were discovered at thy rebuke, O Lord, at the blast of the breath of thy nostrils."},{"verse":16,"text":"He sent from above, he took me, he drew me out of many waters."},{"verse":17,"text":"He delivered me from my strong enemy, and from them which hated me: for they were too strong for me."},{"verse":18,"text":"They prevented me in the day of my calamity: but the Lord was my stay."},{"verse":19,"text":"He brought me forth also into a large place; he delivered me, because he delighted in me."},{"verse":20,"text":"The Lord rewarded me according to my righteousness; according to the cleanness of my hands hath he recompensed me."},{"verse":21,"text":"For I have kept the ways of the Lord, and have not wickedly departed from my God."},{"verse":22,"text":"For all his judgments were before me, and I did not put away his statutes from me."},{"verse":23,"text":"I was also upright before him, and I kept myself from mine iniquity."},{"verse":24,"text":"Therefore hath the Lord recompensed me according to my righteousness, according to the cleanness of my hands in his eyesight."},{"verse":25,"text":"With the merciful thou wilt shew thyself merciful; with an upright man thou wilt shew thyself upright;"},{"verse":26,"text":"With the pure thou wilt shew thyself pure; and with the froward thou wilt shew thyself froward."},{"verse":27,"text":"For thou wilt save the afflicted people; but wilt bring down high looks."},{"verse":28,"text":"For thou wilt light my candle: the Lord my God will enlighten my darkness."},{"verse":29,"text":"For by thee I have run through a troop; and by my God have I leaped over a wall."},{"verse":30,"text":"As for God, his way is perfect: the word of the Lord is tried: he is a buckler to all those that trust in him."},{"verse":31,"text":"For who is God save the Lord? or who is a rock save our God?"},{"verse":32,"text":"It is God that girdeth me with strength, and maketh my way perfect."},{"verse":33,"text":"He maketh my feet like hinds’ feet, and setteth me upon my high places."},{"verse":34,"text":"He teacheth my hands to war, so that a bow of steel is broken by mine arms."},{"verse":35,"text":"Thou hast also given me the shield of thy salvation: and thy right hand hath holden me up, and thy gentleness hath made me great."},{"verse":36,"text":"Thou hast enlarged my steps under me, that my feet did not slip."},{"verse":37,"text":"I have pursued mine enemies, and overtaken them: neither did I turn again till they were consumed."},{"verse":38,"text":"I have wounded them that they were not able to rise: they are fallen under my feet."},{"verse":39,"text":"For thou hast girded me with strength unto the battle: thou hast subdued under me those that rose up against me."},{"verse":40,"text":"Thou hast also given me the necks of mine enemies; that I might destroy them that hate me."},{"verse":41,"text":"They cried, but there was none to save them: even unto the Lord, but he answered them not."},{"verse":42,"text":"Then did I beat them small as the dust before the wind: I did cast them out as the dirt in the streets."},{"verse":43,"text":"Thou hast delivered me from the strivings of the people; and thou hast made me the head of the heathen: a people whom I have not known shall serve me."},{"verse":44,"text":"As soon as they hear of me, they shall obey me: the strangers shall submit themselves unto me."},{"verse":45,"text":"The strangers shall fade away, and be afraid out of their close places."},{"verse":46,"text":"The Lord liveth; and blessed be my rock; and let the God of my salvation be exalted."},{"verse":47,"text":"It is God that avengeth me, and subdueth the people under me."},{"verse":48,"text":"He delivereth me from mine enemies: yea, thou liftest me up above those that rise up against me: thou hast delivered me from the violent man."},{"verse":49,"text":"Therefore will I give thanks unto thee, O Lord, among the heathen, and sing praises unto thy name."},{"verse":50,"text":"Great deliverance giveth he to his king; and sheweth mercy to his anointed, to David, and to his seed for evermore. "}]},{"chapter":19,"verses":[{"verse":1,"text":"The heavens declare the glory of God; and the firmament sheweth his handywork."},{"verse":2,"text":"Day unto day uttereth speech, and night unto night sheweth knowledge."},{"verse":3,"text":"There is no speech nor language, where their voice is not heard."},{"verse":4,"text":"Their line is gone out through all the earth, and their words to the end of the world. In them hath he set a tabernacle for the sun,"},{"verse":5,"text":"Which is as a bridegroom coming out of his chamber, and rejoiceth as a strong man to run a race."},{"verse":6,"text":"His going forth is from the end of the heaven, and his circuit unto the ends of it: and there is nothing hid from the heat thereof."},{"verse":7,"text":"The law of the Lord is perfect, converting the soul: the testimony of the Lord is sure, making wise the simple."},{"verse":8,"text":"The statutes of the Lord are right, rejoicing the heart: the commandment of the Lord is pure, enlightening the eyes."},{"verse":9,"text":"The fear of the Lord is clean, enduring for ever: the judgments of the Lord are true and righteous altogether."},{"verse":10,"text":"More to be desired are they than gold, yea, than much fine gold: sweeter also than honey and the honeycomb."},{"verse":11,"text":"Moreover by them is thy servant warned: and in keeping of them there is great reward."},{"verse":12,"text":"Who can understand his errors? cleanse thou me from secret faults."},{"verse":13,"text":"Keep back thy servant also from presumptuous sins; let them not have dominion over me: then shall I be upright, and I shall be innocent from the great transgression."},{"verse":14,"text":"Let the words of my mouth, and the meditation of my heart, be acceptable in thy sight, O Lord, my strength, and my redeemer. "}]},{"chapter":20,"verses":[{"verse":1,"text":"The Lord hear thee in the day of trouble; the name of the God of Jacob defend thee;"},{"verse":2,"text":"Send thee help from the sanctuary, and strengthen thee out of Zion;"},{"verse":3,"text":"Remember all thy offerings, and accept thy burnt sacrifice; Selah."},{"verse":4,"text":"Grant thee according to thine own heart, and fulfil all thy counsel."},{"verse":5,"text":"We will rejoice in thy salvation, and in the name of our God we will set up our banners: the Lord fulfil all thy petitions."},{"verse":6,"text":"Now know I that the Lord saveth his anointed; he will hear him from his holy heaven with the saving strength of his right hand."},{"verse":7,"text":"Some trust in chariots, and some in horses: but we will remember the name of the Lord our God."},{"verse":8,"text":"They are brought down and fallen: but we are risen, and stand upright."},{"verse":9,"text":"Save, Lord: let the king hear us when we call. "}]},{"chapter":21,"verses":[{"verse":1,"text":"The king shall joy in thy strength, O Lord; and in thy salvation how greatly shall he rejoice!"},{"verse":2,"text":"Thou hast given him his heart’s desire, and hast not withholden the request of his lips. Selah."},{"verse":3,"text":"For thou preventest him with the blessings of goodness: thou settest a crown of pure gold on his head."},{"verse":4,"text":"He asked life of thee, and thou gavest it him, even length of days for ever and ever."},{"verse":5,"text":"His glory is great in thy salvation: honour and majesty hast thou laid upon him."},{"verse":6,"text":"For thou hast made him most blessed for ever: thou hast made him exceeding glad with thy countenance."},{"verse":7,"text":"For the king trusteth in the Lord, and through the mercy of the most High he shall not be moved."},{"verse":8,"text":"Thine hand shall find out all thine enemies: thy right hand shall find out those that hate thee."},{"verse":9,"text":"Thou shalt make them as a fiery oven in the time of thine anger: the Lord shall swallow them up in his wrath, and the fire shall devour them."},{"verse":10,"text":"Their fruit shalt thou destroy from the earth, and their seed from among the children of men."},{"verse":11,"text":"For they intended evil against thee: they imagined a mischievous device, which they are not able to perform."},{"verse":12,"text":"Therefore shalt thou make them turn their back, when thou shalt make ready thine arrows upon thy strings against the face of them."},{"verse":13,"text":"Be thou exalted, Lord, in thine own strength: so will we sing and praise thy power. "}]},{"chapter":22,"verses":[{"verse":1,"text":"My God, my God, why hast thou forsaken me? why art thou so far from helping me, and from the words of my roaring?"},{"verse":2,"text":"O my God, I cry in the daytime, but thou hearest not; and in the night season, and am not silent."},{"verse":3,"text":"But thou art holy, O thou that inhabitest the praises of Israel."},{"verse":4,"text":"Our fathers trusted in thee: they trusted, and thou didst deliver them."},{"verse":5,"text":"They cried unto thee, and were delivered: they trusted in thee, and were not confounded."},{"verse":6,"text":"But I am a worm, and no man; a reproach of men, and despised of the people."},{"verse":7,"text":"All they that see me laugh me to scorn: they shoot out the lip, they shake the head, saying,"},{"verse":8,"text":"He trusted on the Lord that he would deliver him: let him deliver him, seeing he delighted in him."},{"verse":9,"text":"But thou art he that took me out of the womb: thou didst make me hope when I was upon my mother’s breasts."},{"verse":10,"text":"I was cast upon thee from the womb: thou art my God from my mother’s belly."},{"verse":11,"text":"Be not far from me; for trouble is near; for there is none to help."},{"verse":12,"text":"Many bulls have compassed me: strong bulls of Bashan have beset me round."},{"verse":13,"text":"They gaped upon me with their mouths, as a ravening and a roaring lion."},{"verse":14,"text":"I am poured out like water, and all my bones are out of joint: my heart is like wax; it is melted in the midst of my bowels."},{"verse":15,"text":"My strength is dried up like a potsherd; and my tongue cleaveth to my jaws; and thou hast brought me into the dust of death."},{"verse":16,"text":"For dogs have compassed me: the assembly of the wicked have inclosed me: they pierced my hands and my feet."},{"verse":17,"text":"I may tell all my bones: they look and stare upon me."},{"verse":18,"text":"They part my garments among them, and cast lots upon my vesture."},{"verse":19,"text":"But be not thou far from me, O Lord: O my strength, haste thee to help me."},{"verse":20,"text":"Deliver my soul from the sword; my darling from the power of the dog."},{"verse":21,"text":"Save me from the lion’s mouth: for thou hast heard me from the horns of the unicorns."},{"verse":22,"text":"I will declare thy name unto my brethren: in the midst of the congregation will I praise thee."},{"verse":23,"text":"Ye that fear the Lord, praise him; all ye the seed of Jacob, glorify him; and fear him, all ye the seed of Israel."},{"verse":24,"text":"For he hath not despised nor abhorred the affliction of the afflicted; neither hath he hid his face from him; but when he cried unto him, he heard."},{"verse":25,"text":"My praise shall be of thee in the great congregation: I will pay my vows before them that fear him."},{"verse":26,"text":"The meek shall eat and be satisfied: they shall praise the Lord that seek him: your heart shall live for ever."},{"verse":27,"text":"All the ends of the world shall remember and turn unto the Lord: and all the kindreds of the nations shall worship before thee."},{"verse":28,"text":"For the kingdom is the Lord’s: and he is the governor among the nations."},{"verse":29,"text":"All they that be fat upon earth shall eat and worship: all they that go down to the dust shall bow before him: and none can keep alive his own soul."},{"verse":30,"text":"A seed shall serve him; it shall be accounted to the Lord for a generation."},{"verse":31,"text":"They shall come, and shall declare his righteousness unto a people that shall be born, that he hath done this. "}]},{"chapter":23,"verses":[{"verse":1,"text":"The Lord is my shepherd; I shall not want."},{"verse":2,"text":"He maketh me to lie down in green pastures: he leadeth me beside the still waters."},{"verse":3,"text":"He restoreth my soul: he leadeth me in the paths of righteousness for his name’s sake."},{"verse":4,"text":"Yea, though I walk through the valley of the shadow of death, I will fear no evil: for thou art with me; thy rod and thy staff they comfort me."},{"verse":5,"text":"Thou preparest a table before me in the presence of mine enemies: thou anointest my head with oil; my cup runneth over."},{"verse":6,"text":"Surely goodness and mercy shall follow me all the days of my life: and I will dwell in the house of the Lord for ever. "}]},{"chapter":24,"verses":[{"verse":1,"text":"The earth is the Lord’s, and the fulness thereof; the world, and they that dwell therein."},{"verse":2,"text":"For he hath founded it upon the seas, and established it upon the floods."},{"verse":3,"text":"Who shall ascend into the hill of the Lord? or who shall stand in his holy place?"},{"verse":4,"text":"He that hath clean hands, and a pure heart; who hath not lifted up his soul unto vanity, nor sworn deceitfully."},{"verse":5,"text":"He shall receive the blessing from the Lord, and righteousness from the God of his salvation."},{"verse":6,"text":"This is the generation of them that seek him, that seek thy face, O Jacob. Selah."},{"verse":7,"text":"Lift up your heads, O ye gates; and be ye lift up, ye everlasting doors; and the King of glory shall come in."},{"verse":8,"text":"Who is this King of glory? The Lord strong and mighty, the Lord mighty in battle."},{"verse":9,"text":"Lift up your heads, O ye gates; even lift them up, ye everlasting doors; and the King of glory shall come in."},{"verse":10,"text":"Who is this King of glory? The Lord of hosts, he is the King of glory. Selah. "}]},{"chapter":25,"verses":[{"verse":1,"text":"Unto thee, O Lord, do I lift up my soul."},{"verse":2,"text":"O my God, I trust in thee: let me not be ashamed, let not mine enemies triumph over me."},{"verse":3,"text":"Yea, let none that wait on thee be ashamed: let them be ashamed which transgress without cause."},{"verse":4,"text":"Shew me thy ways, O Lord; teach me thy paths."},{"verse":5,"text":"Lead me in thy truth, and teach me: for thou art the God of my salvation; on thee do I wait all the day."},{"verse":6,"text":"Remember, O Lord, thy tender mercies and thy lovingkindnesses; for they have been ever of old."},{"verse":7,"text":"Remember not the sins of my youth, nor my transgressions: according to thy mercy remember thou me for thy goodness’ sake, O Lord."},{"verse":8,"text":"Good and upright is the Lord: therefore will he teach sinners in the way."},{"verse":9,"text":"The meek will he guide in judgment: and the meek will he teach his way."},{"verse":10,"text":"All the paths of the Lord are mercy and truth unto such as keep his covenant and his testimonies."},{"verse":11,"text":"For thy name’s sake, O Lord, pardon mine iniquity; for it is great."},{"verse":12,"text":"What man is he that feareth the Lord? him shall he teach in the way that he shall choose."},{"verse":13,"text":"His soul shall dwell at ease; and his seed shall inherit the earth."},{"verse":14,"text":"The secret of the Lord is with them that fear him; and he will shew them his covenant."},{"verse":15,"text":"Mine eyes are ever toward the Lord; for he shall pluck my feet out of the net."},{"verse":16,"text":"Turn thee unto me, and have mercy upon me; for I am desolate and afflicted."},{"verse":17,"text":"The troubles of my heart are enlarged: O bring thou me out of my distresses."},{"verse":18,"text":"Look upon mine affliction and my pain; and forgive all my sins."},{"verse":19,"text":"Consider mine enemies; for they are many; and they hate me with cruel hatred."},{"verse":20,"text":"O keep my soul, and deliver me: let me not be ashamed; for I put my trust in thee."},{"verse":21,"text":"Let integrity and uprightness preserve me; for I wait on thee."},{"verse":22,"text":"Redeem Israel, O God, out of all his troubles. "}]},{"chapter":26,"verses":[{"verse":1,"text":"Judge me, O Lord; for I have walked in mine integrity: I have trusted also in the Lord; therefore I shall not slide."},{"verse":2,"text":"Examine me, O Lord, and prove me; try my reins and my heart."},{"verse":3,"text":"For thy lovingkindness is before mine eyes: and I have walked in thy truth."},{"verse":4,"text":"I have not sat with vain persons, neither will I go in with dissemblers."},{"verse":5,"text":"I have hated the congregation of evil doers; and will not sit with the wicked."},{"verse":6,"text":"I will wash mine hands in innocency: so will I compass thine altar, O Lord:"},{"verse":7,"text":"That I may publish with the voice of thanksgiving, and tell of all thy wondrous works."},{"verse":8,"text":"Lord, I have loved the habitation of thy house, and the place where thine honour dwelleth."},{"verse":9,"text":"Gather not my soul with sinners, nor my life with bloody men:"},{"verse":10,"text":"In whose hands is mischief, and their right hand is full of bribes."},{"verse":11,"text":"But as for me, I will walk in mine integrity: redeem me, and be merciful unto me."},{"verse":12,"text":"My foot standeth in an even place: in the congregations will I bless the Lord. "}]},{"chapter":27,"verses":[{"verse":1,"text":"The Lord is my light and my salvation; whom shall I fear? the Lord is the strength of my life; of whom shall I be afraid?"},{"verse":2,"text":"When the wicked, even mine enemies and my foes, came upon me to eat up my flesh, they stumbled and fell."},{"verse":3,"text":"Though an host should encamp against me, my heart shall not fear: though war should rise against me, in this will I be confident."},{"verse":4,"text":"One thing have I desired of the Lord, that will I seek after; that I may dwell in the house of the Lord all the days of my life, to behold the beauty of the Lord, and to enquire in his temple."},{"verse":5,"text":"For in the time of trouble he shall hide me in his pavilion: in the secret of his tabernacle shall he hide me; he shall set me up upon a rock."},{"verse":6,"text":"And now shall mine head be lifted up above mine enemies round about me: therefore will I offer in his tabernacle sacrifices of joy; I will sing, yea, I will sing praises unto the Lord."},{"verse":7,"text":"Hear, O Lord, when I cry with my voice: have mercy also upon me, and answer me."},{"verse":8,"text":"When thou saidst, Seek ye my face; my heart said unto thee, Thy face, Lord, will I seek."},{"verse":9,"text":"Hide not thy face far from me; put not thy servant away in anger: thou hast been my help; leave me not, neither forsake me, O God of my salvation."},{"verse":10,"text":"When my father and my mother forsake me, then the Lord will take me up."},{"verse":11,"text":"Teach me thy way, O Lord, and lead me in a plain path, because of mine enemies."},{"verse":12,"text":"Deliver me not over unto the will of mine enemies: for false witnesses are risen up against me, and such as breathe out cruelty."},{"verse":13,"text":"I had fainted, unless I had believed to see the goodness of the Lord in the land of the living."},{"verse":14,"text":"Wait on the Lord: be of good courage, and he shall strengthen thine heart: wait, I say, on the Lord. "}]},{"chapter":28,"verses":[{"verse":1,"text":"Unto thee will I cry, O Lord my rock; be not silent to me: lest, if thou be silent to me, I become like them that go down into the pit."},{"verse":2,"text":"Hear the voice of my supplications, when I cry unto thee, when I lift up my hands toward thy holy oracle."},{"verse":3,"text":"Draw me not away with the wicked, and with the workers of iniquity, which speak peace to their neighbours, but mischief is in their hearts."},{"verse":4,"text":"Give them according to their deeds, and according to the wickedness of their endeavours: give them after the work of their hands; render to them their desert."},{"verse":5,"text":"Because they regard not the works of the Lord, nor the operation of his hands, he shall destroy them, and not build them up."},{"verse":6,"text":"Blessed be the Lord, because he hath heard the voice of my supplications."},{"verse":7,"text":"The Lord is my strength and my shield; my heart trusted in him, and I am helped: therefore my heart greatly rejoiceth; and with my song will I praise him."},{"verse":8,"text":"The Lord is their strength, and he is the saving strength of his anointed."},{"verse":9,"text":"Save thy people, and bless thine inheritance: feed them also, and lift them up for ever. "}]},{"chapter":29,"verses":[{"verse":1,"text":"Give unto the Lord, O ye mighty, give unto the Lord glory and strength."},{"verse":2,"text":"Give unto the Lord the glory due unto his name; worship the Lord in the beauty of holiness."},{"verse":3,"text":"The voice of the Lord is upon the waters: the God of glory thundereth: the Lord is upon many waters."},{"verse":4,"text":"The voice of the Lord is powerful; the voice of the Lord is full of majesty."},{"verse":5,"text":"The voice of the Lord breaketh the cedars; yea, the Lord breaketh the cedars of Lebanon."},{"verse":6,"text":"He maketh them also to skip like a calf; Lebanon and Sirion like a young unicorn."},{"verse":7,"text":"The voice of the Lord divideth the flames of fire."},{"verse":8,"text":"The voice of the Lord shaketh the wilderness; the Lord shaketh the wilderness of Kadesh."},{"verse":9,"text":"The voice of the Lord maketh the hinds to calve, and discovereth the forests: and in his temple doth every one speak of his glory."},{"verse":10,"text":"The Lord sitteth upon the flood; yea, the Lord sitteth King for ever."},{"verse":11,"text":"The Lord will give strength unto his people; the Lord will bless his people with peace. "}]},{"chapter":30,"verses":[{"verse":1,"text":"I will extol thee, O Lord; for thou hast lifted me up, and hast not made my foes to rejoice over me."},{"verse":2,"text":"O Lord my God, I cried unto thee, and thou hast healed me."},{"verse":3,"text":"O Lord, thou hast brought up my soul from the grave: thou hast kept me alive, that I should not go down to the pit."},{"verse":4,"text":"Sing unto the Lord, O ye saints of his, and give thanks at the remembrance of his holiness."},{"verse":5,"text":"For his anger endureth but a moment; in his favour is life: weeping may endure for a night, but joy cometh in the morning."},{"verse":6,"text":"And in my prosperity I said, I shall never be moved."},{"verse":7,"text":"Lord, by thy favour thou hast made my mountain to stand strong: thou didst hide thy face, and I was troubled."},{"verse":8,"text":"I cried to thee, O Lord; and unto the Lord I made supplication."},{"verse":9,"text":"What profit is there in my blood, when I go down to the pit? Shall the dust praise thee? shall it declare thy truth?"},{"verse":10,"text":"Hear, O Lord, and have mercy upon me: Lord, be thou my helper."},{"verse":11,"text":"Thou hast turned for me my mourning into dancing: thou hast put off my sackcloth, and girded me with gladness;"},{"verse":12,"text":"To the end that my glory may sing praise to thee, and not be silent. O Lord my God, I will give thanks unto thee for ever. "}]},{"chapter":31,"verses":[{"verse":1,"text":"In thee, O Lord, do I put my trust; let me never be ashamed: deliver me in thy righteousness."},{"verse":2,"text":"Bow down thine ear to me; deliver me speedily: be thou my strong rock, for an house of defence to save me."},{"verse":3,"text":"For thou art my rock and my fortress; therefore for thy name’s sake lead me, and guide me."},{"verse":4,"text":"Pull me out of the net that they have laid privily for me: for thou art my strength."},{"verse":5,"text":"Into thine hand I commit my spirit: thou hast redeemed me, O Lord God of truth."},{"verse":6,"text":"I have hated them that regard lying vanities: but I trust in the Lord."},{"verse":7,"text":"I will be glad and rejoice in thy mercy: for thou hast considered my trouble; thou hast known my soul in adversities;"},{"verse":8,"text":"And hast not shut me up into the hand of the enemy: thou hast set my feet in a large room."},{"verse":9,"text":"Have mercy upon me, O Lord, for I am in trouble: mine eye is consumed with grief, yea, my soul and my belly."},{"verse":10,"text":"For my life is spent with grief, and my years with sighing: my strength faileth because of mine iniquity, and my bones are consumed."},{"verse":11,"text":"I was a reproach among all mine enemies, but especially among my neighbours, and a fear to mine acquaintance: they that did see me without fled from me."},{"verse":12,"text":"I am forgotten as a dead man out of mind: I am like a broken vessel."},{"verse":13,"text":"For I have heard the slander of many: fear was on every side: while they took counsel together against me, they devised to take away my life."},{"verse":14,"text":"But I trusted in thee, O Lord: I said, Thou art my God."},{"verse":15,"text":"My times are in thy hand: deliver me from the hand of mine enemies, and from them that persecute me."},{"verse":16,"text":"Make thy face to shine upon thy servant: save me for thy mercies’ sake."},{"verse":17,"text":"Let me not be ashamed, O Lord; for I have called upon thee: let the wicked be ashamed, and let them be silent in the grave."},{"verse":18,"text":"Let the lying lips be put to silence; which speak grievous things proudly and contemptuously against the righteous."},{"verse":19,"text":"Oh how great is thy goodness, which thou hast laid up for them that fear thee; which thou hast wrought for them that trust in thee before the sons of men!"},{"verse":20,"text":"Thou shalt hide them in the secret of thy presence from the pride of man: thou shalt keep them secretly in a pavilion from the strife of tongues."},{"verse":21,"text":"Blessed be the Lord: for he hath shewed me his marvellous kindness in a strong city."},{"verse":22,"text":"For I said in my haste, I am cut off from before thine eyes: nevertheless thou heardest the voice of my supplications when I cried unto thee."},{"verse":23,"text":"O love the Lord, all ye his saints: for the Lord preserveth the faithful, and plentifully rewardeth the proud doer."},{"verse":24,"text":"Be of good courage, and he shall strengthen your heart, all ye that hope in the Lord. "}]},{"chapter":32,"verses":[{"verse":1,"text":"Blessed is he whose transgression is forgiven, whose sin is covered."},{"verse":2,"text":"Blessed is the man unto whom the Lord imputeth not iniquity, and in whose spirit there is no guile."},{"verse":3,"text":"When I kept silence, my bones waxed old through my roaring all the day long."},{"verse":4,"text":"For day and night thy hand was heavy upon me: my moisture is turned into the drought of summer. Selah."},{"verse":5,"text":"I acknowledged my sin unto thee, and mine iniquity have I not hid. I said, I will confess my transgressions unto the Lord; and thou forgavest the iniquity of my sin. Selah."},{"verse":6,"text":"For this shall every one that is godly pray unto thee in a time when thou mayest be found: surely in the floods of great waters they shall not come nigh unto him."},{"verse":7,"text":"Thou art my hiding place; thou shalt preserve me from trouble; thou shalt compass me about with songs of deliverance. Selah."},{"verse":8,"text":"I will instruct thee and teach thee in the way which thou shalt go: I will guide thee with mine eye."},{"verse":9,"text":"Be ye not as the horse, or as the mule, which have no understanding: whose mouth must be held in with bit and bridle, lest they come near unto thee."},{"verse":10,"text":"Many sorrows shall be to the wicked: but he that trusteth in the Lord, mercy shall compass him about."},{"verse":11,"text":"Be glad in the Lord, and rejoice, ye righteous: and shout for joy, all ye that are upright in heart. "}]},{"chapter":33,"verses":[{"verse":1,"text":"Rejoice in the Lord, O ye righteous: for praise is comely for the upright."},{"verse":2,"text":"Praise the Lord with harp: sing unto him with the psaltery and an instrument of ten strings."},{"verse":3,"text":"Sing unto him a new song; play skilfully with a loud noise."},{"verse":4,"text":"For the word of the Lord is right; and all his works are done in truth."},{"verse":5,"text":"He loveth righteousness and judgment: the earth is full of the goodness of the Lord."},{"verse":6,"text":"By the word of the Lord were the heavens made; and all the host of them by the breath of his mouth."},{"verse":7,"text":"He gathereth the waters of the sea together as an heap: he layeth up the depth in storehouses."},{"verse":8,"text":"Let all the earth fear the Lord: let all the inhabitants of the world stand in awe of him."},{"verse":9,"text":"For he spake, and it was done; he commanded, and it stood fast."},{"verse":10,"text":"The Lord bringeth the counsel of the heathen to nought: he maketh the devices of the people of none effect."},{"verse":11,"text":"The counsel of the Lord standeth for ever, the thoughts of his heart to all generations."},{"verse":12,"text":"Blessed is the nation whose God is the Lord; and the people whom he hath chosen for his own inheritance."},{"verse":13,"text":"The Lord looketh from heaven; he beholdeth all the sons of men."},{"verse":14,"text":"From the place of his habitation he looketh upon all the inhabitants of the earth."},{"verse":15,"text":"He fashioneth their hearts alike; he considereth all their works."},{"verse":16,"text":"There is no king saved by the multitude of an host: a mighty man is not delivered by much strength."},{"verse":17,"text":"An horse is a vain thing for safety: neither shall he deliver any by his great strength."},{"verse":18,"text":"Behold, the eye of the Lord is upon them that fear him, upon them that hope in his mercy;"},{"verse":19,"text":"To deliver their soul from death, and to keep them alive in famine."},{"verse":20,"text":"Our soul waiteth for the Lord: he is our help and our shield."},{"verse":21,"text":"For our heart shall rejoice in him, because we have trusted in his holy name."},{"verse":22,"text":"Let thy mercy, O Lord, be upon us, according as we hope in thee. "}]},{"chapter":34,"verses":[{"verse":1,"text":"I will bless the Lord at all times: his praise shall continually be in my mouth."},{"verse":2,"text":"My soul shall make her boast in the Lord: the humble shall hear thereof, and be glad."},{"verse":3,"text":"O magnify the Lord with me, and let us exalt his name together."},{"verse":4,"text":"I sought the Lord, and he heard me, and delivered me from all my fears."},{"verse":5,"text":"They looked unto him, and were lightened: and their faces were not ashamed."},{"verse":6,"text":"This poor man cried, and the Lord heard him, and saved him out of all his troubles."},{"verse":7,"text":"The angel of the Lord encampeth round about them that fear him, and delivereth them."},{"verse":8,"text":"O taste and see that the Lord is good: blessed is the man that trusteth in him."},{"verse":9,"text":"O fear the Lord, ye his saints: for there is no want to them that fear him."},{"verse":10,"text":"The young lions do lack, and suffer hunger: but they that seek the Lord shall not want any good thing."},{"verse":11,"text":"Come, ye children, hearken unto me: I will teach you the fear of the Lord."},{"verse":12,"text":"What man is he that desireth life, and loveth many days, that he may see good?"},{"verse":13,"text":"Keep thy tongue from evil, and thy lips from speaking guile."},{"verse":14,"text":"Depart from evil, and do good; seek peace, and pursue it."},{"verse":15,"text":"The eyes of the Lord are upon the righteous, and his ears are open unto their cry."},{"verse":16,"text":"The face of the Lord is against them that do evil, to cut off the remembrance of them from the earth."},{"verse":17,"text":"The righteous cry, and the Lord heareth, and delivereth them out of all their troubles."},{"verse":18,"text":"The Lord is nigh unto them that are of a broken heart; and saveth such as be of a contrite spirit."},{"verse":19,"text":"Many are the afflictions of the righteous: but the Lord delivereth him out of them all."},{"verse":20,"text":"He keepeth all his bones: not one of them is broken."},{"verse":21,"text":"Evil shall slay the wicked: and they that hate the righteous shall be desolate."},{"verse":22,"text":"The Lord redeemeth the soul of his servants: and none of them that trust in him shall be desolate. "}]},{"chapter":35,"verses":[{"verse":1,"text":"Plead my cause, O Lord, with them that strive with me: fight against them that fight against me."},{"verse":2,"text":"Take hold of shield and buckler, and stand up for mine help."},{"verse":3,"text":"Draw out also the spear, and stop the way against them that persecute me: say unto my soul, I am thy salvation."},{"verse":4,"text":"Let them be confounded and put to shame that seek after my soul: let them be turned back and brought to confusion that devise my hurt."},{"verse":5,"text":"Let them be as chaff before the wind: and let the angel of the Lord chase them."},{"verse":6,"text":"Let their way be dark and slippery: and let the angel of the Lord persecute them."},{"verse":7,"text":"For without cause have they hid for me their net in a pit, which without cause they have digged for my soul."},{"verse":8,"text":"Let destruction come upon him at unawares; and let his net that he hath hid catch himself: into that very destruction let him fall."},{"verse":9,"text":"And my soul shall be joyful in the Lord: it shall rejoice in his salvation."},{"verse":10,"text":"All my bones shall say, Lord, who is like unto thee, which deliverest the poor from him that is too strong for him, yea, the poor and the needy from him that spoileth him?"},{"verse":11,"text":"False witnesses did rise up; they laid to my charge things that I knew not."},{"verse":12,"text":"They rewarded me evil for good to the spoiling of my soul."},{"verse":13,"text":"But as for me, when they were sick, my clothing was sackcloth: I humbled my soul with fasting; and my prayer returned into mine own bosom."},{"verse":14,"text":"I behaved myself as though he had been my friend or brother: I bowed down heavily, as one that mourneth for his mother."},{"verse":15,"text":"But in mine adversity they rejoiced, and gathered themselves together: yea, the abjects gathered themselves together against me, and I knew it not; they did tear me, and ceased not:"},{"verse":16,"text":"With hypocritical mockers in feasts, they gnashed upon me with their teeth."},{"verse":17,"text":"Lord, how long wilt thou look on? rescue my soul from their destructions, my darling from the lions."},{"verse":18,"text":"I will give thee thanks in the great congregation: I will praise thee among much people."},{"verse":19,"text":"Let not them that are mine enemies wrongfully rejoice over me: neither let them wink with the eye that hate me without a cause."},{"verse":20,"text":"For they speak not peace: but they devise deceitful matters against them that are quiet in the land."},{"verse":21,"text":"Yea, they opened their mouth wide against me, and said, Aha, aha, our eye hath seen it."},{"verse":22,"text":"This thou hast seen, O Lord: keep not silence: O Lord, be not far from me."},{"verse":23,"text":"Stir up thyself, and awake to my judgment, even unto my cause, my God and my Lord."},{"verse":24,"text":"Judge me, O Lord my God, according to thy righteousness; and let them not rejoice over me."},{"verse":25,"text":"Let them not say in their hearts, Ah, so would we have it: let them not say, We have swallowed him up."},{"verse":26,"text":"Let them be ashamed and brought to confusion together that rejoice at mine hurt: let them be clothed with shame and dishonour that magnify themselves against me."},{"verse":27,"text":"Let them shout for joy, and be glad, that favour my righteous cause: yea, let them say continually, Let the Lord be magnified, which hath pleasure in the prosperity of his servant."},{"verse":28,"text":"And my tongue shall speak of thy righteousness and of thy praise all the day long. "}]},{"chapter":36,"verses":[{"verse":1,"text":"The transgression of the wicked saith within my heart, that there is no fear of God before his eyes."},{"verse":2,"text":"For he flattereth himself in his own eyes, until his iniquity be found to be hateful."},{"verse":3,"text":"The words of his mouth are iniquity and deceit: he hath left off to be wise, and to do good."},{"verse":4,"text":"He deviseth mischief upon his bed; he setteth himself in a way that is not good; he abhorreth not evil."},{"verse":5,"text":"Thy mercy, O Lord, is in the heavens; and thy faithfulness reacheth unto the clouds."},{"verse":6,"text":"Thy righteousness is like the great mountains; thy judgments are a great deep: O Lord, thou preservest man and beast."},{"verse":7,"text":"How excellent is thy lovingkindness, O God! therefore the children of men put their trust under the shadow of thy wings."},{"verse":8,"text":"They shall be abundantly satisfied with the fatness of thy house; and thou shalt make them drink of the river of thy pleasures."},{"verse":9,"text":"For with thee is the fountain of life: in thy light shall we see light."},{"verse":10,"text":"O continue thy lovingkindness unto them that know thee; and thy righteousness to the upright in heart."},{"verse":11,"text":"Let not the foot of pride come against me, and let not the hand of the wicked remove me."},{"verse":12,"text":"There are the workers of iniquity fallen: they are cast down, and shall not be able to rise. "}]},{"chapter":37,"verses":[{"verse":1,"text":"Fret not thyself because of evildoers, neither be thou envious against the workers of iniquity."},{"verse":2,"text":"For they shall soon be cut down like the grass, and wither as the green herb."},{"verse":3,"text":"Trust in the Lord, and do good; so shalt thou dwell in the land, and verily thou shalt be fed."},{"verse":4,"text":"Delight thyself also in the Lord; and he shall give thee the desires of thine heart."},{"verse":5,"text":"Commit thy way unto the Lord; trust also in him; and he shall bring it to pass."},{"verse":6,"text":"And he shall bring forth thy righteousness as the light, and thy judgment as the noonday."},{"verse":7,"text":"Rest in the Lord, and wait patiently for him: fret not thyself because of him who prospereth in his way, because of the man who bringeth wicked devices to pass."},{"verse":8,"text":"Cease from anger, and forsake wrath: fret not thyself in any wise to do evil."},{"verse":9,"text":"For evildoers shall be cut off: but those that wait upon the Lord, they shall inherit the earth."},{"verse":10,"text":"For yet a little while, and the wicked shall not be: yea, thou shalt diligently consider his place, and it shall not be."},{"verse":11,"text":"But the meek shall inherit the earth; and shall delight themselves in the abundance of peace."},{"verse":12,"text":"The wicked plotteth against the just, and gnasheth upon him with his teeth."},{"verse":13,"text":"The Lord shall laugh at him: for he seeth that his day is coming."},{"verse":14,"text":"The wicked have drawn out the sword, and have bent their bow, to cast down the poor and needy, and to slay such as be of upright conversation."},{"verse":15,"text":"Their sword shall enter into their own heart, and their bows shall be broken."},{"verse":16,"text":"A little that a righteous man hath is better than the riches of many wicked."},{"verse":17,"text":"For the arms of the wicked shall be broken: but the Lord upholdeth the righteous."},{"verse":18,"text":"The Lord knoweth the days of the upright: and their inheritance shall be for ever."},{"verse":19,"text":"They shall not be ashamed in the evil time: and in the days of famine they shall be satisfied."},{"verse":20,"text":"But the wicked shall perish, and the enemies of the Lord shall be as the fat of lambs: they shall consume; into smoke shall they consume away."},{"verse":21,"text":"The wicked borroweth, and payeth not again: but the righteous sheweth mercy, and giveth."},{"verse":22,"text":"For such as be blessed of him shall inherit the earth; and they that be cursed of him shall be cut off."},{"verse":23,"text":"The steps of a good man are ordered by the Lord: and he delighteth in his way."},{"verse":24,"text":"Though he fall, he shall not be utterly cast down: for the Lord upholdeth him with his hand."},{"verse":25,"text":"I have been young, and now am old; yet have I not seen the righteous forsaken, nor his seed begging bread."},{"verse":26,"text":"He is ever merciful, and lendeth; and his seed is blessed."},{"verse":27,"text":"Depart from evil, and do good; and dwell for evermore."},{"verse":28,"text":"For the Lord loveth judgment, and forsaketh not his saints; they are preserved for ever: but the seed of the wicked shall be cut off."},{"verse":29,"text":"The righteous shall inherit the land, and dwell therein for ever."},{"verse":30,"text":"The mouth of the righteous speaketh wisdom, and his tongue talketh of judgment."},{"verse":31,"text":"The law of his God is in his heart; none of his steps shall slide."},{"verse":32,"text":"The wicked watcheth the righteous, and seeketh to slay him."},{"verse":33,"text":"The Lord will not leave him in his hand, nor condemn him when he is judged."},{"verse":34,"text":"Wait on the Lord, and keep his way, and he shall exalt thee to inherit the land: when the wicked are cut off, thou shalt see it."},{"verse":35,"text":"I have seen the wicked in great power, and spreading himself like a green bay tree."},{"verse":36,"text":"Yet he passed away, and, lo, he was not: yea, I sought him, but he could not be found."},{"verse":37,"text":"Mark the perfect man, and behold the upright: for the end of that man is peace."},{"verse":38,"text":"But the transgressors shall be destroyed together: the end of the wicked shall be cut off."},{"verse":39,"text":"But the salvation of the righteous is of the Lord: he is their strength in the time of trouble."},{"verse":40,"text":"And the Lord shall help them, and deliver them: he shall deliver them from the wicked, and save them, because they trust in him. "}]},{"chapter":38,"verses":[{"verse":1,"text":"O Lord, rebuke me not in thy wrath: neither chasten me in thy hot displeasure."},{"verse":2,"text":"For thine arrows stick fast in me, and thy hand presseth me sore."},{"verse":3,"text":"There is no soundness in my flesh because of thine anger; neither is there any rest in my bones because of my sin."},{"verse":4,"text":"For mine iniquities are gone over mine head: as an heavy burden they are too heavy for me."},{"verse":5,"text":"My wounds stink and are corrupt because of my foolishness."},{"verse":6,"text":"I am troubled; I am bowed down greatly; I go mourning all the day long."},{"verse":7,"text":"For my loins are filled with a loathsome disease: and there is no soundness in my flesh."},{"verse":8,"text":"I am feeble and sore broken: I have roared by reason of the disquietness of my heart."},{"verse":9,"text":"Lord, all my desire is before thee; and my groaning is not hid from thee."},{"verse":10,"text":"My heart panteth, my strength faileth me: as for the light of mine eyes, it also is gone from me."},{"verse":11,"text":"My lovers and my friends stand aloof from my sore; and my kinsmen stand afar off."},{"verse":12,"text":"They also that seek after my life lay snares for me: and they that seek my hurt speak mischievous things, and imagine deceits all the day long."},{"verse":13,"text":"But I, as a deaf man, heard not; and I was as a dumb man that openeth not his mouth."},{"verse":14,"text":"Thus I was as a man that heareth not, and in whose mouth are no reproofs."},{"verse":15,"text":"For in thee, O Lord, do I hope: thou wilt hear, O Lord my God."},{"verse":16,"text":"For I said, Hear me, lest otherwise they should rejoice over me: when my foot slippeth, they magnify themselves against me."},{"verse":17,"text":"For I am ready to halt, and my sorrow is continually before me."},{"verse":18,"text":"For I will declare mine iniquity; I will be sorry for my sin."},{"verse":19,"text":"But mine enemies are lively, and they are strong: and they that hate me wrongfully are multiplied."},{"verse":20,"text":"They also that render evil for good are mine adversaries; because I follow the thing that good is."},{"verse":21,"text":"Forsake me not, O Lord: O my God, be not far from me."},{"verse":22,"text":"Make haste to help me, O Lord my salvation. "}]},{"chapter":39,"verses":[{"verse":1,"text":"I said, I will take heed to my ways, that I sin not with my tongue: I will keep my mouth with a bridle, while the wicked is before me."},{"verse":2,"text":"I was dumb with silence, I held my peace, even from good; and my sorrow was stirred."},{"verse":3,"text":"My heart was hot within me, while I was musing the fire burned: then spake I with my tongue,"},{"verse":4,"text":"Lord, make me to know mine end, and the measure of my days, what it is; that I may know how frail I am."},{"verse":5,"text":"Behold, thou hast made my days as an handbreadth; and mine age is as nothing before thee: verily every man at his best state is altogether vanity. Selah."},{"verse":6,"text":"Surely every man walketh in a vain shew: surely they are disquieted in vain: he heapeth up riches, and knoweth not who shall gather them."},{"verse":7,"text":"And now, Lord, what wait I for? my hope is in thee."},{"verse":8,"text":"Deliver me from all my transgressions: make me not the reproach of the foolish."},{"verse":9,"text":"I was dumb, I opened not my mouth; because thou didst it."},{"verse":10,"text":"Remove thy stroke away from me: I am consumed by the blow of thine hand."},{"verse":11,"text":"When thou with rebukes dost correct man for iniquity, thou makest his beauty to consume away like a moth: surely every man is vanity. Selah."},{"verse":12,"text":"Hear my prayer, O Lord, and give ear unto my cry; hold not thy peace at my tears: for I am a stranger with thee, and a sojourner, as all my fathers were."},{"verse":13,"text":"O spare me, that I may recover strength, before I go hence, and be no more. "}]},{"chapter":40,"verses":[{"verse":1,"text":"I waited patiently for the Lord; and he inclined unto me, and heard my cry."},{"verse":2,"text":"He brought me up also out of an horrible pit, out of the miry clay, and set my feet upon a rock, and established my goings."},{"verse":3,"text":"And he hath put a new song in my mouth, even praise unto our God: many shall see it, and fear, and shall trust in the Lord."},{"verse":4,"text":"Blessed is that man that maketh the Lord his trust, and respecteth not the proud, nor such as turn aside to lies."},{"verse":5,"text":"Many, O Lord my God, are thy wonderful works which thou hast done, and thy thoughts which are to us-ward: they cannot be reckoned up in order unto thee: if I would declare and speak of them, they are more than can be numbered."},{"verse":6,"text":"Sacrifice and offering thou didst not desire; mine ears hast thou opened: burnt offering and sin offering hast thou not required."},{"verse":7,"text":"Then said I, Lo, I come: in the volume of the book it is written of me,"},{"verse":8,"text":"I delight to do thy will, O my God: yea, thy law is within my heart."},{"verse":9,"text":"I have preached righteousness in the great congregation: lo, I have not refrained my lips, O Lord, thou knowest."},{"verse":10,"text":"I have not hid thy righteousness within my heart; I have declared thy faithfulness and thy salvation: I have not concealed thy lovingkindness and thy truth from the great congregation."},{"verse":11,"text":"Withhold not thou thy tender mercies from me, O Lord: let thy lovingkindness and thy truth continually preserve me."},{"verse":12,"text":"For innumerable evils have compassed me about: mine iniquities have taken hold upon me, so that I am not able to look up; they are more than the hairs of mine head: therefore my heart faileth me."},{"verse":13,"text":"Be pleased, O Lord, to deliver me: O Lord, make haste to help me."},{"verse":14,"text":"Let them be ashamed and confounded together that seek after my soul to destroy it; let them be driven backward and put to shame that wish me evil."},{"verse":15,"text":"Let them be desolate for a reward of their shame that say unto me, Aha, aha."},{"verse":16,"text":"Let all those that seek thee rejoice and be glad in thee: let such as love thy salvation say continually, The Lord be magnified."},{"verse":17,"text":"But I am poor and needy; yet the Lord thinketh upon me: thou art my help and my deliverer; make no tarrying, O my God. "}]},{"chapter":41,"verses":[{"verse":1,"text":"Blessed is he that considereth the poor: the Lord will deliver him in time of trouble."},{"verse":2,"text":"The Lord will preserve him, and keep him alive; and he shall be blessed upon the earth: and thou wilt not deliver him unto the will of his enemies."},{"verse":3,"text":"The Lord will strengthen him upon the bed of languishing: thou wilt make all his bed in his sickness."},{"verse":4,"text":"I said, Lord, be merciful unto me: heal my soul; for I have sinned against thee."},{"verse":5,"text":"Mine enemies speak evil of me, When shall he die, and his name perish?"},{"verse":6,"text":"And if he come to see me, he speaketh vanity: his heart gathereth iniquity to itself; when he goeth abroad, he telleth it."},{"verse":7,"text":"All that hate me whisper together against me: against me do they devise my hurt."},{"verse":8,"text":"An evil disease, say they, cleaveth fast unto him: and now that he lieth he shall rise up no more."},{"verse":9,"text":"Yea, mine own familiar friend, in whom I trusted, which did eat of my bread, hath lifted up his heel against me."},{"verse":10,"text":"But thou, O Lord, be merciful unto me, and raise me up, that I may requite them."},{"verse":11,"text":"By this I know that thou favourest me, because mine enemy doth not triumph over me."},{"verse":12,"text":"And as for me, thou upholdest me in mine integrity, and settest me before thy face for ever."},{"verse":13,"text":"Blessed be the Lord God of Israel from everlasting, and to everlasting. Amen, and Amen. "}]},{"chapter":42,"verses":[{"verse":1,"text":"As the hart panteth after the water brooks, so panteth my soul after thee, O God."},{"verse":2,"text":"My soul thirsteth for God, for the living God: when shall I come and appear before God?"},{"verse":3,"text":"My tears have been my meat day and night, while they continually say unto me, Where is thy God?"},{"verse":4,"text":"When I remember these things, I pour out my soul in me: for I had gone with the multitude, I went with them to the house of God, with the voice of joy and praise, with a multitude that kept holyday."},{"verse":5,"text":"Why art thou cast down, O my soul? and why art thou disquieted in me? hope thou in God: for I shall yet praise him for the help of his countenance."},{"verse":6,"text":"O my God, my soul is cast down within me: therefore will I remember thee from the land of Jordan, and of the Hermonites, from the hill Mizar."},{"verse":7,"text":"Deep calleth unto deep at the noise of thy waterspouts: all thy waves and thy billows are gone over me."},{"verse":8,"text":"Yet the Lord will command his lovingkindness in the daytime, and in the night his song shall be with me, and my prayer unto the God of my life."},{"verse":9,"text":"I will say unto God my rock, Why hast thou forgotten me? why go I mourning because of the oppression of the enemy?"},{"verse":10,"text":"As with a sword in my bones, mine enemies reproach me; while they say daily unto me, Where is thy God?"},{"verse":11,"text":"Why art thou cast down, O my soul? and why art thou disquieted within me? hope thou in God: for I shall yet praise him, who is the health of my countenance, and my God. "}]},{"chapter":43,"verses":[{"verse":1,"text":"Judge me, O God, and plead my cause against an ungodly nation: O deliver me from the deceitful and unjust man."},{"verse":2,"text":"For thou art the God of my strength: why dost thou cast me off? why go I mourning because of the oppression of the enemy?"},{"verse":3,"text":"O send out thy light and thy truth: let them lead me; let them bring me unto thy holy hill, and to thy tabernacles."},{"verse":4,"text":"Then will I go unto the altar of God, unto God my exceeding joy: yea, upon the harp will I praise thee, O God my God."},{"verse":5,"text":"Why art thou cast down, O my soul? and why art thou disquieted within me? hope in God: for I shall yet praise him, who is the health of my countenance, and my God. "}]},{"chapter":44,"verses":[{"verse":1,"text":"We have heard with our ears, O God, our fathers have told us, what work thou didst in their days, in the times of old."},{"verse":2,"text":"How thou didst drive out the heathen with thy hand, and plantedst them; how thou didst afflict the people, and cast them out."},{"verse":3,"text":"For they got not the land in possession by their own sword, neither did their own arm save them: but thy right hand, and thine arm, and the light of thy countenance, because thou hadst a favour unto them."},{"verse":4,"text":"Thou art my King, O God: command deliverances for Jacob."},{"verse":5,"text":"Through thee will we push down our enemies: through thy name will we tread them under that rise up against us."},{"verse":6,"text":"For I will not trust in my bow, neither shall my sword save me."},{"verse":7,"text":"But thou hast saved us from our enemies, and hast put them to shame that hated us."},{"verse":8,"text":"In God we boast all the day long, and praise thy name for ever. Selah."},{"verse":9,"text":"But thou hast cast off, and put us to shame; and goest not forth with our armies."},{"verse":10,"text":"Thou makest us to turn back from the enemy: and they which hate us spoil for themselves."},{"verse":11,"text":"Thou hast given us like sheep appointed for meat; and hast scattered us among the heathen."},{"verse":12,"text":"Thou sellest thy people for nought, and dost not increase thy wealth by their price."},{"verse":13,"text":"Thou makest us a reproach to our neighbours, a scorn and a derision to them that are round about us."},{"verse":14,"text":"Thou makest us a byword among the heathen, a shaking of the head among the people."},{"verse":15,"text":"My confusion is continually before me, and the shame of my face hath covered me,"},{"verse":16,"text":"For the voice of him that reproacheth and blasphemeth; by reason of the enemy and avenger."},{"verse":17,"text":"All this is come upon us; yet have we not forgotten thee, neither have we dealt falsely in thy covenant."},{"verse":18,"text":"Our heart is not turned back, neither have our steps declined from thy way;"},{"verse":19,"text":"Though thou hast sore broken us in the place of dragons, and covered us with the shadow of death."},{"verse":20,"text":"If we have forgotten the name of our God, or stretched out our hands to a strange god;"},{"verse":21,"text":"Shall not God search this out? for he knoweth the secrets of the heart."},{"verse":22,"text":"Yea, for thy sake are we killed all the day long; we are counted as sheep for the slaughter."},{"verse":23,"text":"Awake, why sleepest thou, O Lord? arise, cast us not off for ever."},{"verse":24,"text":"Wherefore hidest thou thy face, and forgettest our affliction and our oppression?"},{"verse":25,"text":"For our soul is bowed down to the dust: our belly cleaveth unto the earth."},{"verse":26,"text":"Arise for our help, and redeem us for thy mercies’ sake. "}]},{"chapter":45,"verses":[{"verse":1,"text":"My heart is inditing a good matter: I speak of the things which I have made touching the king: my tongue is the pen of a ready writer."},{"verse":2,"text":"Thou art fairer than the children of men: grace is poured into thy lips: therefore God hath blessed thee for ever."},{"verse":3,"text":"Gird thy sword upon thy thigh, O most mighty, with thy glory and thy majesty."},{"verse":4,"text":"And in thy majesty ride prosperously because of truth and meekness and righteousness; and thy right hand shall teach thee terrible things."},{"verse":5,"text":"Thine arrows are sharp in the heart of the king’s enemies; whereby the people fall under thee."},{"verse":6,"text":"Thy throne, O God, is for ever and ever: the sceptre of thy kingdom is a right sceptre."},{"verse":7,"text":"Thou lovest righteousness, and hatest wickedness: therefore God, thy God, hath anointed thee with the oil of gladness above thy fellows."},{"verse":8,"text":"All thy garments smell of myrrh, and aloes, and cassia, out of the ivory palaces, whereby they have made thee glad."},{"verse":9,"text":"Kings’ daughters were among thy honourable women: upon thy right hand did stand the queen in gold of Ophir."},{"verse":10,"text":"Hearken, O daughter, and consider, and incline thine ear; forget also thine own people, and thy father’s house;"},{"verse":11,"text":"So shall the king greatly desire thy beauty: for he is thy Lord; and worship thou him."},{"verse":12,"text":"And the daughter of Tyre shall be there with a gift; even the rich among the people shall intreat thy favour."},{"verse":13,"text":"The king’s daughter is all glorious within: her clothing is of wrought gold."},{"verse":14,"text":"She shall be brought unto the king in raiment of needlework: the virgins her companions that follow her shall be brought unto thee."},{"verse":15,"text":"With gladness and rejoicing shall they be brought: they shall enter into the king’s palace."},{"verse":16,"text":"Instead of thy fathers shall be thy children, whom thou mayest make princes in all the earth."},{"verse":17,"text":"I will make thy name to be remembered in all generations: therefore shall the people praise thee for ever and ever. "}]},{"chapter":46,"verses":[{"verse":1,"text":"God is our refuge and strength, a very present help in trouble."},{"verse":2,"text":"Therefore will not we fear, though the earth be removed, and though the mountains be carried into the midst of the sea;"},{"verse":3,"text":"Though the waters thereof roar and be troubled, though the mountains shake with the swelling thereof. Selah."},{"verse":4,"text":"There is a river, the streams whereof shall make glad the city of God, the holy place of the tabernacles of the most High."},{"verse":5,"text":"God is in the midst of her; she shall not be moved: God shall help her, and that right early."},{"verse":6,"text":"The heathen raged, the kingdoms were moved: he uttered his voice, the earth melted."},{"verse":7,"text":"The Lord of hosts is with us; the God of Jacob is our refuge. Selah."},{"verse":8,"text":"Come, behold the works of the Lord, what desolations he hath made in the earth."},{"verse":9,"text":"He maketh wars to cease unto the end of the earth; he breaketh the bow, and cutteth the spear in sunder; he burneth the chariot in the fire."},{"verse":10,"text":"Be still, and know that I am God: I will be exalted among the heathen, I will be exalted in the earth."},{"verse":11,"text":"The Lord of hosts is with us; the God of Jacob is our refuge. Selah. "}]},{"chapter":47,"verses":[{"verse":1,"text":"O clap your hands, all ye people; shout unto God with the voice of triumph."},{"verse":2,"text":"For the Lord most high is terrible; he is a great King over all the earth."},{"verse":3,"text":"He shall subdue the people under us, and the nations under our feet."},{"verse":4,"text":"He shall choose our inheritance for us, the excellency of Jacob whom he loved. Selah."},{"verse":5,"text":"God is gone up with a shout, the Lord with the sound of a trumpet."},{"verse":6,"text":"Sing praises to God, sing praises: sing praises unto our King, sing praises."},{"verse":7,"text":"For God is the King of all the earth: sing ye praises with understanding."},{"verse":8,"text":"God reigneth over the heathen: God sitteth upon the throne of his holiness."},{"verse":9,"text":"The princes of the people are gathered together, even the people of the God of Abraham: for the shields of the earth belong unto God: he is greatly exalted. "}]},{"chapter":48,"verses":[{"verse":1,"text":"Great is the Lord, and greatly to be praised in the city of our God, in the mountain of his holiness."},{"verse":2,"text":"Beautiful for situation, the joy of the whole earth, is mount Zion, on the sides of the north, the city of the great King."},{"verse":3,"text":"God is known in her palaces for a refuge."},{"verse":4,"text":"For, lo, the kings were assembled, they passed by together."},{"verse":5,"text":"They saw it, and so they marvelled; they were troubled, and hasted away."},{"verse":6,"text":"Fear took hold upon them there, and pain, as of a woman in travail."},{"verse":7,"text":"Thou breakest the ships of Tarshish with an east wind."},{"verse":8,"text":"As we have heard, so have we seen in the city of the Lord of hosts, in the city of our God: God will establish it for ever. Selah."},{"verse":9,"text":"We have thought of thy lovingkindness, O God, in the midst of thy temple."},{"verse":10,"text":"According to thy name, O God, so is thy praise unto the ends of the earth: thy right hand is full of righteousness."},{"verse":11,"text":"Let mount Zion rejoice, let the daughters of Judah be glad, because of thy judgments."},{"verse":12,"text":"Walk about Zion, and go round about her: tell the towers thereof."},{"verse":13,"text":"Mark ye well her bulwarks, consider her palaces; that ye may tell it to the generation following."},{"verse":14,"text":"For this God is our God for ever and ever: he will be our guide even unto death. "}]},{"chapter":49,"verses":[{"verse":1,"text":"Hear this, all ye people; give ear, all ye inhabitants of the world:"},{"verse":2,"text":"Both low and high, rich and poor, together."},{"verse":3,"text":"My mouth shall speak of wisdom; and the meditation of my heart shall be of understanding."},{"verse":4,"text":"I will incline mine ear to a parable: I will open my dark saying upon the harp."},{"verse":5,"text":"Wherefore should I fear in the days of evil, when the iniquity of my heels shall compass me about?"},{"verse":6,"text":"They that trust in their wealth, and boast themselves in the multitude of their riches;"},{"verse":7,"text":"None of them can by any means redeem his brother, nor give to God a ransom for him:"},{"verse":8,"text":"(For the redemption of their soul is precious, and it ceaseth for ever:)"},{"verse":9,"text":"That he should still live for ever, and not see corruption."},{"verse":10,"text":"For he seeth that wise men die, likewise the fool and the brutish person perish, and leave their wealth to others."},{"verse":11,"text":"Their inward thought is, that their houses shall continue for ever, and their dwelling places to all generations; they call their lands after their own names."},{"verse":12,"text":"Nevertheless man being in honour abideth not: he is like the beasts that perish."},{"verse":13,"text":"This their way is their folly: yet their posterity approve their sayings. Selah."},{"verse":14,"text":"Like sheep they are laid in the grave; death shall feed on them; and the upright shall have dominion over them in the morning; and their beauty shall consume in the grave from their dwelling."},{"verse":15,"text":"But God will redeem my soul from the power of the grave: for he shall receive me. Selah."},{"verse":16,"text":"Be not thou afraid when one is made rich, when the glory of his house is increased;"},{"verse":17,"text":"For when he dieth he shall carry nothing away: his glory shall not descend after him."},{"verse":18,"text":"Though while he lived he blessed his soul: and men will praise thee, when thou doest well to thyself."},{"verse":19,"text":"He shall go to the generation of his fathers; they shall never see light."},{"verse":20,"text":"Man that is in honour, and understandeth not, is like the beasts that perish. "}]},{"chapter":50,"verses":[{"verse":1,"text":"The mighty God, even the Lord, hath spoken, and called the earth from the rising of the sun unto the going down thereof."},{"verse":2,"text":"Out of Zion, the perfection of beauty, God hath shined."},{"verse":3,"text":"Our God shall come, and shall not keep silence: a fire shall devour before him, and it shall be very tempestuous round about him."},{"verse":4,"text":"He shall call to the heavens from above, and to the earth, that he may judge his people."},{"verse":5,"text":"Gather my saints together unto me; those that have made a covenant with me by sacrifice."},{"verse":6,"text":"And the heavens shall declare his righteousness: for God is judge himself. Selah."},{"verse":7,"text":"Hear, O my people, and I will speak; O Israel, and I will testify against thee: I am God, even thy God."},{"verse":8,"text":"I will not reprove thee for thy sacrifices or thy burnt offerings, to have been continually before me."},{"verse":9,"text":"I will take no bullock out of thy house, nor he goats out of thy folds."},{"verse":10,"text":"For every beast of the forest is mine, and the cattle upon a thousand hills."},{"verse":11,"text":"I know all the fowls of the mountains: and the wild beasts of the field are mine."},{"verse":12,"text":"If I were hungry, I would not tell thee: for the world is mine, and the fulness thereof."},{"verse":13,"text":"Will I eat the flesh of bulls, or drink the blood of goats?"},{"verse":14,"text":"Offer unto God thanksgiving; and pay thy vows unto the most High:"},{"verse":15,"text":"And call upon me in the day of trouble: I will deliver thee, and thou shalt glorify me."},{"verse":16,"text":"But unto the wicked God saith, What hast thou to do to declare my statutes, or that thou shouldest take my covenant in thy mouth?"},{"verse":17,"text":"Seeing thou hatest instruction, and castest my words behind thee."},{"verse":18,"text":"When thou sawest a thief, then thou consentedst with him, and hast been partaker with adulterers."},{"verse":19,"text":"Thou givest thy mouth to evil, and thy tongue frameth deceit."},{"verse":20,"text":"Thou sittest and speakest against thy brother; thou slanderest thine own mother’s son."},{"verse":21,"text":"These things hast thou done, and I kept silence; thou thoughtest that I was altogether such an one as thyself: but I will reprove thee, and set them in order before thine eyes."},{"verse":22,"text":"Now consider this, ye that forget God, lest I tear you in pieces, and there be none to deliver."},{"verse":23,"text":"Whoso offereth praise glorifieth me: and to him that ordereth his conversation aright will I shew the salvation of God. "}]},{"chapter":51,"verses":[{"verse":1,"text":"Have mercy upon me, O God, according to thy lovingkindness: according unto the multitude of thy tender mercies blot out my transgressions."},{"verse":2,"text":"Wash me throughly from mine iniquity, and cleanse me from my sin."},{"verse":3,"text":"For I acknowledge my transgressions: and my sin is ever before me."},{"verse":4,"text":"Against thee, thee only, have I sinned, and done this evil in thy sight: that thou mightest be justified when thou speakest, and be clear when thou judgest."},{"verse":5,"text":"Behold, I was shapen in iniquity; and in sin did my mother conceive me."},{"verse":6,"text":"Behold, thou desirest truth in the inward parts: and in the hidden part thou shalt make me to know wisdom."},{"verse":7,"text":"Purge me with hyssop, and I shall be clean: wash me, and I shall be whiter than snow."},{"verse":8,"text":"Make me to hear joy and gladness; that the bones which thou hast broken may rejoice."},{"verse":9,"text":"Hide thy face from my sins, and blot out all mine iniquities."},{"verse":10,"text":"Create in me a clean heart, O God; and renew a right spirit within me."},{"verse":11,"text":"Cast me not away from thy presence; and take not thy holy spirit from me."},{"verse":12,"text":"Restore unto me the joy of thy salvation; and uphold me with thy free spirit."},{"verse":13,"text":"Then will I teach transgressors thy ways; and sinners shall be converted unto thee."},{"verse":14,"text":"Deliver me from bloodguiltiness, O God, thou God of my salvation: and my tongue shall sing aloud of thy righteousness."},{"verse":15,"text":"O Lord, open thou my lips; and my mouth shall shew forth thy praise."},{"verse":16,"text":"For thou desirest not sacrifice; else would I give it: thou delightest not in burnt offering."},{"verse":17,"text":"The sacrifices of God are a broken spirit: a broken and a contrite heart, O God, thou wilt not despise."},{"verse":18,"text":"Do good in thy good pleasure unto Zion: build thou the walls of Jerusalem."},{"verse":19,"text":"Then shalt thou be pleased with the sacrifices of righteousness, with burnt offering and whole burnt offering: then shall they offer bullocks upon thine altar. "}]},{"chapter":52,"verses":[{"verse":1,"text":"Why boastest thou thyself in mischief, O mighty man? the goodness of God endureth continually."},{"verse":2,"text":"Thy tongue deviseth mischiefs; like a sharp razor, working deceitfully."},{"verse":3,"text":"Thou lovest evil more than good; and lying rather than to speak righteousness. Selah."},{"verse":4,"text":"Thou lovest all devouring words, O thou deceitful tongue."},{"verse":5,"text":"God shall likewise destroy thee for ever, he shall take thee away, and pluck thee out of thy dwelling place, and root thee out of the land of the living. Selah."},{"verse":6,"text":"The righteous also shall see, and fear, and shall laugh at him:"},{"verse":7,"text":"Lo, this is the man that made not God his strength; but trusted in the abundance of his riches, and strengthened himself in his wickedness."},{"verse":8,"text":"But I am like a green olive tree in the house of God: I trust in the mercy of God for ever and ever."},{"verse":9,"text":"I will praise thee for ever, because thou hast done it: and I will wait on thy name; for it is good before thy saints. "}]},{"chapter":53,"verses":[{"verse":1,"text":"The fool hath said in his heart, There is no God. Corrupt are they, and have done abominable iniquity: there is none that doeth good."},{"verse":2,"text":"God looked down from heaven upon the children of men, to see if there were any that did understand, that did seek God."},{"verse":3,"text":"Every one of them is gone back: they are altogether become filthy; there is none that doeth good, no, not one."},{"verse":4,"text":"Have the workers of iniquity no knowledge? who eat up my people as they eat bread: they have not called upon God."},{"verse":5,"text":"There were they in great fear, where no fear was: for God hath scattered the bones of him that encampeth against thee: thou hast put them to shame, because God hath despised them."},{"verse":6,"text":"Oh that the salvation of Israel were come out of Zion! When God bringeth back the captivity of his people, Jacob shall rejoice, and Israel shall be glad. "}]},{"chapter":54,"verses":[{"verse":1,"text":"Save me, O God, by thy name, and judge me by thy strength."},{"verse":2,"text":"Hear my prayer, O God; give ear to the words of my mouth."},{"verse":3,"text":"For strangers are risen up against me, and oppressors seek after my soul: they have not set God before them. Selah."},{"verse":4,"text":"Behold, God is mine helper: the Lord is with them that uphold my soul."},{"verse":5,"text":"He shall reward evil unto mine enemies: cut them off in thy truth."},{"verse":6,"text":"I will freely sacrifice unto thee: I will praise thy name, O Lord; for it is good."},{"verse":7,"text":"For he hath delivered me out of all trouble: and mine eye hath seen his desire upon mine enemies. "}]},{"chapter":55,"verses":[{"verse":1,"text":"Give ear to my prayer, O God; and hide not thyself from my supplication."},{"verse":2,"text":"Attend unto me, and hear me: I mourn in my complaint, and make a noise;"},{"verse":3,"text":"Because of the voice of the enemy, because of the oppression of the wicked: for they cast iniquity upon me, and in wrath they hate me."},{"verse":4,"text":"My heart is sore pained within me: and the terrors of death are fallen upon me."},{"verse":5,"text":"Fearfulness and trembling are come upon me, and horror hath overwhelmed me."},{"verse":6,"text":"And I said, Oh that I had wings like a dove! for then would I fly away, and be at rest."},{"verse":7,"text":"Lo, then would I wander far off, and remain in the wilderness. Selah."},{"verse":8,"text":"I would hasten my escape from the windy storm and tempest."},{"verse":9,"text":"Destroy, O Lord, and divide their tongues: for I have seen violence and strife in the city."},{"verse":10,"text":"Day and night they go about it upon the walls thereof: mischief also and sorrow are in the midst of it."},{"verse":11,"text":"Wickedness is in the midst thereof: deceit and guile depart not from her streets."},{"verse":12,"text":"For it was not an enemy that reproached me; then I could have borne it: neither was it he that hated me that did magnify himself against me; then I would have hid myself from him:"},{"verse":13,"text":"But it was thou, a man mine equal, my guide, and mine acquaintance."},{"verse":14,"text":"We took sweet counsel together, and walked unto the house of God in company."},{"verse":15,"text":"Let death seize upon them, and let them go down quick into hell: for wickedness is in their dwellings, and among them."},{"verse":16,"text":"As for me, I will call upon God; and the Lord shall save me."},{"verse":17,"text":"Evening, and morning, and at noon, will I pray, and cry aloud: and he shall hear my voice."},{"verse":18,"text":"He hath delivered my soul in peace from the battle that was against me: for there were many with me."},{"verse":19,"text":"God shall hear, and afflict them, even he that abideth of old. Selah. Because they have no changes, therefore they fear not God."},{"verse":20,"text":"He hath put forth his hands against such as be at peace with him: he hath broken his covenant."},{"verse":21,"text":"The words of his mouth were smoother than butter, but war was in his heart: his words were softer than oil, yet were they drawn swords."},{"verse":22,"text":"Cast thy burden upon the Lord, and he shall sustain thee: he shall never suffer the righteous to be moved."},{"verse":23,"text":"But thou, O God, shalt bring them down into the pit of destruction: bloody and deceitful men shall not live out half their days; but I will trust in thee. "}]},{"chapter":56,"verses":[{"verse":1,"text":"Be merciful unto me, O God: for man would swallow me up; he fighting daily oppresseth me."},{"verse":2,"text":"Mine enemies would daily swallow me up: for they be many that fight against me, O thou most High."},{"verse":3,"text":"What time I am afraid, I will trust in thee."},{"verse":4,"text":"In God I will praise his word, in God I have put my trust; I will not fear what flesh can do unto me."},{"verse":5,"text":"Every day they wrest my words: all their thoughts are against me for evil."},{"verse":6,"text":"They gather themselves together, they hide themselves, they mark my steps, when they wait for my soul."},{"verse":7,"text":"Shall they escape by iniquity? in thine anger cast down the people, O God."},{"verse":8,"text":"Thou tellest my wanderings: put thou my tears into thy bottle: are they not in thy book?"},{"verse":9,"text":"When I cry unto thee, then shall mine enemies turn back: this I know; for God is for me."},{"verse":10,"text":"In God will I praise his word: in the Lord will I praise his word."},{"verse":11,"text":"In God have I put my trust: I will not be afraid what man can do unto me."},{"verse":12,"text":"Thy vows are upon me, O God: I will render praises unto thee."},{"verse":13,"text":"For thou hast delivered my soul from death: wilt not thou deliver my feet from falling, that I may walk before God in the light of the living? "}]},{"chapter":57,"verses":[{"verse":1,"text":"Be merciful unto me, O God, be merciful unto me: for my soul trusteth in thee: yea, in the shadow of thy wings will I make my refuge, until these calamities be overpast."},{"verse":2,"text":"I will cry unto God most high; unto God that performeth all things for me."},{"verse":3,"text":"He shall send from heaven, and save me from the reproach of him that would swallow me up. Selah. God shall send forth his mercy and his truth."},{"verse":4,"text":"My soul is among lions: and I lie even among them that are set on fire, even the sons of men, whose teeth are spears and arrows, and their tongue a sharp sword."},{"verse":5,"text":"Be thou exalted, O God, above the heavens; let thy glory be above all the earth."},{"verse":6,"text":"They have prepared a net for my steps; my soul is bowed down: they have digged a pit before me, into the midst whereof they are fallen themselves. Selah."},{"verse":7,"text":"My heart is fixed, O God, my heart is fixed: I will sing and give praise."},{"verse":8,"text":"Awake up, my glory; awake, psaltery and harp: I myself will awake early."},{"verse":9,"text":"I will praise thee, O Lord, among the people: I will sing unto thee among the nations."},{"verse":10,"text":"For thy mercy is great unto the heavens, and thy truth unto the clouds."},{"verse":11,"text":"Be thou exalted, O God, above the heavens: let thy glory be above all the earth. "}]},{"chapter":58,"verses":[{"verse":1,"text":"Do ye indeed speak righteousness, O congregation? do ye judge uprightly, O ye sons of men?"},{"verse":2,"text":"Yea, in heart ye work wickedness; ye weigh the violence of your hands in the earth."},{"verse":3,"text":"The wicked are estranged from the womb: they go astray as soon as they be born, speaking lies."},{"verse":4,"text":"Their poison is like the poison of a serpent: they are like the deaf adder that stoppeth her ear;"},{"verse":5,"text":"Which will not hearken to the voice of charmers, charming never so wisely."},{"verse":6,"text":"Break their teeth, O God, in their mouth: break out the great teeth of the young lions, O Lord."},{"verse":7,"text":"Let them melt away as waters which run continually: when he bendeth his bow to shoot his arrows, let them be as cut in pieces."},{"verse":8,"text":"As a snail which melteth, let every one of them pass away: like the untimely birth of a woman, that they may not see the sun."},{"verse":9,"text":"Before your pots can feel the thorns, he shall take them away as with a whirlwind, both living, and in his wrath."},{"verse":10,"text":"The righteous shall rejoice when he seeth the vengeance: he shall wash his feet in the blood of the wicked."},{"verse":11,"text":"So that a man shall say, Verily there is a reward for the righteous: verily he is a God that judgeth in the earth. "}]},{"chapter":59,"verses":[{"verse":1,"text":"Deliver me from mine enemies, O my God: defend me from them that rise up against me."},{"verse":2,"text":"Deliver me from the workers of iniquity, and save me from bloody men."},{"verse":3,"text":"For, lo, they lie in wait for my soul: the mighty are gathered against me; not for my transgression, nor for my sin, O Lord."},{"verse":4,"text":"They run and prepare themselves without my fault: awake to help me, and behold."},{"verse":5,"text":"Thou therefore, O Lord God of hosts, the God of Israel, awake to visit all the heathen: be not merciful to any wicked transgressors. Selah."},{"verse":6,"text":"They return at evening: they make a noise like a dog, and go round about the city."},{"verse":7,"text":"Behold, they belch out with their mouth: swords are in their lips: for who, say they, doth hear?"},{"verse":8,"text":"But thou, O Lord, shalt laugh at them; thou shalt have all the heathen in derision."},{"verse":9,"text":"Because of his strength will I wait upon thee: for God is my defence."},{"verse":10,"text":"The God of my mercy shall prevent me: God shall let me see my desire upon mine enemies."},{"verse":11,"text":"Slay them not, lest my people forget: scatter them by thy power; and bring them down, O Lord our shield."},{"verse":12,"text":"For the sin of their mouth and the words of their lips let them even be taken in their pride: and for cursing and lying which they speak."},{"verse":13,"text":"Consume them in wrath, consume them, that they may not be: and let them know that God ruleth in Jacob unto the ends of the earth. Selah."},{"verse":14,"text":"And at evening let them return; and let them make a noise like a dog, and go round about the city."},{"verse":15,"text":"Let them wander up and down for meat, and grudge if they be not satisfied."},{"verse":16,"text":"But I will sing of thy power; yea, I will sing aloud of thy mercy in the morning: for thou hast been my defence and refuge in the day of my trouble."},{"verse":17,"text":"Unto thee, O my strength, will I sing: for God is my defence, and the God of my mercy. "}]},{"chapter":60,"verses":[{"verse":1,"text":"O God, thou hast cast us off, thou hast scattered us, thou hast been displeased; O turn thyself to us again."},{"verse":2,"text":"Thou hast made the earth to tremble; thou hast broken it: heal the breaches thereof; for it shaketh."},{"verse":3,"text":"Thou hast shewed thy people hard things: thou hast made us to drink the wine of astonishment."},{"verse":4,"text":"Thou hast given a banner to them that fear thee, that it may be displayed because of the truth. Selah."},{"verse":5,"text":"That thy beloved may be delivered; save with thy right hand, and hear me."},{"verse":6,"text":"God hath spoken in his holiness; I will rejoice, I will divide Shechem, and mete out the valley of Succoth."},{"verse":7,"text":"Gilead is mine, and Manasseh is mine; Ephraim also is the strength of mine head; Judah is my lawgiver;"},{"verse":8,"text":"Moab is my washpot; over Edom will I cast out my shoe: Philistia, triumph thou because of me."},{"verse":9,"text":"Who will bring me into the strong city? who will lead me into Edom?"},{"verse":10,"text":"Wilt not thou, O God, which hadst cast us off? and thou, O God, which didst not go out with our armies?"},{"verse":11,"text":"Give us help from trouble: for vain is the help of man."},{"verse":12,"text":"Through God we shall do valiantly: for he it is that shall tread down our enemies. "}]},{"chapter":61,"verses":[{"verse":1,"text":"Hear my cry, O God; attend unto my prayer."},{"verse":2,"text":"From the end of the earth will I cry unto thee, when my heart is overwhelmed: lead me to the rock that is higher than I."},{"verse":3,"text":"For thou hast been a shelter for me, and a strong tower from the enemy."},{"verse":4,"text":"I will abide in thy tabernacle for ever: I will trust in the covert of thy wings. Selah."},{"verse":5,"text":"For thou, O God, hast heard my vows: thou hast given me the heritage of those that fear thy name."},{"verse":6,"text":"Thou wilt prolong the king’s life: and his years as many generations."},{"verse":7,"text":"He shall abide before God for ever: O prepare mercy and truth, which may preserve him."},{"verse":8,"text":"So will I sing praise unto thy name for ever, that I may daily perform my vows. "}]},{"chapter":62,"verses":[{"verse":1,"text":"Truly my soul waiteth upon God: from him cometh my salvation."},{"verse":2,"text":"He only is my rock and my salvation; he is my defence; I shall not be greatly moved."},{"verse":3,"text":"How long will ye imagine mischief against a man? ye shall be slain all of you: as a bowing wall shall ye be, and as a tottering fence."},{"verse":4,"text":"They only consult to cast him down from his excellency: they delight in lies: they bless with their mouth, but they curse inwardly. Selah."},{"verse":5,"text":"My soul, wait thou only upon God; for my expectation is from him."},{"verse":6,"text":"He only is my rock and my salvation: he is my defence; I shall not be moved."},{"verse":7,"text":"In God is my salvation and my glory: the rock of my strength, and my refuge, is in God."},{"verse":8,"text":"Trust in him at all times; ye people, pour out your heart before him: God is a refuge for us. Selah."},{"verse":9,"text":"Surely men of low degree are vanity, and men of high degree are a lie: to be laid in the balance, they are altogether lighter than vanity."},{"verse":10,"text":"Trust not in oppression, and become not vain in robbery: if riches increase, set not your heart upon them."},{"verse":11,"text":"God hath spoken once; twice have I heard this; that power belongeth unto God."},{"verse":12,"text":"Also unto thee, O Lord, belongeth mercy: for thou renderest to every man according to his work. "}]},{"chapter":63,"verses":[{"verse":1,"text":"O God, thou art my God; early will I seek thee: my soul thirsteth for thee, my flesh longeth for thee in a dry and thirsty land, where no water is;"},{"verse":2,"text":"To see thy power and thy glory, so as I have seen thee in the sanctuary."},{"verse":3,"text":"Because thy lovingkindness is better than life, my lips shall praise thee."},{"verse":4,"text":"Thus will I bless thee while I live: I will lift up my hands in thy name."},{"verse":5,"text":"My soul shall be satisfied as with marrow and fatness; and my mouth shall praise thee with joyful lips:"},{"verse":6,"text":"When I remember thee upon my bed, and meditate on thee in the night watches."},{"verse":7,"text":"Because thou hast been my help, therefore in the shadow of thy wings will I rejoice."},{"verse":8,"text":"My soul followeth hard after thee: thy right hand upholdeth me."},{"verse":9,"text":"But those that seek my soul, to destroy it, shall go into the lower parts of the earth."},{"verse":10,"text":"They shall fall by the sword: they shall be a portion for foxes."},{"verse":11,"text":"But the king shall rejoice in God; every one that sweareth by him shall glory: but the mouth of them that speak lies shall be stopped. "}]},{"chapter":64,"verses":[{"verse":1,"text":"Hear my voice, O God, in my prayer: preserve my life from fear of the enemy."},{"verse":2,"text":"Hide me from the secret counsel of the wicked; from the insurrection of the workers of iniquity:"},{"verse":3,"text":"Who whet their tongue like a sword, and bend their bows to shoot their arrows, even bitter words:"},{"verse":4,"text":"That they may shoot in secret at the perfect: suddenly do they shoot at him, and fear not."},{"verse":5,"text":"They encourage themselves in an evil matter: they commune of laying snares privily; they say, Who shall see them?"},{"verse":6,"text":"They search out iniquities; they accomplish a diligent search: both the inward thought of every one of them, and the heart, is deep."},{"verse":7,"text":"But God shall shoot at them with an arrow; suddenly shall they be wounded."},{"verse":8,"text":"So they shall make their own tongue to fall upon themselves: all that see them shall flee away."},{"verse":9,"text":"And all men shall fear, and shall declare the work of God; for they shall wisely consider of his doing."},{"verse":10,"text":"The righteous shall be glad in the Lord, and shall trust in him; and all the upright in heart shall glory. "}]},{"chapter":65,"verses":[{"verse":1,"text":"Praise waiteth for thee, O God, in Sion: and unto thee shall the vow be performed."},{"verse":2,"text":"O thou that hearest prayer, unto thee shall all flesh come."},{"verse":3,"text":"Iniquities prevail against me: as for our transgressions, thou shalt purge them away."},{"verse":4,"text":"Blessed is the man whom thou choosest, and causest to approach unto thee, that he may dwell in thy courts: we shall be satisfied with the goodness of thy house, even of thy holy temple."},{"verse":5,"text":"By terrible things in righteousness wilt thou answer us, O God of our salvation; who art the confidence of all the ends of the earth, and of them that are afar off upon the sea:"},{"verse":6,"text":"Which by his strength setteth fast the mountains; being girded with power:"},{"verse":7,"text":"Which stilleth the noise of the seas, the noise of their waves, and the tumult of the people."},{"verse":8,"text":"They also that dwell in the uttermost parts are afraid at thy tokens: thou makest the outgoings of the morning and evening to rejoice."},{"verse":9,"text":"Thou visitest the earth, and waterest it: thou greatly enrichest it with the river of God, which is full of water: thou preparest them corn, when thou hast so provided for it."},{"verse":10,"text":"Thou waterest the ridges thereof abundantly: thou settlest the furrows thereof: thou makest it soft with showers: thou blessest the springing thereof."},{"verse":11,"text":"Thou crownest the year with thy goodness; and thy paths drop fatness."},{"verse":12,"text":"They drop upon the pastures of the wilderness: and the little hills rejoice on every side."},{"verse":13,"text":"The pastures are clothed with flocks; the valleys also are covered over with corn; they shout for joy, they also sing. "}]},{"chapter":66,"verses":[{"verse":1,"text":"Make a joyful noise unto God, all ye lands:"},{"verse":2,"text":"Sing forth the honour of his name: make his praise glorious."},{"verse":3,"text":"Say unto God, How terrible art thou in thy works! through the greatness of thy power shall thine enemies submit themselves unto thee."},{"verse":4,"text":"All the earth shall worship thee, and shall sing unto thee; they shall sing to thy name. Selah."},{"verse":5,"text":"Come and see the works of God: he is terrible in his doing toward the children of men."},{"verse":6,"text":"He turned the sea into dry land: they went through the flood on foot: there did we rejoice in him."},{"verse":7,"text":"He ruleth by his power for ever; his eyes behold the nations: let not the rebellious exalt themselves. Selah."},{"verse":8,"text":"O bless our God, ye people, and make the voice of his praise to be heard:"},{"verse":9,"text":"Which holdeth our soul in life, and suffereth not our feet to be moved."},{"verse":10,"text":"For thou, O God, hast proved us: thou hast tried us, as silver is tried."},{"verse":11,"text":"Thou broughtest us into the net; thou laidst affliction upon our loins."},{"verse":12,"text":"Thou hast caused men to ride over our heads; we went through fire and through water: but thou broughtest us out into a wealthy place."},{"verse":13,"text":"I will go into thy house with burnt offerings: I will pay thee my vows,"},{"verse":14,"text":"Which my lips have uttered, and my mouth hath spoken, when I was in trouble."},{"verse":15,"text":"I will offer unto thee burnt sacrifices of fatlings, with the incense of rams; I will offer bullocks with goats. Selah."},{"verse":16,"text":"Come and hear, all ye that fear God, and I will declare what he hath done for my soul."},{"verse":17,"text":"I cried unto him with my mouth, and he was extolled with my tongue."},{"verse":18,"text":"If I regard iniquity in my heart, the Lord will not hear me:"},{"verse":19,"text":"But verily God hath heard me; he hath attended to the voice of my prayer."},{"verse":20,"text":"Blessed be God, which hath not turned away my prayer, nor his mercy from me. "}]},{"chapter":67,"verses":[{"verse":1,"text":"God be merciful unto us, and bless us; and cause his face to shine upon us; Selah."},{"verse":2,"text":"That thy way may be known upon earth, thy saving health among all nations."},{"verse":3,"text":"Let the people praise thee, O God; let all the people praise thee."},{"verse":4,"text":"O let the nations be glad and sing for joy: for thou shalt judge the people righteously, and govern the nations upon earth. Selah."},{"verse":5,"text":"Let the people praise thee, O God; let all the people praise thee."},{"verse":6,"text":"Then shall the earth yield her increase; and God, even our own God, shall bless us."},{"verse":7,"text":"God shall bless us; and all the ends of the earth shall fear him. "}]},{"chapter":68,"verses":[{"verse":1,"text":"Let God arise, let his enemies be scattered: let them also that hate him flee before him."},{"verse":2,"text":"As smoke is driven away, so drive them away: as wax melteth before the fire, so let the wicked perish at the presence of God."},{"verse":3,"text":"But let the righteous be glad; let them rejoice before God: yea, let them exceedingly rejoice."},{"verse":4,"text":"Sing unto God, sing praises to his name: extol him that rideth upon the heavens by his name Jah, and rejoice before him."},{"verse":5,"text":"A father of the fatherless, and a judge of the widows, is God in his holy habitation."},{"verse":6,"text":"God setteth the solitary in families: he bringeth out those which are bound with chains: but the rebellious dwell in a dry land."},{"verse":7,"text":"O God, when thou wentest forth before thy people, when thou didst march through the wilderness; Selah:"},{"verse":8,"text":"The earth shook, the heavens also dropped at the presence of God: even Sinai itself was moved at the presence of God, the God of Israel."},{"verse":9,"text":"Thou, O God, didst send a plentiful rain, whereby thou didst confirm thine inheritance, when it was weary."},{"verse":10,"text":"Thy congregation hath dwelt therein: thou, O God, hast prepared of thy goodness for the poor."},{"verse":11,"text":"The Lord gave the word: great was the company of those that published it."},{"verse":12,"text":"Kings of armies did flee apace: and she that tarried at home divided the spoil."},{"verse":13,"text":"Though ye have lien among the pots, yet shall ye be as the wings of a dove covered with silver, and her feathers with yellow gold."},{"verse":14,"text":"When the Almighty scattered kings in it, it was white as snow in Salmon."},{"verse":15,"text":"The hill of God is as the hill of Bashan; an high hill as the hill of Bashan."},{"verse":16,"text":"Why leap ye, ye high hills? this is the hill which God desireth to dwell in; yea, the Lord will dwell in it for ever."},{"verse":17,"text":"The chariots of God are twenty thousand, even thousands of angels: the Lord is among them, as in Sinai, in the holy place."},{"verse":18,"text":"Thou hast ascended on high, thou hast led captivity captive: thou hast received gifts for men; yea, for the rebellious also, that the Lord God might dwell among them."},{"verse":19,"text":"Blessed be the Lord, who daily loadeth us with benefits, even the God of our salvation. Selah."},{"verse":20,"text":"He that is our God is the God of salvation; and unto God the Lord belong the issues from death."},{"verse":21,"text":"But God shall wound the head of his enemies, and the hairy scalp of such an one as goeth on still in his trespasses."},{"verse":22,"text":"The Lord said, I will bring again from Bashan, I will bring my people again from the depths of the sea:"},{"verse":23,"text":"That thy foot may be dipped in the blood of thine enemies, and the tongue of thy dogs in the same."},{"verse":24,"text":"They have seen thy goings, O God; even the goings of my God, my King, in the sanctuary."},{"verse":25,"text":"The singers went before, the players on instruments followed after; among them were the damsels playing with timbrels."},{"verse":26,"text":"Bless ye God in the congregations, even the Lord, from the fountain of Israel."},{"verse":27,"text":"There is little Benjamin with their ruler, the princes of Judah and their council, the princes of Zebulun, and the princes of Naphtali."},{"verse":28,"text":"Thy God hath commanded thy strength: strengthen, O God, that which thou hast wrought for us."},{"verse":29,"text":"Because of thy temple at Jerusalem shall kings bring presents unto thee."},{"verse":30,"text":"Rebuke the company of spearmen, the multitude of the bulls, with the calves of the people, till every one submit himself with pieces of silver: scatter thou the people that delight in war."},{"verse":31,"text":"Princes shall come out of Egypt; Ethiopia shall soon stretch out her hands unto God."},{"verse":32,"text":"Sing unto God, ye kingdoms of the earth; O sing praises unto the Lord; Selah:"},{"verse":33,"text":"To him that rideth upon the heavens of heavens, which were of old; lo, he doth send out his voice, and that a mighty voice."},{"verse":34,"text":"Ascribe ye strength unto God: his excellency is over Israel, and his strength is in the clouds."},{"verse":35,"text":"O God, thou art terrible out of thy holy places: the God of Israel is he that giveth strength and power unto his people. Blessed be God. "}]},{"chapter":69,"verses":[{"verse":1,"text":"Save me, O God; for the waters are come in unto my soul."},{"verse":2,"text":"I sink in deep mire, where there is no standing: I am come into deep waters, where the floods overflow me."},{"verse":3,"text":"I am weary of my crying: my throat is dried: mine eyes fail while I wait for my God."},{"verse":4,"text":"They that hate me without a cause are more than the hairs of mine head: they that would destroy me, being mine enemies wrongfully, are mighty: then I restored that which I took not away."},{"verse":5,"text":"O God, thou knowest my foolishness; and my sins are not hid from thee."},{"verse":6,"text":"Let not them that wait on thee, O Lord God of hosts, be ashamed for my sake: let not those that seek thee be confounded for my sake, O God of Israel."},{"verse":7,"text":"Because for thy sake I have borne reproach; shame hath covered my face."},{"verse":8,"text":"I am become a stranger unto my brethren, and an alien unto my mother’s children."},{"verse":9,"text":"For the zeal of thine house hath eaten me up; and the reproaches of them that reproached thee are fallen upon me."},{"verse":10,"text":"When I wept, and chastened my soul with fasting, that was to my reproach."},{"verse":11,"text":"I made sackcloth also my garment; and I became a proverb to them."},{"verse":12,"text":"They that sit in the gate speak against me; and I was the song of the drunkards."},{"verse":13,"text":"But as for me, my prayer is unto thee, O Lord, in an acceptable time: O God, in the multitude of thy mercy hear me, in the truth of thy salvation."},{"verse":14,"text":"Deliver me out of the mire, and let me not sink: let me be delivered from them that hate me, and out of the deep waters."},{"verse":15,"text":"Let not the waterflood overflow me, neither let the deep swallow me up, and let not the pit shut her mouth upon me."},{"verse":16,"text":"Hear me, O Lord; for thy lovingkindness is good: turn unto me according to the multitude of thy tender mercies."},{"verse":17,"text":"And hide not thy face from thy servant; for I am in trouble: hear me speedily."},{"verse":18,"text":"Draw nigh unto my soul, and redeem it: deliver me because of mine enemies."},{"verse":19,"text":"Thou hast known my reproach, and my shame, and my dishonour: mine adversaries are all before thee."},{"verse":20,"text":"Reproach hath broken my heart; and I am full of heaviness: and I looked for some to take pity, but there was none; and for comforters, but I found none."},{"verse":21,"text":"They gave me also gall for my meat; and in my thirst they gave me vinegar to drink."},{"verse":22,"text":"Let their table become a snare before them: and that which should have been for their welfare, let it become a trap."},{"verse":23,"text":"Let their eyes be darkened, that they see not; and make their loins continually to shake."},{"verse":24,"text":"Pour out thine indignation upon them, and let thy wrathful anger take hold of them."},{"verse":25,"text":"Let their habitation be desolate; and let none dwell in their tents."},{"verse":26,"text":"For they persecute him whom thou hast smitten; and they talk to the grief of those whom thou hast wounded."},{"verse":27,"text":"Add iniquity unto their iniquity: and let them not come into thy righteousness."},{"verse":28,"text":"Let them be blotted out of the book of the living, and not be written with the righteous."},{"verse":29,"text":"But I am poor and sorrowful: let thy salvation, O God, set me up on high."},{"verse":30,"text":"I will praise the name of God with a song, and will magnify him with thanksgiving."},{"verse":31,"text":"This also shall please the Lord better than an ox or bullock that hath horns and hoofs."},{"verse":32,"text":"The humble shall see this, and be glad: and your heart shall live that seek God."},{"verse":33,"text":"For the Lord heareth the poor, and despiseth not his prisoners."},{"verse":34,"text":"Let the heaven and earth praise him, the seas, and every thing that moveth therein."},{"verse":35,"text":"For God will save Zion, and will build the cities of Judah: that they may dwell there, and have it in possession."},{"verse":36,"text":"The seed also of his servants shall inherit it: and they that love his name shall dwell therein. "}]},{"chapter":70,"verses":[{"verse":1,"text":"Make haste, O God, to deliver me; make haste to help me, O Lord."},{"verse":2,"text":"Let them be ashamed and confounded that seek after my soul: let them be turned backward, and put to confusion, that desire my hurt."},{"verse":3,"text":"Let them be turned back for a reward of their shame that say, Aha, aha."},{"verse":4,"text":"Let all those that seek thee rejoice and be glad in thee: and let such as love thy salvation say continually, Let God be magnified."},{"verse":5,"text":"But I am poor and needy: make haste unto me, O God: thou art my help and my deliverer; O Lord, make no tarrying. "}]},{"chapter":71,"verses":[{"verse":1,"text":"In thee, O Lord, do I put my trust: let me never be put to confusion."},{"verse":2,"text":"Deliver me in thy righteousness, and cause me to escape: incline thine ear unto me, and save me."},{"verse":3,"text":"Be thou my strong habitation, whereunto I may continually resort: thou hast given commandment to save me; for thou art my rock and my fortress."},{"verse":4,"text":"Deliver me, O my God, out of the hand of the wicked, out of the hand of the unrighteous and cruel man."},{"verse":5,"text":"For thou art my hope, O Lord God: thou art my trust from my youth."},{"verse":6,"text":"By thee have I been holden up from the womb: thou art he that took me out of my mother’s bowels: my praise shall be continually of thee."},{"verse":7,"text":"I am as a wonder unto many; but thou art my strong refuge."},{"verse":8,"text":"Let my mouth be filled with thy praise and with thy honour all the day."},{"verse":9,"text":"Cast me not off in the time of old age; forsake me not when my strength faileth."},{"verse":10,"text":"For mine enemies speak against me; and they that lay wait for my soul take counsel together,"},{"verse":11,"text":"Saying, God hath forsaken him: persecute and take him; for there is none to deliver him."},{"verse":12,"text":"O God, be not far from me: O my God, make haste for my help."},{"verse":13,"text":"Let them be confounded and consumed that are adversaries to my soul; let them be covered with reproach and dishonour that seek my hurt."},{"verse":14,"text":"But I will hope continually, and will yet praise thee more and more."},{"verse":15,"text":"My mouth shall shew forth thy righteousness and thy salvation all the day; for I know not the numbers thereof."},{"verse":16,"text":"I will go in the strength of the Lord God: I will make mention of thy righteousness, even of thine only."},{"verse":17,"text":"O God, thou hast taught me from my youth: and hitherto have I declared thy wondrous works."},{"verse":18,"text":"Now also when I am old and grayheaded, O God, forsake me not; until I have shewed thy strength unto this generation, and thy power to every one that is to come."},{"verse":19,"text":"Thy righteousness also, O God, is very high, who hast done great things: O God, who is like unto thee!"},{"verse":20,"text":"Thou, which hast shewed me great and sore troubles, shalt quicken me again, and shalt bring me up again from the depths of the earth."},{"verse":21,"text":"Thou shalt increase my greatness, and comfort me on every side."},{"verse":22,"text":"I will also praise thee with the psaltery, even thy truth, O my God: unto thee will I sing with the harp, O thou Holy One of Israel."},{"verse":23,"text":"My lips shall greatly rejoice when I sing unto thee; and my soul, which thou hast redeemed."},{"verse":24,"text":"My tongue also shall talk of thy righteousness all the day long: for they are confounded, for they are brought unto shame, that seek my hurt. "}]},{"chapter":72,"verses":[{"verse":1,"text":"Give the king thy judgments, O God, and thy righteousness unto the king’s son."},{"verse":2,"text":"He shall judge thy people with righteousness, and thy poor with judgment."},{"verse":3,"text":"The mountains shall bring peace to the people, and the little hills, by righteousness."},{"verse":4,"text":"He shall judge the poor of the people, he shall save the children of the needy, and shall break in pieces the oppressor."},{"verse":5,"text":"They shall fear thee as long as the sun and moon endure, throughout all generations."},{"verse":6,"text":"He shall come down like rain upon the mown grass: as showers that water the earth."},{"verse":7,"text":"In his days shall the righteous flourish; and abundance of peace so long as the moon endureth."},{"verse":8,"text":"He shall have dominion also from sea to sea, and from the river unto the ends of the earth."},{"verse":9,"text":"They that dwell in the wilderness shall bow before him; and his enemies shall lick the dust."},{"verse":10,"text":"The kings of Tarshish and of the isles shall bring presents: the kings of Sheba and Seba shall offer gifts."},{"verse":11,"text":"Yea, all kings shall fall down before him: all nations shall serve him."},{"verse":12,"text":"For he shall deliver the needy when he crieth; the poor also, and him that hath no helper."},{"verse":13,"text":"He shall spare the poor and needy, and shall save the souls of the needy."},{"verse":14,"text":"He shall redeem their soul from deceit and violence: and precious shall their blood be in his sight."},{"verse":15,"text":"And he shall live, and to him shall be given of the gold of Sheba: prayer also shall be made for him continually; and daily shall he be praised."},{"verse":16,"text":"There shall be an handful of corn in the earth upon the top of the mountains; the fruit thereof shall shake like Lebanon: and they of the city shall flourish like grass of the earth."},{"verse":17,"text":"His name shall endure for ever: his name shall be continued as long as the sun: and men shall be blessed in him: all nations shall call him blessed."},{"verse":18,"text":"Blessed be the Lord God, the God of Israel, who only doeth wondrous things."},{"verse":19,"text":"And blessed be his glorious name for ever: and let the whole earth be filled with his glory; Amen, and Amen."},{"verse":20,"text":"The prayers of David the son of Jesse are ended. "}]},{"chapter":73,"verses":[{"verse":1,"text":"Truly God is good to Israel, even to such as are of a clean heart."},{"verse":2,"text":"But as for me, my feet were almost gone; my steps had well nigh slipped."},{"verse":3,"text":"For I was envious at the foolish, when I saw the prosperity of the wicked."},{"verse":4,"text":"For there are no bands in their death: but their strength is firm."},{"verse":5,"text":"They are not in trouble as other men; neither are they plagued like other men."},{"verse":6,"text":"Therefore pride compasseth them about as a chain; violence covereth them as a garment."},{"verse":7,"text":"Their eyes stand out with fatness: they have more than heart could wish."},{"verse":8,"text":"They are corrupt, and speak wickedly concerning oppression: they speak loftily."},{"verse":9,"text":"They set their mouth against the heavens, and their tongue walketh through the earth."},{"verse":10,"text":"Therefore his people return hither: and waters of a full cup are wrung out to them."},{"verse":11,"text":"And they say, How doth God know? and is there knowledge in the most High?"},{"verse":12,"text":"Behold, these are the ungodly, who prosper in the world; they increase in riches."},{"verse":13,"text":"Verily I have cleansed my heart in vain, and washed my hands in innocency."},{"verse":14,"text":"For all the day long have I been plagued, and chastened every morning."},{"verse":15,"text":"If I say, I will speak thus; behold, I should offend against the generation of thy children."},{"verse":16,"text":"When I thought to know this, it was too painful for me;"},{"verse":17,"text":"Until I went into the sanctuary of God; then understood I their end."},{"verse":18,"text":"Surely thou didst set them in slippery places: thou castedst them down into destruction."},{"verse":19,"text":"How are they brought into desolation, as in a moment! they are utterly consumed with terrors."},{"verse":20,"text":"As a dream when one awaketh; so, O Lord, when thou awakest, thou shalt despise their image."},{"verse":21,"text":"Thus my heart was grieved, and I was pricked in my reins."},{"verse":22,"text":"So foolish was I, and ignorant: I was as a beast before thee."},{"verse":23,"text":"Nevertheless I am continually with thee: thou hast holden me by my right hand."},{"verse":24,"text":"Thou shalt guide me with thy counsel, and afterward receive me to glory."},{"verse":25,"text":"Whom have I in heaven but thee? and there is none upon earth that I desire beside thee."},{"verse":26,"text":"My flesh and my heart faileth: but God is the strength of my heart, and my portion for ever."},{"verse":27,"text":"For, lo, they that are far from thee shall perish: thou hast destroyed all them that go a whoring from thee."},{"verse":28,"text":"But it is good for me to draw near to God: I have put my trust in the Lord God, that I may declare all thy works. "}]},{"chapter":74,"verses":[{"verse":1,"text":"O God, why hast thou cast us off for ever? why doth thine anger smoke against the sheep of thy pasture?"},{"verse":2,"text":"Remember thy congregation, which thou hast purchased of old; the rod of thine inheritance, which thou hast redeemed; this mount Zion, wherein thou hast dwelt."},{"verse":3,"text":"Lift up thy feet unto the perpetual desolations; even all that the enemy hath done wickedly in the sanctuary."},{"verse":4,"text":"Thine enemies roar in the midst of thy congregations; they set up their ensigns for signs."},{"verse":5,"text":"A man was famous according as he had lifted up axes upon the thick trees."},{"verse":6,"text":"But now they break down the carved work thereof at once with axes and hammers."},{"verse":7,"text":"They have cast fire into thy sanctuary, they have defiled by casting down the dwelling place of thy name to the ground."},{"verse":8,"text":"They said in their hearts, Let us destroy them together: they have burned up all the synagogues of God in the land."},{"verse":9,"text":"We see not our signs: there is no more any prophet: neither is there among us any that knoweth how long."},{"verse":10,"text":"O God, how long shall the adversary reproach? shall the enemy blaspheme thy name for ever?"},{"verse":11,"text":"Why withdrawest thou thy hand, even thy right hand? pluck it out of thy bosom."},{"verse":12,"text":"For God is my King of old, working salvation in the midst of the earth."},{"verse":13,"text":"Thou didst divide the sea by thy strength: thou brakest the heads of the dragons in the waters."},{"verse":14,"text":"Thou brakest the heads of leviathan in pieces, and gavest him to be meat to the people inhabiting the wilderness."},{"verse":15,"text":"Thou didst cleave the fountain and the flood: thou driedst up mighty rivers."},{"verse":16,"text":"The day is thine, the night also is thine: thou hast prepared the light and the sun."},{"verse":17,"text":"Thou hast set all the borders of the earth: thou hast made summer and winter."},{"verse":18,"text":"Remember this, that the enemy hath reproached, O Lord, and that the foolish people have blasphemed thy name."},{"verse":19,"text":"O deliver not the soul of thy turtledove unto the multitude of the wicked: forget not the congregation of thy poor for ever."},{"verse":20,"text":"Have respect unto the covenant: for the dark places of the earth are full of the habitations of cruelty."},{"verse":21,"text":"O let not the oppressed return ashamed: let the poor and needy praise thy name."},{"verse":22,"text":"Arise, O God, plead thine own cause: remember how the foolish man reproacheth thee daily."},{"verse":23,"text":"Forget not the voice of thine enemies: the tumult of those that rise up against thee increaseth continually. "}]},{"chapter":75,"verses":[{"verse":1,"text":"Unto thee, O God, do we give thanks, unto thee do we give thanks: for that thy name is near thy wondrous works declare."},{"verse":2,"text":"When I shall receive the congregation I will judge uprightly."},{"verse":3,"text":"The earth and all the inhabitants thereof are dissolved: I bear up the pillars of it. Selah."},{"verse":4,"text":"I said unto the fools, Deal not foolishly: and to the wicked, Lift not up the horn:"},{"verse":5,"text":"Lift not up your horn on high: speak not with a stiff neck."},{"verse":6,"text":"For promotion cometh neither from the east, nor from the west, nor from the south."},{"verse":7,"text":"But God is the judge: he putteth down one, and setteth up another."},{"verse":8,"text":"For in the hand of the Lord there is a cup, and the wine is red; it is full of mixture; and he poureth out of the same: but the dregs thereof, all the wicked of the earth shall wring them out, and drink them."},{"verse":9,"text":"But I will declare for ever; I will sing praises to the God of Jacob."},{"verse":10,"text":"All the horns of the wicked also will I cut off; but the horns of the righteous shall be exalted. "}]},{"chapter":76,"verses":[{"verse":1,"text":"In Judah is God known: his name is great in Israel."},{"verse":2,"text":"In Salem also is his tabernacle, and his dwelling place in Zion."},{"verse":3,"text":"There brake he the arrows of the bow, the shield, and the sword, and the battle. Selah."},{"verse":4,"text":"Thou art more glorious and excellent than the mountains of prey."},{"verse":5,"text":"The stouthearted are spoiled, they have slept their sleep: and none of the men of might have found their hands."},{"verse":6,"text":"At thy rebuke, O God of Jacob, both the chariot and horse are cast into a dead sleep."},{"verse":7,"text":"Thou, even thou, art to be feared: and who may stand in thy sight when once thou art angry?"},{"verse":8,"text":"Thou didst cause judgment to be heard from heaven; the earth feared, and was still,"},{"verse":9,"text":"When God arose to judgment, to save all the meek of the earth. Selah."},{"verse":10,"text":"Surely the wrath of man shall praise thee: the remainder of wrath shalt thou restrain."},{"verse":11,"text":"Vow, and pay unto the Lord your God: let all that be round about him bring presents unto him that ought to be feared."},{"verse":12,"text":"He shall cut off the spirit of princes: he is terrible to the kings of the earth. "}]},{"chapter":77,"verses":[{"verse":1,"text":"I cried unto God with my voice, even unto God with my voice; and he gave ear unto me."},{"verse":2,"text":"In the day of my trouble I sought the Lord: my sore ran in the night, and ceased not: my soul refused to be comforted."},{"verse":3,"text":"I remembered God, and was troubled: I complained, and my spirit was overwhelmed. Selah."},{"verse":4,"text":"Thou holdest mine eyes waking: I am so troubled that I cannot speak."},{"verse":5,"text":"I have considered the days of old, the years of ancient times."},{"verse":6,"text":"I call to remembrance my song in the night: I commune with mine own heart: and my spirit made diligent search."},{"verse":7,"text":"Will the Lord cast off for ever? and will he be favourable no more?"},{"verse":8,"text":"Is his mercy clean gone for ever? doth his promise fail for evermore?"},{"verse":9,"text":"Hath God forgotten to be gracious? hath he in anger shut up his tender mercies? Selah."},{"verse":10,"text":"And I said, This is my infirmity: but I will remember the years of the right hand of the most High."},{"verse":11,"text":"I will remember the works of the Lord: surely I will remember thy wonders of old."},{"verse":12,"text":"I will meditate also of all thy work, and talk of thy doings."},{"verse":13,"text":"Thy way, O God, is in the sanctuary: who is so great a God as our God?"},{"verse":14,"text":"Thou art the God that doest wonders: thou hast declared thy strength among the people."},{"verse":15,"text":"Thou hast with thine arm redeemed thy people, the sons of Jacob and Joseph. Selah."},{"verse":16,"text":"The waters saw thee, O God, the waters saw thee; they were afraid: the depths also were troubled."},{"verse":17,"text":"The clouds poured out water: the skies sent out a sound: thine arrows also went abroad."},{"verse":18,"text":"The voice of thy thunder was in the heaven: the lightnings lightened the world: the earth trembled and shook."},{"verse":19,"text":"Thy way is in the sea, and thy path in the great waters, and thy footsteps are not known."},{"verse":20,"text":"Thou leddest thy people like a flock by the hand of Moses and Aaron. "}]},{"chapter":78,"verses":[{"verse":1,"text":"Give ear, O my people, to my law: incline your ears to the words of my mouth."},{"verse":2,"text":"I will open my mouth in a parable: I will utter dark sayings of old:"},{"verse":3,"text":"Which we have heard and known, and our fathers have told us."},{"verse":4,"text":"We will not hide them from their children, shewing to the generation to come the praises of the Lord, and his strength, and his wonderful works that he hath done."},{"verse":5,"text":"For he established a testimony in Jacob, and appointed a law in Israel, which he commanded our fathers, that they should make them known to their children:"},{"verse":6,"text":"That the generation to come might know them, even the children which should be born; who should arise and declare them to their children:"},{"verse":7,"text":"That they might set their hope in God, and not forget the works of God, but keep his commandments:"},{"verse":8,"text":"And might not be as their fathers, a stubborn and rebellious generation; a generation that set not their heart aright, and whose spirit was not stedfast with God."},{"verse":9,"text":"The children of Ephraim, being armed, and carrying bows, turned back in the day of battle."},{"verse":10,"text":"They kept not the covenant of God, and refused to walk in his law;"},{"verse":11,"text":"And forgat his works, and his wonders that he had shewed them."},{"verse":12,"text":"Marvellous things did he in the sight of their fathers, in the land of Egypt, in the field of Zoan."},{"verse":13,"text":"He divided the sea, and caused them to pass through; and he made the waters to stand as an heap."},{"verse":14,"text":"In the daytime also he led them with a cloud, and all the night with a light of fire."},{"verse":15,"text":"He clave the rocks in the wilderness, and gave them drink as out of the great depths."},{"verse":16,"text":"He brought streams also out of the rock, and caused waters to run down like rivers."},{"verse":17,"text":"And they sinned yet more against him by provoking the most High in the wilderness."},{"verse":18,"text":"And they tempted God in their heart by asking meat for their lust."},{"verse":19,"text":"Yea, they spake against God; they said, Can God furnish a table in the wilderness?"},{"verse":20,"text":"Behold, he smote the rock, that the waters gushed out, and the streams overflowed; can he give bread also? can he provide flesh for his people?"},{"verse":21,"text":"Therefore the Lord heard this, and was wroth: so a fire was kindled against Jacob, and anger also came up against Israel;"},{"verse":22,"text":"Because they believed not in God, and trusted not in his salvation:"},{"verse":23,"text":"Though he had commanded the clouds from above, and opened the doors of heaven,"},{"verse":24,"text":"And had rained down manna upon them to eat, and had given them of the corn of heaven."},{"verse":25,"text":"Man did eat angels’ food: he sent them meat to the full."},{"verse":26,"text":"He caused an east wind to blow in the heaven: and by his power he brought in the south wind."},{"verse":27,"text":"He rained flesh also upon them as dust, and feathered fowls like as the sand of the sea:"},{"verse":28,"text":"And he let it fall in the midst of their camp, round about their habitations."},{"verse":29,"text":"So they did eat, and were well filled: for he gave them their own desire;"},{"verse":30,"text":"They were not estranged from their lust. But while their meat was yet in their mouths,"},{"verse":31,"text":"The wrath of God came upon them, and slew the fattest of them, and smote down the chosen men of Israel."},{"verse":32,"text":"For all this they sinned still, and believed not for his wondrous works."},{"verse":33,"text":"Therefore their days did he consume in vanity, and their years in trouble."},{"verse":34,"text":"When he slew them, then they sought him: and they returned and enquired early after God."},{"verse":35,"text":"And they remembered that God was their rock, and the high God their redeemer."},{"verse":36,"text":"Nevertheless they did flatter him with their mouth, and they lied unto him with their tongues."},{"verse":37,"text":"For their heart was not right with him, neither were they stedfast in his covenant."},{"verse":38,"text":"But he, being full of compassion, forgave their iniquity, and destroyed them not: yea, many a time turned he his anger away, and did not stir up all his wrath."},{"verse":39,"text":"For he remembered that they were but flesh; a wind that passeth away, and cometh not again."},{"verse":40,"text":"How oft did they provoke him in the wilderness, and grieve him in the desert!"},{"verse":41,"text":"Yea, they turned back and tempted God, and limited the Holy One of Israel."},{"verse":42,"text":"They remembered not his hand, nor the day when he delivered them from the enemy."},{"verse":43,"text":"How he had wrought his signs in Egypt, and his wonders in the field of Zoan:"},{"verse":44,"text":"And had turned their rivers into blood; and their floods, that they could not drink."},{"verse":45,"text":"He sent divers sorts of flies among them, which devoured them; and frogs, which destroyed them."},{"verse":46,"text":"He gave also their increase unto the caterpiller, and their labour unto the locust."},{"verse":47,"text":"He destroyed their vines with hail, and their sycomore trees with frost."},{"verse":48,"text":"He gave up their cattle also to the hail, and their flocks to hot thunderbolts."},{"verse":49,"text":"He cast upon them the fierceness of his anger, wrath, and indignation, and trouble, by sending evil angels among them."},{"verse":50,"text":"He made a way to his anger; he spared not their soul from death, but gave their life over to the pestilence;"},{"verse":51,"text":"And smote all the firstborn in Egypt; the chief of their strength in the tabernacles of Ham:"},{"verse":52,"text":"But made his own people to go forth like sheep, and guided them in the wilderness like a flock."},{"verse":53,"text":"And he led them on safely, so that they feared not: but the sea overwhelmed their enemies."},{"verse":54,"text":"And he brought them to the border of his sanctuary, even to this mountain, which his right hand had purchased."},{"verse":55,"text":"He cast out the heathen also before them, and divided them an inheritance by line, and made the tribes of Israel to dwell in their tents."},{"verse":56,"text":"Yet they tempted and provoked the most high God, and kept not his testimonies:"},{"verse":57,"text":"But turned back, and dealt unfaithfully like their fathers: they were turned aside like a deceitful bow."},{"verse":58,"text":"For they provoked him to anger with their high places, and moved him to jealousy with their graven images."},{"verse":59,"text":"When God heard this, he was wroth, and greatly abhorred Israel:"},{"verse":60,"text":"So that he forsook the tabernacle of Shiloh, the tent which he placed among men;"},{"verse":61,"text":"And delivered his strength into captivity, and his glory into the enemy’s hand."},{"verse":62,"text":"He gave his people over also unto the sword; and was wroth with his inheritance."},{"verse":63,"text":"The fire consumed their young men; and their maidens were not given to marriage."},{"verse":64,"text":"Their priests fell by the sword; and their widows made no lamentation."},{"verse":65,"text":"Then the Lord awaked as one out of sleep, and like a mighty man that shouteth by reason of wine."},{"verse":66,"text":"And he smote his enemies in the hinder parts: he put them to a perpetual reproach."},{"verse":67,"text":"Moreover he refused the tabernacle of Joseph, and chose not the tribe of Ephraim:"},{"verse":68,"text":"But chose the tribe of Judah, the mount Zion which he loved."},{"verse":69,"text":"And he built his sanctuary like high palaces, like the earth which he hath established for ever."},{"verse":70,"text":"He chose David also his servant, and took him from the sheepfolds:"},{"verse":71,"text":"From following the ewes great with young he brought him to feed Jacob his people, and Israel his inheritance."},{"verse":72,"text":"So he fed them according to the integrity of his heart; and guided them by the skilfulness of his hands. "}]},{"chapter":79,"verses":[{"verse":1,"text":"O God, the heathen are come into thine inheritance; thy holy temple have they defiled; they have laid Jerusalem on heaps."},{"verse":2,"text":"The dead bodies of thy servants have they given to be meat unto the fowls of the heaven, the flesh of thy saints unto the beasts of the earth."},{"verse":3,"text":"Their blood have they shed like water round about Jerusalem; and there was none to bury them."},{"verse":4,"text":"We are become a reproach to our neighbours, a scorn and derision to them that are round about us."},{"verse":5,"text":"How long, Lord? wilt thou be angry for ever? shall thy jealousy burn like fire?"},{"verse":6,"text":"Pour out thy wrath upon the heathen that have not known thee, and upon the kingdoms that have not called upon thy name."},{"verse":7,"text":"For they have devoured Jacob, and laid waste his dwelling place."},{"verse":8,"text":"O remember not against us former iniquities: let thy tender mercies speedily prevent us: for we are brought very low."},{"verse":9,"text":"Help us, O God of our salvation, for the glory of thy name: and deliver us, and purge away our sins, for thy name’s sake."},{"verse":10,"text":"Wherefore should the heathen say, Where is their God? let him be known among the heathen in our sight by the revenging of the blood of thy servants which is shed."},{"verse":11,"text":"Let the sighing of the prisoner come before thee; according to the greatness of thy power preserve thou those that are appointed to die;"},{"verse":12,"text":"And render unto our neighbours sevenfold into their bosom their reproach, wherewith they have reproached thee, O Lord."},{"verse":13,"text":"So we thy people and sheep of thy pasture will give thee thanks for ever: we will shew forth thy praise to all generations. "}]},{"chapter":80,"verses":[{"verse":1,"text":"Give ear, O Shepherd of Israel, thou that leadest Joseph like a flock; thou that dwellest between the cherubims, shine forth."},{"verse":2,"text":"Before Ephraim and Benjamin and Manasseh stir up thy strength, and come and save us."},{"verse":3,"text":"Turn us again, O God, and cause thy face to shine; and we shall be saved."},{"verse":4,"text":"O Lord God of hosts, how long wilt thou be angry against the prayer of thy people?"},{"verse":5,"text":"Thou feedest them with the bread of tears; and givest them tears to drink in great measure."},{"verse":6,"text":"Thou makest us a strife unto our neighbours: and our enemies laugh among themselves."},{"verse":7,"text":"Turn us again, O God of hosts, and cause thy face to shine; and we shall be saved."},{"verse":8,"text":"Thou hast brought a vine out of Egypt: thou hast cast out the heathen, and planted it."},{"verse":9,"text":"Thou preparedst room before it, and didst cause it to take deep root, and it filled the land."},{"verse":10,"text":"The hills were covered with the shadow of it, and the boughs thereof were like the goodly cedars."},{"verse":11,"text":"She sent out her boughs unto the sea, and her branches unto the river."},{"verse":12,"text":"Why hast thou then broken down her hedges, so that all they which pass by the way do pluck her?"},{"verse":13,"text":"The boar out of the wood doth waste it, and the wild beast of the field doth devour it."},{"verse":14,"text":"Return, we beseech thee, O God of hosts: look down from heaven, and behold, and visit this vine;"},{"verse":15,"text":"And the vineyard which thy right hand hath planted, and the branch that thou madest strong for thyself."},{"verse":16,"text":"It is burned with fire, it is cut down: they perish at the rebuke of thy countenance."},{"verse":17,"text":"Let thy hand be upon the man of thy right hand, upon the son of man whom thou madest strong for thyself."},{"verse":18,"text":"So will not we go back from thee: quicken us, and we will call upon thy name."},{"verse":19,"text":"Turn us again, O Lord God of hosts, cause thy face to shine; and we shall be saved. "}]},{"chapter":81,"verses":[{"verse":1,"text":"Sing aloud unto God our strength: make a joyful noise unto the God of Jacob."},{"verse":2,"text":"Take a psalm, and bring hither the timbrel, the pleasant harp with the psaltery."},{"verse":3,"text":"Blow up the trumpet in the new moon, in the time appointed, on our solemn feast day."},{"verse":4,"text":"For this was a statute for Israel, and a law of the God of Jacob."},{"verse":5,"text":"This he ordained in Joseph for a testimony, when he went out through the land of Egypt: where I heard a language that I understood not."},{"verse":6,"text":"I removed his shoulder from the burden: his hands were delivered from the pots."},{"verse":7,"text":"Thou calledst in trouble, and I delivered thee; I answered thee in the secret place of thunder: I proved thee at the waters of Meribah. Selah."},{"verse":8,"text":"Hear, O my people, and I will testify unto thee: O Israel, if thou wilt hearken unto me;"},{"verse":9,"text":"There shall no strange god be in thee; neither shalt thou worship any strange god."},{"verse":10,"text":"I am the Lord thy God, which brought thee out of the land of Egypt: open thy mouth wide, and I will fill it."},{"verse":11,"text":"But my people would not hearken to my voice; and Israel would none of me."},{"verse":12,"text":"So I gave them up unto their own hearts’ lust: and they walked in their own counsels."},{"verse":13,"text":"Oh that my people had hearkened unto me, and Israel had walked in my ways!"},{"verse":14,"text":"I should soon have subdued their enemies, and turned my hand against their adversaries."},{"verse":15,"text":"The haters of the Lord should have submitted themselves unto him: but their time should have endured for ever."},{"verse":16,"text":"He should have fed them also with the finest of the wheat: and with honey out of the rock should I have satisfied thee. "}]},{"chapter":82,"verses":[{"verse":1,"text":"God standeth in the congregation of the mighty; he judgeth among the gods."},{"verse":2,"text":"How long will ye judge unjustly, and accept the persons of the wicked? Selah."},{"verse":3,"text":"Defend the poor and fatherless: do justice to the afflicted and needy."},{"verse":4,"text":"Deliver the poor and needy: rid them out of the hand of the wicked."},{"verse":5,"text":"They know not, neither will they understand; they walk on in darkness: all the foundations of the earth are out of course."},{"verse":6,"text":"I have said, Ye are gods; and all of you are children of the most High."},{"verse":7,"text":"But ye shall die like men, and fall like one of the princes."},{"verse":8,"text":"Arise, O God, judge the earth: for thou shalt inherit all nations. "}]},{"chapter":83,"verses":[{"verse":1,"text":"Keep not thou silence, O God: hold not thy peace, and be not still, O God."},{"verse":2,"text":"For, lo, thine enemies make a tumult: and they that hate thee have lifted up the head."},{"verse":3,"text":"They have taken crafty counsel against thy people, and consulted against thy hidden ones."},{"verse":4,"text":"They have said, Come, and let us cut them off from being a nation; that the name of Israel may be no more in remembrance."},{"verse":5,"text":"For they have consulted together with one consent: they are confederate against thee:"},{"verse":6,"text":"The tabernacles of Edom, and the Ishmaelites; of Moab, and the Hagarenes;"},{"verse":7,"text":"Gebal, and Ammon, and Amalek; the Philistines with the inhabitants of Tyre;"},{"verse":8,"text":"Assur also is joined with them: they have holpen the children of Lot. Selah."},{"verse":9,"text":"Do unto them as unto the Midianites; as to Sisera, as to Jabin, at the brook of Kison:"},{"verse":10,"text":"Which perished at En–dor: they became as dung for the earth."},{"verse":11,"text":"Make their nobles like Oreb, and like Zeeb: yea, all their princes as Zebah, and as Zalmunna:"},{"verse":12,"text":"Who said, Let us take to ourselves the houses of God in possession."},{"verse":13,"text":"O my God, make them like a wheel; as the stubble before the wind."},{"verse":14,"text":"As the fire burneth a wood, and as the flame setteth the mountains on fire;"},{"verse":15,"text":"So persecute them with thy tempest, and make them afraid with thy storm."},{"verse":16,"text":"Fill their faces with shame; that they may seek thy name, O Lord."},{"verse":17,"text":"Let them be confounded and troubled for ever; yea, let them be put to shame, and perish:"},{"verse":18,"text":"That men may know that thou, whose name alone is Jehovah, art the most high over all the earth. "}]},{"chapter":84,"verses":[{"verse":1,"text":"How amiable are thy tabernacles, O Lord of hosts!"},{"verse":2,"text":"My soul longeth, yea, even fainteth for the courts of the Lord: my heart and my flesh crieth out for the living God."},{"verse":3,"text":"Yea, the sparrow hath found an house, and the swallow a nest for herself, where she may lay her young, even thine altars, O Lord of hosts, my King, and my God."},{"verse":4,"text":"Blessed are they that dwell in thy house: they will be still praising thee. Selah."},{"verse":5,"text":"Blessed is the man whose strength is in thee; in whose heart are the ways of them."},{"verse":6,"text":"Who passing through the valley of Baca make it a well; the rain also filleth the pools."},{"verse":7,"text":"They go from strength to strength, every one of them in Zion appeareth before God."},{"verse":8,"text":"O Lord God of hosts, hear my prayer: give ear, O God of Jacob. Selah."},{"verse":9,"text":"Behold, O God our shield, and look upon the face of thine anointed."},{"verse":10,"text":"For a day in thy courts is better than a thousand. I had rather be a doorkeeper in the house of my God, than to dwell in the tents of wickedness."},{"verse":11,"text":"For the Lord God is a sun and shield: the Lord will give grace and glory: no good thing will he withhold from them that walk uprightly."},{"verse":12,"text":"O Lord of hosts, blessed is the man that trusteth in thee. "}]},{"chapter":85,"verses":[{"verse":1,"text":"Lord, thou hast been favourable unto thy land: thou hast brought back the captivity of Jacob."},{"verse":2,"text":"Thou hast forgiven the iniquity of thy people, thou hast covered all their sin. Selah."},{"verse":3,"text":"Thou hast taken away all thy wrath: thou hast turned thyself from the fierceness of thine anger."},{"verse":4,"text":"Turn us, O God of our salvation, and cause thine anger toward us to cease."},{"verse":5,"text":"Wilt thou be angry with us for ever? wilt thou draw out thine anger to all generations?"},{"verse":6,"text":"Wilt thou not revive us again: that thy people may rejoice in thee?"},{"verse":7,"text":"Shew us thy mercy, O Lord, and grant us thy salvation."},{"verse":8,"text":"I will hear what God the Lord will speak: for he will speak peace unto his people, and to his saints: but let them not turn again to folly."},{"verse":9,"text":"Surely his salvation is nigh them that fear him; that glory may dwell in our land."},{"verse":10,"text":"Mercy and truth are met together; righteousness and peace have kissed each other."},{"verse":11,"text":"Truth shall spring out of the earth; and righteousness shall look down from heaven."},{"verse":12,"text":"Yea, the Lord shall give that which is good; and our land shall yield her increase."},{"verse":13,"text":"Righteousness shall go before him; and shall set us in the way of his steps. "}]},{"chapter":86,"verses":[{"verse":1,"text":"Bow down thine ear, O Lord, hear me: for I am poor and needy."},{"verse":2,"text":"Preserve my soul; for I am holy: O thou my God, save thy servant that trusteth in thee."},{"verse":3,"text":"Be merciful unto me, O Lord: for I cry unto thee daily."},{"verse":4,"text":"Rejoice the soul of thy servant: for unto thee, O Lord, do I lift up my soul."},{"verse":5,"text":"For thou, Lord, art good, and ready to forgive; and plenteous in mercy unto all them that call upon thee."},{"verse":6,"text":"Give ear, O Lord, unto my prayer; and attend to the voice of my supplications."},{"verse":7,"text":"In the day of my trouble I will call upon thee: for thou wilt answer me."},{"verse":8,"text":"Among the gods there is none like unto thee, O Lord; neither are there any works like unto thy works."},{"verse":9,"text":"All nations whom thou hast made shall come and worship before thee, O Lord; and shall glorify thy name."},{"verse":10,"text":"For thou art great, and doest wondrous things: thou art God alone."},{"verse":11,"text":"Teach me thy way, O Lord; I will walk in thy truth: unite my heart to fear thy name."},{"verse":12,"text":"I will praise thee, O Lord my God, with all my heart: and I will glorify thy name for evermore."},{"verse":13,"text":"For great is thy mercy toward me: and thou hast delivered my soul from the lowest hell."},{"verse":14,"text":"O God, the proud are risen against me, and the assemblies of violent men have sought after my soul; and have not set thee before them."},{"verse":15,"text":"But thou, O Lord, art a God full of compassion, and gracious, longsuffering, and plenteous in mercy and truth."},{"verse":16,"text":"O turn unto me, and have mercy upon me; give thy strength unto thy servant, and save the son of thine handmaid."},{"verse":17,"text":"Shew me a token for good; that they which hate me may see it, and be ashamed: because thou, Lord, hast holpen me, and comforted me. "}]},{"chapter":87,"verses":[{"verse":1,"text":"His foundation is in the holy mountains."},{"verse":2,"text":"The Lord loveth the gates of Zion more than all the dwellings of Jacob."},{"verse":3,"text":"Glorious things are spoken of thee, O city of God. Selah."},{"verse":4,"text":"I will make mention of Rahab and Babylon to them that know me: behold Philistia, and Tyre, with Ethiopia; this man was born there."},{"verse":5,"text":"And of Zion it shall be said, This and that man was born in her: and the highest himself shall establish her."},{"verse":6,"text":"The Lord shall count, when he writeth up the people, that this man was born there. Selah."},{"verse":7,"text":"As well the singers as the players on instruments shall be there: all my springs are in thee. "}]},{"chapter":88,"verses":[{"verse":1,"text":"O Lord God of my salvation, I have cried day and night before thee:"},{"verse":2,"text":"Let my prayer come before thee: incline thine ear unto my cry;"},{"verse":3,"text":"For my soul is full of troubles: and my life draweth nigh unto the grave."},{"verse":4,"text":"I am counted with them that go down into the pit: I am as a man that hath no strength:"},{"verse":5,"text":"Free among the dead, like the slain that lie in the grave, whom thou rememberest no more: and they are cut off from thy hand."},{"verse":6,"text":"Thou hast laid me in the lowest pit, in darkness, in the deeps."},{"verse":7,"text":"Thy wrath lieth hard upon me, and thou hast afflicted me with all thy waves. Selah."},{"verse":8,"text":"Thou hast put away mine acquaintance far from me; thou hast made me an abomination unto them: I am shut up, and I cannot come forth."},{"verse":9,"text":"Mine eye mourneth by reason of affliction: Lord, I have called daily upon thee, I have stretched out my hands unto thee."},{"verse":10,"text":"Wilt thou shew wonders to the dead? shall the dead arise and praise thee? Selah."},{"verse":11,"text":"Shall thy lovingkindness be declared in the grave? or thy faithfulness in destruction?"},{"verse":12,"text":"Shall thy wonders be known in the dark? and thy righteousness in the land of forgetfulness?"},{"verse":13,"text":"But unto thee have I cried, O Lord; and in the morning shall my prayer prevent thee."},{"verse":14,"text":"Lord, why castest thou off my soul? why hidest thou thy face from me?"},{"verse":15,"text":"I am afflicted and ready to die from my youth up: while I suffer thy terrors I am distracted."},{"verse":16,"text":"Thy fierce wrath goeth over me; thy terrors have cut me off."},{"verse":17,"text":"They came round about me daily like water; they compassed me about together."},{"verse":18,"text":"Lover and friend hast thou put far from me, and mine acquaintance into darkness. "}]},{"chapter":89,"verses":[{"verse":1,"text":"I will sing of the mercies of the Lord for ever: with my mouth will I make known thy faithfulness to all generations."},{"verse":2,"text":"For I have said, Mercy shall be built up for ever: thy faithfulness shalt thou establish in the very heavens."},{"verse":3,"text":"I have made a covenant with my chosen, I have sworn unto David my servant,"},{"verse":4,"text":"Thy seed will I establish for ever, and build up thy throne to all generations. Selah."},{"verse":5,"text":"And the heavens shall praise thy wonders, O Lord: thy faithfulness also in the congregation of the saints."},{"verse":6,"text":"For who in the heaven can be compared unto the Lord? who among the sons of the mighty can be likened unto the Lord?"},{"verse":7,"text":"God is greatly to be feared in the assembly of the saints, and to be had in reverence of all them that are about him."},{"verse":8,"text":"O Lord God of hosts, who is a strong Lord like unto thee? or to thy faithfulness round about thee?"},{"verse":9,"text":"Thou rulest the raging of the sea: when the waves thereof arise, thou stillest them."},{"verse":10,"text":"Thou hast broken Rahab in pieces, as one that is slain; thou hast scattered thine enemies with thy strong arm."},{"verse":11,"text":"The heavens are thine, the earth also is thine: as for the world and the fulness thereof, thou hast founded them."},{"verse":12,"text":"The north and the south thou hast created them: Tabor and Hermon shall rejoice in thy name."},{"verse":13,"text":"Thou hast a mighty arm: strong is thy hand, and high is thy right hand."},{"verse":14,"text":"Justice and judgment are the habitation of thy throne: mercy and truth shall go before thy face."},{"verse":15,"text":"Blessed is the people that know the joyful sound: they shall walk, O Lord, in the light of thy countenance."},{"verse":16,"text":"In thy name shall they rejoice all the day: and in thy righteousness shall they be exalted."},{"verse":17,"text":"For thou art the glory of their strength: and in thy favour our horn shall be exalted."},{"verse":18,"text":"For the Lord is our defence; and the Holy One of Israel is our king."},{"verse":19,"text":"Then thou spakest in vision to thy holy one, and saidst, I have laid help upon one that is mighty; I have exalted one chosen out of the people."},{"verse":20,"text":"I have found David my servant; with my holy oil have I anointed him:"},{"verse":21,"text":"With whom my hand shall be established: mine arm also shall strengthen him."},{"verse":22,"text":"The enemy shall not exact upon him; nor the son of wickedness afflict him."},{"verse":23,"text":"And I will beat down his foes before his face, and plague them that hate him."},{"verse":24,"text":"But my faithfulness and my mercy shall be with him: and in my name shall his horn be exalted."},{"verse":25,"text":"I will set his hand also in the sea, and his right hand in the rivers."},{"verse":26,"text":"He shall cry unto me, Thou art my father, my God, and the rock of my salvation."},{"verse":27,"text":"Also I will make him my firstborn, higher than the kings of the earth."},{"verse":28,"text":"My mercy will I keep for him for evermore, and my covenant shall stand fast with him."},{"verse":29,"text":"His seed also will I make to endure for ever, and his throne as the days of heaven."},{"verse":30,"text":"If his children forsake my law, and walk not in my judgments;"},{"verse":31,"text":"If they break my statutes, and keep not my commandments;"},{"verse":32,"text":"Then will I visit their transgression with the rod, and their iniquity with stripes."},{"verse":33,"text":"Nevertheless my lovingkindness will I not utterly take from him, nor suffer my faithfulness to fail."},{"verse":34,"text":"My covenant will I not break, nor alter the thing that is gone out of my lips."},{"verse":35,"text":"Once have I sworn by my holiness that I will not lie unto David."},{"verse":36,"text":"His seed shall endure for ever, and his throne as the sun before me."},{"verse":37,"text":"It shall be established for ever as the moon, and as a faithful witness in heaven. Selah."},{"verse":38,"text":"But thou hast cast off and abhorred, thou hast been wroth with thine anointed."},{"verse":39,"text":"Thou hast made void the covenant of thy servant: thou hast profaned his crown by casting it to the ground."},{"verse":40,"text":"Thou hast broken down all his hedges; thou hast brought his strong holds to ruin."},{"verse":41,"text":"All that pass by the way spoil him: he is a reproach to his neighbours."},{"verse":42,"text":"Thou hast set up the right hand of his adversaries; thou hast made all his enemies to rejoice."},{"verse":43,"text":"Thou hast also turned the edge of his sword, and hast not made him to stand in the battle."},{"verse":44,"text":"Thou hast made his glory to cease, and cast his throne down to the ground."},{"verse":45,"text":"The days of his youth hast thou shortened: thou hast covered him with shame. Selah."},{"verse":46,"text":"How long, Lord? wilt thou hide thyself for ever? shall thy wrath burn like fire?"},{"verse":47,"text":"Remember how short my time is: wherefore hast thou made all men in vain?"},{"verse":48,"text":"What man is he that liveth, and shall not see death? shall he deliver his soul from the hand of the grave? Selah."},{"verse":49,"text":"Lord, where are thy former lovingkindnesses, which thou swarest unto David in thy truth?"},{"verse":50,"text":"Remember, Lord, the reproach of thy servants; how I do bear in my bosom the reproach of all the mighty people;"},{"verse":51,"text":"Wherewith thine enemies have reproached, O Lord; wherewith they have reproached the footsteps of thine anointed."},{"verse":52,"text":"Blessed be the Lord for evermore. Amen, and Amen. "}]},{"chapter":90,"verses":[{"verse":1,"text":"Lord, thou hast been our dwelling place in all generations."},{"verse":2,"text":"Before the mountains were brought forth, or ever thou hadst formed the earth and the world, even from everlasting to everlasting, thou art God."},{"verse":3,"text":"Thou turnest man to destruction; and sayest, Return, ye children of men."},{"verse":4,"text":"For a thousand years in thy sight are but as yesterday when it is past, and as a watch in the night."},{"verse":5,"text":"Thou carriest them away as with a flood; they are as a sleep: in the morning they are like grass which groweth up."},{"verse":6,"text":"In the morning it flourisheth, and groweth up; in the evening it is cut down, and withereth."},{"verse":7,"text":"For we are consumed by thine anger, and by thy wrath are we troubled."},{"verse":8,"text":"Thou hast set our iniquities before thee, our secret sins in the light of thy countenance."},{"verse":9,"text":"For all our days are passed away in thy wrath: we spend our years as a tale that is told."},{"verse":10,"text":"The days of our years are threescore years and ten; and if by reason of strength they be fourscore years, yet is their strength labour and sorrow; for it is soon cut off, and we fly away."},{"verse":11,"text":"Who knoweth the power of thine anger? even according to thy fear, so is thy wrath."},{"verse":12,"text":"So teach us to number our days, that we may apply our hearts unto wisdom."},{"verse":13,"text":"Return, O Lord, how long? and let it repent thee concerning thy servants."},{"verse":14,"text":"O satisfy us early with thy mercy; that we may rejoice and be glad all our days."},{"verse":15,"text":"Make us glad according to the days wherein thou hast afflicted us, and the years wherein we have seen evil."},{"verse":16,"text":"Let thy work appear unto thy servants, and thy glory unto their children."},{"verse":17,"text":"And let the beauty of the Lord our God be upon us: and establish thou the work of our hands upon us; yea, the work of our hands establish thou it. "}]},{"chapter":91,"verses":[{"verse":1,"text":"He that dwelleth in the secret place of the most High shall abide under the shadow of the Almighty."},{"verse":2,"text":"I will say of the Lord, He is my refuge and my fortress: my God; in him will I trust."},{"verse":3,"text":"Surely he shall deliver thee from the snare of the fowler, and from the noisome pestilence."},{"verse":4,"text":"He shall cover thee with his feathers, and under his wings shalt thou trust: his truth shall be thy shield and buckler."},{"verse":5,"text":"Thou shalt not be afraid for the terror by night; nor for the arrow that flieth by day;"},{"verse":6,"text":"Nor for the pestilence that walketh in darkness; nor for the destruction that wasteth at noonday."},{"verse":7,"text":"A thousand shall fall at thy side, and ten thousand at thy right hand; but it shall not come nigh thee."},{"verse":8,"text":"Only with thine eyes shalt thou behold and see the reward of the wicked."},{"verse":9,"text":"Because thou hast made the Lord, which is my refuge, even the most High, thy habitation;"},{"verse":10,"text":"There shall no evil befall thee, neither shall any plague come nigh thy dwelling."},{"verse":11,"text":"For he shall give his angels charge over thee, to keep thee in all thy ways."},{"verse":12,"text":"They shall bear thee up in their hands, lest thou dash thy foot against a stone."},{"verse":13,"text":"Thou shalt tread upon the lion and adder: the young lion and the dragon shalt thou trample under feet."},{"verse":14,"text":"Because he hath set his love upon me, therefore will I deliver him: I will set him on high, because he hath known my name."},{"verse":15,"text":"He shall call upon me, and I will answer him: I will be with him in trouble; I will deliver him, and honour him."},{"verse":16,"text":"With long life will I satisfy him, and shew him my salvation. "}]},{"chapter":92,"verses":[{"verse":1,"text":"It is a good thing to give thanks unto the Lord, and to sing praises unto thy name, O most High:"},{"verse":2,"text":"To shew forth thy lovingkindness in the morning, and thy faithfulness every night,"},{"verse":3,"text":"Upon an instrument of ten strings, and upon the psaltery; upon the harp with a solemn sound."},{"verse":4,"text":"For thou, Lord, hast made me glad through thy work: I will triumph in the works of thy hands."},{"verse":5,"text":"O Lord, how great are thy works! and thy thoughts are very deep."},{"verse":6,"text":"A brutish man knoweth not; neither doth a fool understand this."},{"verse":7,"text":"When the wicked spring as the grass, and when all the workers of iniquity do flourish; it is that they shall be destroyed for ever:"},{"verse":8,"text":"But thou, Lord, art most high for evermore."},{"verse":9,"text":"For, lo, thine enemies, O Lord, for, lo, thine enemies shall perish; all the workers of iniquity shall be scattered."},{"verse":10,"text":"But my horn shalt thou exalt like the horn of an unicorn: I shall be anointed with fresh oil."},{"verse":11,"text":"Mine eye also shall see my desire on mine enemies, and mine ears shall hear my desire of the wicked that rise up against me."},{"verse":12,"text":"The righteous shall flourish like the palm tree: he shall grow like a cedar in Lebanon."},{"verse":13,"text":"Those that be planted in the house of the Lord shall flourish in the courts of our God."},{"verse":14,"text":"They shall still bring forth fruit in old age; they shall be fat and flourishing;"},{"verse":15,"text":"To shew that the Lord is upright: he is my rock, and there is no unrighteousness in him. "}]},{"chapter":93,"verses":[{"verse":1,"text":"The Lord reigneth, he is clothed with majesty; the Lord is clothed with strength, wherewith he hath girded himself: the world also is stablished, that it cannot be moved."},{"verse":2,"text":"Thy throne is established of old: thou art from everlasting."},{"verse":3,"text":"The floods have lifted up, O Lord, the floods have lifted up their voice; the floods lift up their waves."},{"verse":4,"text":"The Lord on high is mightier than the noise of many waters, yea, than the mighty waves of the sea."},{"verse":5,"text":"Thy testimonies are very sure: holiness becometh thine house, O Lord, for ever. "}]},{"chapter":94,"verses":[{"verse":1,"text":"O Lord God, to whom vengeance belongeth; O God, to whom vengeance belongeth, shew thyself."},{"verse":2,"text":"Lift up thyself, thou judge of the earth: render a reward to the proud."},{"verse":3,"text":"Lord, how long shall the wicked, how long shall the wicked triumph?"},{"verse":4,"text":"How long shall they utter and speak hard things? and all the workers of iniquity boast themselves?"},{"verse":5,"text":"They break in pieces thy people, O Lord, and afflict thine heritage."},{"verse":6,"text":"They slay the widow and the stranger, and murder the fatherless."},{"verse":7,"text":"Yet they say, The Lord shall not see, neither shall the God of Jacob regard it."},{"verse":8,"text":"Understand, ye brutish among the people: and ye fools, when will ye be wise?"},{"verse":9,"text":"He that planted the ear, shall he not hear? he that formed the eye, shall he not see?"},{"verse":10,"text":"He that chastiseth the heathen, shall not he correct? he that teacheth man knowledge, shall not he know?"},{"verse":11,"text":"The Lord knoweth the thoughts of man, that they are vanity."},{"verse":12,"text":"Blessed is the man whom thou chastenest, O Lord, and teachest him out of thy law;"},{"verse":13,"text":"That thou mayest give him rest from the days of adversity, until the pit be digged for the wicked."},{"verse":14,"text":"For the Lord will not cast off his people, neither will he forsake his inheritance."},{"verse":15,"text":"But judgment shall return unto righteousness: and all the upright in heart shall follow it."},{"verse":16,"text":"Who will rise up for me against the evildoers? or who will stand up for me against the workers of iniquity?"},{"verse":17,"text":"Unless the Lord had been my help, my soul had almost dwelt in silence."},{"verse":18,"text":"When I said, My foot slippeth; thy mercy, O Lord, held me up."},{"verse":19,"text":"In the multitude of my thoughts within me thy comforts delight my soul."},{"verse":20,"text":"Shall the throne of iniquity have fellowship with thee, which frameth mischief by a law?"},{"verse":21,"text":"They gather themselves together against the soul of the righteous, and condemn the innocent blood."},{"verse":22,"text":"But the Lord is my defence; and my God is the rock of my refuge."},{"verse":23,"text":"And he shall bring upon them their own iniquity, and shall cut them off in their own wickedness; yea, the Lord our God shall cut them off. "}]},{"chapter":95,"verses":[{"verse":1,"text":"O come, let us sing unto the Lord: let us make a joyful noise to the rock of our salvation."},{"verse":2,"text":"Let us come before his presence with thanksgiving, and make a joyful noise unto him with psalms."},{"verse":3,"text":"For the Lord is a great God, and a great King above all gods."},{"verse":4,"text":"In his hand are the deep places of the earth: the strength of the hills is his also."},{"verse":5,"text":"The sea is his, and he made it: and his hands formed the dry land."},{"verse":6,"text":"O come, let us worship and bow down: let us kneel before the Lord our maker."},{"verse":7,"text":"For he is our God; and we are the people of his pasture, and the sheep of his hand. To day if ye will hear his voice,"},{"verse":8,"text":"Harden not your heart, as in the provocation, and as in the day of temptation in the wilderness:"},{"verse":9,"text":"When your fathers tempted me, proved me, and saw my work."},{"verse":10,"text":"Forty years long was I grieved with this generation, and said, It is a people that do err in their heart, and they have not known my ways:"},{"verse":11,"text":"Unto whom I sware in my wrath that they should not enter into my rest. "}]},{"chapter":96,"verses":[{"verse":1,"text":"O sing unto the Lord a new song: sing unto the Lord, all the earth."},{"verse":2,"text":"Sing unto the Lord, bless his name; shew forth his salvation from day to day."},{"verse":3,"text":"Declare his glory among the heathen, his wonders among all people."},{"verse":4,"text":"For the Lord is great, and greatly to be praised: he is to be feared above all gods."},{"verse":5,"text":"For all the gods of the nations are idols: but the Lord made the heavens."},{"verse":6,"text":"Honour and majesty are before him: strength and beauty are in his sanctuary."},{"verse":7,"text":"Give unto the Lord, O ye kindreds of the people, give unto the Lord glory and strength."},{"verse":8,"text":"Give unto the Lord the glory due unto his name: bring an offering, and come into his courts."},{"verse":9,"text":"O worship the Lord in the beauty of holiness: fear before him, all the earth."},{"verse":10,"text":"Say among the heathen that the Lord reigneth: the world also shall be established that it shall not be moved: he shall judge the people righteously."},{"verse":11,"text":"Let the heavens rejoice, and let the earth be glad; let the sea roar, and the fulness thereof."},{"verse":12,"text":"Let the field be joyful, and all that is therein: then shall all the trees of the wood rejoice"},{"verse":13,"text":"Before the Lord: for he cometh, for he cometh to judge the earth: he shall judge the world with righteousness, and the people with his truth. "}]},{"chapter":97,"verses":[{"verse":1,"text":"The Lord reigneth; let the earth rejoice; let the multitude of isles be glad thereof."},{"verse":2,"text":"Clouds and darkness are round about him: righteousness and judgment are the habitation of his throne."},{"verse":3,"text":"A fire goeth before him, and burneth up his enemies round about."},{"verse":4,"text":"His lightnings enlightened the world: the earth saw, and trembled."},{"verse":5,"text":"The hills melted like wax at the presence of the Lord, at the presence of the Lord of the whole earth."},{"verse":6,"text":"The heavens declare his righteousness, and all the people see his glory."},{"verse":7,"text":"Confounded be all they that serve graven images, that boast themselves of idols: worship him, all ye gods."},{"verse":8,"text":"Zion heard, and was glad; and the daughters of Judah rejoiced because of thy judgments, O Lord."},{"verse":9,"text":"For thou, Lord, art high above all the earth: thou art exalted far above all gods."},{"verse":10,"text":"Ye that love the Lord, hate evil: he preserveth the souls of his saints; he delivereth them out of the hand of the wicked."},{"verse":11,"text":"Light is sown for the righteous, and gladness for the upright in heart."},{"verse":12,"text":"Rejoice in the Lord, ye righteous; and give thanks at the remembrance of his holiness. "}]},{"chapter":98,"verses":[{"verse":1,"text":"O sing unto the Lord a new song; for he hath done marvellous things: his right hand, and his holy arm, hath gotten him the victory."},{"verse":2,"text":"The Lord hath made known his salvation: his righteousness hath he openly shewed in the sight of the heathen."},{"verse":3,"text":"He hath remembered his mercy and his truth toward the house of Israel: all the ends of the earth have seen the salvation of our God."},{"verse":4,"text":"Make a joyful noise unto the Lord, all the earth: make a loud noise, and rejoice, and sing praise."},{"verse":5,"text":"Sing unto the Lord with the harp; with the harp, and the voice of a psalm."},{"verse":6,"text":"With trumpets and sound of cornet make a joyful noise before the Lord, the King."},{"verse":7,"text":"Let the sea roar, and the fulness thereof; the world, and they that dwell therein."},{"verse":8,"text":"Let the floods clap their hands: let the hills be joyful together"},{"verse":9,"text":"Before the Lord; for he cometh to judge the earth: with righteousness shall he judge the world, and the people with equity. "}]},{"chapter":99,"verses":[{"verse":1,"text":"The Lord reigneth; let the people tremble: he sitteth between the cherubims; let the earth be moved."},{"verse":2,"text":"The Lord is great in Zion; and he is high above all the people."},{"verse":3,"text":"Let them praise thy great and terrible name; for it is holy."},{"verse":4,"text":"The king’s strength also loveth judgment; thou dost establish equity, thou executest judgment and righteousness in Jacob."},{"verse":5,"text":"Exalt ye the Lord our God, and worship at his footstool; for he is holy."},{"verse":6,"text":"Moses and Aaron among his priests, and Samuel among them that call upon his name; they called upon the Lord, and he answered them."},{"verse":7,"text":"He spake unto them in the cloudy pillar: they kept his testimonies, and the ordinance that he gave them."},{"verse":8,"text":"Thou answeredst them, O Lord our God: thou wast a God that forgavest them, though thou tookest vengeance of their inventions."},{"verse":9,"text":"Exalt the Lord our God, and worship at his holy hill; for the Lord our God is holy. "}]},{"chapter":100,"verses":[{"verse":1,"text":"Make a joyful noise unto the Lord, all ye lands."},{"verse":2,"text":"Serve the Lord with gladness: come before his presence with singing."},{"verse":3,"text":"Know ye that the Lord he is God: it is he that hath made us, and not we ourselves; we are his people, and the sheep of his pasture."},{"verse":4,"text":"Enter into his gates with thanksgiving, and into his courts with praise: be thankful unto him, and bless his name."},{"verse":5,"text":"For the Lord is good; his mercy is everlasting; and his truth endureth to all generations. "}]},{"chapter":101,"verses":[{"verse":1,"text":"I will sing of mercy and judgment: unto thee, O Lord, will I sing."},{"verse":2,"text":"I will behave myself wisely in a perfect way. O when wilt thou come unto me? I will walk within my house with a perfect heart."},{"verse":3,"text":"I will set no wicked thing before mine eyes: I hate the work of them that turn aside; it shall not cleave to me."},{"verse":4,"text":"A froward heart shall depart from me: I will not know a wicked person."},{"verse":5,"text":"Whoso privily slandereth his neighbour, him will I cut off: him that hath an high look and a proud heart will not I suffer."},{"verse":6,"text":"Mine eyes shall be upon the faithful of the land, that they may dwell with me: he that walketh in a perfect way, he shall serve me."},{"verse":7,"text":"He that worketh deceit shall not dwell within my house: he that telleth lies shall not tarry in my sight."},{"verse":8,"text":"I will early destroy all the wicked of the land; that I may cut off all wicked doers from the city of the Lord. "}]},{"chapter":102,"verses":[{"verse":1,"text":"Hear my prayer, O Lord, and let my cry come unto thee."},{"verse":2,"text":"Hide not thy face from me in the day when I am in trouble; incline thine ear unto me: in the day when I call answer me speedily."},{"verse":3,"text":"For my days are consumed like smoke, and my bones are burned as an hearth."},{"verse":4,"text":"My heart is smitten, and withered like grass; so that I forget to eat my bread."},{"verse":5,"text":"By reason of the voice of my groaning my bones cleave to my skin."},{"verse":6,"text":"I am like a pelican of the wilderness: I am like an owl of the desert."},{"verse":7,"text":"I watch, and am as a sparrow alone upon the house top."},{"verse":8,"text":"Mine enemies reproach me all the day; and they that are mad against me are sworn against me."},{"verse":9,"text":"For I have eaten ashes like bread, and mingled my drink with weeping,"},{"verse":10,"text":"Because of thine indignation and thy wrath: for thou hast lifted me up, and cast me down."},{"verse":11,"text":"My days are like a shadow that declineth; and I am withered like grass."},{"verse":12,"text":"But thou, O Lord, shalt endure for ever; and thy remembrance unto all generations."},{"verse":13,"text":"Thou shalt arise, and have mercy upon Zion: for the time to favour her, yea, the set time, is come."},{"verse":14,"text":"For thy servants take pleasure in her stones, and favour the dust thereof."},{"verse":15,"text":"So the heathen shall fear the name of the Lord, and all the kings of the earth thy glory."},{"verse":16,"text":"When the Lord shall build up Zion, he shall appear in his glory."},{"verse":17,"text":"He will regard the prayer of the destitute, and not despise their prayer."},{"verse":18,"text":"This shall be written for the generation to come: and the people which shall be created shall praise the Lord."},{"verse":19,"text":"For he hath looked down from the height of his sanctuary; from heaven did the Lord behold the earth;"},{"verse":20,"text":"To hear the groaning of the prisoner; to loose those that are appointed to death;"},{"verse":21,"text":"To declare the name of the Lord in Zion, and his praise in Jerusalem;"},{"verse":22,"text":"When the people are gathered together, and the kingdoms, to serve the Lord."},{"verse":23,"text":"He weakened my strength in the way; he shortened my days."},{"verse":24,"text":"I said, O my God, take me not away in the midst of my days: thy years are throughout all generations."},{"verse":25,"text":"Of old hast thou laid the foundation of the earth: and the heavens are the work of thy hands."},{"verse":26,"text":"They shall perish, but thou shalt endure: yea, all of them shall wax old like a garment; as a vesture shalt thou change them, and they shall be changed:"},{"verse":27,"text":"But thou art the same, and thy years shall have no end."},{"verse":28,"text":"The children of thy servants shall continue, and their seed shall be established before thee. "}]},{"chapter":103,"verses":[{"verse":1,"text":"Bless the Lord, O my soul: and all that is within me, bless his holy name."},{"verse":2,"text":"Bless the Lord, O my soul, and forget not all his benefits:"},{"verse":3,"text":"Who forgiveth all thine iniquities; who healeth all thy diseases;"},{"verse":4,"text":"Who redeemeth thy life from destruction; who crowneth thee with lovingkindness and tender mercies;"},{"verse":5,"text":"Who satisfieth thy mouth with good things; so that thy youth is renewed like the eagle’s."},{"verse":6,"text":"The Lord executeth righteousness and judgment for all that are oppressed."},{"verse":7,"text":"He made known his ways unto Moses, his acts unto the children of Israel."},{"verse":8,"text":"The Lord is merciful and gracious, slow to anger, and plenteous in mercy."},{"verse":9,"text":"He will not always chide: neither will he keep his anger for ever."},{"verse":10,"text":"He hath not dealt with us after our sins; nor rewarded us according to our iniquities."},{"verse":11,"text":"For as the heaven is high above the earth, so great is his mercy toward them that fear him."},{"verse":12,"text":"As far as the east is from the west, so far hath he removed our transgressions from us."},{"verse":13,"text":"Like as a father pitieth his children, so the Lord pitieth them that fear him."},{"verse":14,"text":"For he knoweth our frame; he remembereth that we are dust."},{"verse":15,"text":"As for man, his days are as grass: as a flower of the field, so he flourisheth."},{"verse":16,"text":"For the wind passeth over it, and it is gone; and the place thereof shall know it no more."},{"verse":17,"text":"But the mercy of the Lord is from everlasting to everlasting upon them that fear him, and his righteousness unto children’s children;"},{"verse":18,"text":"To such as keep his covenant, and to those that remember his commandments to do them."},{"verse":19,"text":"The Lord hath prepared his throne in the heavens; and his kingdom ruleth over all."},{"verse":20,"text":"Bless the Lord, ye his angels, that excel in strength, that do his commandments, hearkening unto the voice of his word."},{"verse":21,"text":"Bless ye the Lord, all ye his hosts; ye ministers of his, that do his pleasure."},{"verse":22,"text":"Bless the Lord, all his works in all places of his dominion: bless the Lord, O my soul. "}]},{"chapter":104,"verses":[{"verse":1,"text":"Bless the Lord, O my soul. O Lord my God, thou art very great; thou art clothed with honour and majesty."},{"verse":2,"text":"Who coverest thyself with light as with a garment: who stretchest out the heavens like a curtain:"},{"verse":3,"text":"Who layeth the beams of his chambers in the waters: who maketh the clouds his chariot: who walketh upon the wings of the wind:"},{"verse":4,"text":"Who maketh his angels spirits; his ministers a flaming fire:"},{"verse":5,"text":"Who laid the foundations of the earth, that it should not be removed for ever."},{"verse":6,"text":"Thou coveredst it with the deep as with a garment: the waters stood above the mountains."},{"verse":7,"text":"At thy rebuke they fled; at the voice of thy thunder they hasted away."},{"verse":8,"text":"They go up by the mountains; they go down by the valleys unto the place which thou hast founded for them."},{"verse":9,"text":"Thou hast set a bound that they may not pass over; that they turn not again to cover the earth."},{"verse":10,"text":"He sendeth the springs into the valleys, which run among the hills."},{"verse":11,"text":"They give drink to every beast of the field: the wild asses quench their thirst."},{"verse":12,"text":"By them shall the fowls of the heaven have their habitation, which sing among the branches."},{"verse":13,"text":"He watereth the hills from his chambers: the earth is satisfied with the fruit of thy works."},{"verse":14,"text":"He causeth the grass to grow for the cattle, and herb for the service of man: that he may bring forth food out of the earth;"},{"verse":15,"text":"And wine that maketh glad the heart of man, and oil to make his face to shine, and bread which strengtheneth man’s heart."},{"verse":16,"text":"The trees of the Lord are full of sap; the cedars of Lebanon, which he hath planted;"},{"verse":17,"text":"Where the birds make their nests: as for the stork, the fir trees are her house."},{"verse":18,"text":"The high hills are a refuge for the wild goats; and the rocks for the conies."},{"verse":19,"text":"He appointed the moon for seasons: the sun knoweth his going down."},{"verse":20,"text":"Thou makest darkness, and it is night: wherein all the beasts of the forest do creep forth."},{"verse":21,"text":"The young lions roar after their prey, and seek their meat from God."},{"verse":22,"text":"The sun ariseth, they gather themselves together, and lay them down in their dens."},{"verse":23,"text":"Man goeth forth unto his work and to his labour until the evening."},{"verse":24,"text":"O Lord, how manifold are thy works! in wisdom hast thou made them all: the earth is full of thy riches."},{"verse":25,"text":"So is this great and wide sea, wherein are things creeping innumerable, both small and great beasts."},{"verse":26,"text":"There go the ships: there is that leviathan, whom thou hast made to play therein."},{"verse":27,"text":"These wait all upon thee; that thou mayest give them their meat in due season."},{"verse":28,"text":"That thou givest them they gather: thou openest thine hand, they are filled with good."},{"verse":29,"text":"Thou hidest thy face, they are troubled: thou takest away their breath, they die, and return to their dust."},{"verse":30,"text":"Thou sendest forth thy spirit, they are created: and thou renewest the face of the earth."},{"verse":31,"text":"The glory of the Lord shall endure for ever: the Lord shall rejoice in his works."},{"verse":32,"text":"He looketh on the earth, and it trembleth: he toucheth the hills, and they smoke."},{"verse":33,"text":"I will sing unto the Lord as long as I live: I will sing praise to my God while I have my being."},{"verse":34,"text":"My meditation of him shall be sweet: I will be glad in the Lord."},{"verse":35,"text":"Let the sinners be consumed out of the earth, and let the wicked be no more. Bless thou the Lord, O my soul. Praise ye the Lord. "}]},{"chapter":105,"verses":[{"verse":1,"text":"O give thanks unto the Lord; call upon his name: make known his deeds among the people."},{"verse":2,"text":"Sing unto him, sing psalms unto him: talk ye of all his wondrous works."},{"verse":3,"text":"Glory ye in his holy name: let the heart of them rejoice that seek the Lord."},{"verse":4,"text":"Seek the Lord, and his strength: seek his face evermore."},{"verse":5,"text":"Remember his marvellous works that he hath done; his wonders, and the judgments of his mouth;"},{"verse":6,"text":"O ye seed of Abraham his servant, ye children of Jacob his chosen."},{"verse":7,"text":"He is the Lord our God: his judgments are in all the earth."},{"verse":8,"text":"He hath remembered his covenant for ever, the word which he commanded to a thousand generations."},{"verse":9,"text":"Which covenant he made with Abraham, and his oath unto Isaac;"},{"verse":10,"text":"And confirmed the same unto Jacob for a law, and to Israel for an everlasting covenant:"},{"verse":11,"text":"Saying, Unto thee will I give the land of Canaan, the lot of your inheritance:"},{"verse":12,"text":"When they were but a few men in number; yea, very few, and strangers in it."},{"verse":13,"text":"When they went from one nation to another, from one kingdom to another people;"},{"verse":14,"text":"He suffered no man to do them wrong: yea, he reproved kings for their sakes;"},{"verse":15,"text":"Saying, Touch not mine anointed, and do my prophets no harm."},{"verse":16,"text":"Moreover he called for a famine upon the land: he brake the whole staff of bread."},{"verse":17,"text":"He sent a man before them, even Joseph, who was sold for a servant:"},{"verse":18,"text":"Whose feet they hurt with fetters: he was laid in iron:"},{"verse":19,"text":"Until the time that his word came: the word of the Lord tried him."},{"verse":20,"text":"The king sent and loosed him; even the ruler of the people, and let him go free."},{"verse":21,"text":"He made him lord of his house, and ruler of all his substance:"},{"verse":22,"text":"To bind his princes at his pleasure; and teach his senators wisdom."},{"verse":23,"text":"Israel also came into Egypt; and Jacob sojourned in the land of Ham."},{"verse":24,"text":"And he increased his people greatly; and made them stronger than their enemies."},{"verse":25,"text":"He turned their heart to hate his people, to deal subtilly with his servants."},{"verse":26,"text":"He sent Moses his servant; and Aaron whom he had chosen."},{"verse":27,"text":"They shewed his signs among them, and wonders in the land of Ham."},{"verse":28,"text":"He sent darkness, and made it dark; and they rebelled not against his word."},{"verse":29,"text":"He turned their waters into blood, and slew their fish."},{"verse":30,"text":"Their land brought forth frogs in abundance, in the chambers of their kings."},{"verse":31,"text":"He spake, and there came divers sorts of flies, and lice in all their coasts."},{"verse":32,"text":"He gave them hail for rain, and flaming fire in their land."},{"verse":33,"text":"He smote their vines also and their fig trees; and brake the trees of their coasts."},{"verse":34,"text":"He spake, and the locusts came, and caterpillers, and that without number,"},{"verse":35,"text":"And did eat up all the herbs in their land, and devoured the fruit of their ground."},{"verse":36,"text":"He smote also all the firstborn in their land, the chief of all their strength."},{"verse":37,"text":"He brought them forth also with silver and gold: and there was not one feeble person among their tribes."},{"verse":38,"text":"Egypt was glad when they departed: for the fear of them fell upon them."},{"verse":39,"text":"He spread a cloud for a covering; and fire to give light in the night."},{"verse":40,"text":"The people asked, and he brought quails, and satisfied them with the bread of heaven."},{"verse":41,"text":"He opened the rock, and the waters gushed out; they ran in the dry places like a river."},{"verse":42,"text":"For he remembered his holy promise, and Abraham his servant."},{"verse":43,"text":"And he brought forth his people with joy, and his chosen with gladness:"},{"verse":44,"text":"And gave them the lands of the heathen: and they inherited the labour of the people;"},{"verse":45,"text":"That they might observe his statutes, and keep his laws. Praise ye the Lord. "}]},{"chapter":106,"verses":[{"verse":1,"text":"Praise ye the Lord. O give thanks unto the Lord; for he is good: for his mercy endureth for ever."},{"verse":2,"text":"Who can utter the mighty acts of the Lord? who can shew forth all his praise?"},{"verse":3,"text":"Blessed are they that keep judgment, and he that doeth righteousness at all times."},{"verse":4,"text":"Remember me, O Lord, with the favour that thou bearest unto thy people: O visit me with thy salvation;"},{"verse":5,"text":"That I may see the good of thy chosen, that I may rejoice in the gladness of thy nation, that I may glory with thine inheritance."},{"verse":6,"text":"We have sinned with our fathers, we have committed iniquity, we have done wickedly."},{"verse":7,"text":"Our fathers understood not thy wonders in Egypt; they remembered not the multitude of thy mercies; but provoked him at the sea, even at the Red sea."},{"verse":8,"text":"Nevertheless he saved them for his name’s sake, that he might make his mighty power to be known."},{"verse":9,"text":"He rebuked the Red sea also, and it was dried up: so he led them through the depths, as through the wilderness."},{"verse":10,"text":"And he saved them from the hand of him that hated them, and redeemed them from the hand of the enemy."},{"verse":11,"text":"And the waters covered their enemies: there was not one of them left."},{"verse":12,"text":"Then believed they his words; they sang his praise."},{"verse":13,"text":"They soon forgat his works; they waited not for his counsel:"},{"verse":14,"text":"But lusted exceedingly in the wilderness, and tempted God in the desert."},{"verse":15,"text":"And he gave them their request; but sent leanness into their soul."},{"verse":16,"text":"They envied Moses also in the camp, and Aaron the saint of the Lord."},{"verse":17,"text":"The earth opened and swallowed up Dathan, and covered the company of Abiram."},{"verse":18,"text":"And a fire was kindled in their company; the flame burned up the wicked."},{"verse":19,"text":"They made a calf in Horeb, and worshipped the molten image."},{"verse":20,"text":"Thus they changed their glory into the similitude of an ox that eateth grass."},{"verse":21,"text":"They forgat God their saviour, which had done great things in Egypt;"},{"verse":22,"text":"Wondrous works in the land of Ham, and terrible things by the Red sea."},{"verse":23,"text":"Therefore he said that he would destroy them, had not Moses his chosen stood before him in the breach, to turn away his wrath, lest he should destroy them."},{"verse":24,"text":"Yea, they despised the pleasant land, they believed not his word:"},{"verse":25,"text":"But murmured in their tents, and hearkened not unto the voice of the Lord."},{"verse":26,"text":"Therefore he lifted up his hand against them, to overthrow them in the wilderness:"},{"verse":27,"text":"To overthrow their seed also among the nations, and to scatter them in the lands."},{"verse":28,"text":"They joined themselves also unto Baal–peor, and ate the sacrifices of the dead."},{"verse":29,"text":"Thus they provoked him to anger with their inventions: and the plague brake in upon them."},{"verse":30,"text":"Then stood up Phinehas, and executed judgment: and so the plague was stayed."},{"verse":31,"text":"And that was counted unto him for righteousness unto all generations for evermore."},{"verse":32,"text":"They angered him also at the waters of strife, so that it went ill with Moses for their sakes:"},{"verse":33,"text":"Because they provoked his spirit, so that he spake unadvisedly with his lips."},{"verse":34,"text":"They did not destroy the nations, concerning whom the Lord commanded them:"},{"verse":35,"text":"But were mingled among the heathen, and learned their works."},{"verse":36,"text":"And they served their idols: which were a snare unto them."},{"verse":37,"text":"Yea, they sacrificed their sons and their daughters unto devils,"},{"verse":38,"text":"And shed innocent blood, even the blood of their sons and of their daughters, whom they sacrificed unto the idols of Canaan: and the land was polluted with blood."},{"verse":39,"text":"Thus were they defiled with their own works, and went a whoring with their own inventions."},{"verse":40,"text":"Therefore was the wrath of the Lord kindled against his people, insomuch that he abhorred his own inheritance."},{"verse":41,"text":"And he gave them into the hand of the heathen; and they that hated them ruled over them."},{"verse":42,"text":"Their enemies also oppressed them, and they were brought into subjection under their hand."},{"verse":43,"text":"Many times did he deliver them; but they provoked him with their counsel, and were brought low for their iniquity."},{"verse":44,"text":"Nevertheless he regarded their affliction, when he heard their cry:"},{"verse":45,"text":"And he remembered for them his covenant, and repented according to the multitude of his mercies."},{"verse":46,"text":"He made them also to be pitied of all those that carried them captives."},{"verse":47,"text":"Save us, O Lord our God, and gather us from among the heathen, to give thanks unto thy holy name, and to triumph in thy praise."},{"verse":48,"text":"Blessed be the Lord God of Israel from everlasting to everlasting: and let all the people say, Amen. Praise ye the Lord. "}]},{"chapter":107,"verses":[{"verse":1,"text":"O give thanks unto the Lord, for he is good: for his mercy endureth for ever."},{"verse":2,"text":"Let the redeemed of the Lord say so, whom he hath redeemed from the hand of the enemy;"},{"verse":3,"text":"And gathered them out of the lands, from the east, and from the west, from the north, and from the south."},{"verse":4,"text":"They wandered in the wilderness in a solitary way; they found no city to dwell in."},{"verse":5,"text":"Hungry and thirsty, their soul fainted in them."},{"verse":6,"text":"Then they cried unto the Lord in their trouble, and he delivered them out of their distresses."},{"verse":7,"text":"And he led them forth by the right way, that they might go to a city of habitation."},{"verse":8,"text":"Oh that men would praise the Lord for his goodness, and for his wonderful works to the children of men!"},{"verse":9,"text":"For he satisfieth the longing soul, and filleth the hungry soul with goodness."},{"verse":10,"text":"Such as sit in darkness and in the shadow of death, being bound in affliction and iron;"},{"verse":11,"text":"Because they rebelled against the words of God, and contemned the counsel of the most High:"},{"verse":12,"text":"Therefore he brought down their heart with labour; they fell down, and there was none to help."},{"verse":13,"text":"Then they cried unto the Lord in their trouble, and he saved them out of their distresses."},{"verse":14,"text":"He brought them out of darkness and the shadow of death, and brake their bands in sunder."},{"verse":15,"text":"Oh that men would praise the Lord for his goodness, and for his wonderful works to the children of men!"},{"verse":16,"text":"For he hath broken the gates of brass, and cut the bars of iron in sunder."},{"verse":17,"text":"Fools because of their transgression, and because of their iniquities, are afflicted."},{"verse":18,"text":"Their soul abhorreth all manner of meat; and they draw near unto the gates of death."},{"verse":19,"text":"Then they cry unto the Lord in their trouble, and he saveth them out of their distresses."},{"verse":20,"text":"He sent his word, and healed them, and delivered them from their destructions."},{"verse":21,"text":"Oh that men would praise the Lord for his goodness, and for his wonderful works to the children of men!"},{"verse":22,"text":"And let them sacrifice the sacrifices of thanksgiving, and declare his works with rejoicing."},{"verse":23,"text":"They that go down to the sea in ships, that do business in great waters;"},{"verse":24,"text":"These see the works of the Lord, and his wonders in the deep."},{"verse":25,"text":"For he commandeth, and raiseth the stormy wind, which lifteth up the waves thereof."},{"verse":26,"text":"They mount up to the heaven, they go down again to the depths: their soul is melted because of trouble."},{"verse":27,"text":"They reel to and fro, and stagger like a drunken man, and are at their wits’ end."},{"verse":28,"text":"Then they cry unto the Lord in their trouble, and he bringeth them out of their distresses."},{"verse":29,"text":"He maketh the storm a calm, so that the waves thereof are still."},{"verse":30,"text":"Then are they glad because they be quiet; so he bringeth them unto their desired haven."},{"verse":31,"text":"Oh that men would praise the Lord for his goodness, and for his wonderful works to the children of men!"},{"verse":32,"text":"Let them exalt him also in the congregation of the people, and praise him in the assembly of the elders."},{"verse":33,"text":"He turneth rivers into a wilderness, and the watersprings into dry ground;"},{"verse":34,"text":"A fruitful land into barrenness, for the wickedness of them that dwell therein."},{"verse":35,"text":"He turneth the wilderness into a standing water, and dry ground into watersprings."},{"verse":36,"text":"And there he maketh the hungry to dwell, that they may prepare a city for habitation;"},{"verse":37,"text":"And sow the fields, and plant vineyards, which may yield fruits of increase."},{"verse":38,"text":"He blesseth them also, so that they are multiplied greatly; and suffereth not their cattle to decrease."},{"verse":39,"text":"Again, they are minished and brought low through oppression, affliction, and sorrow."},{"verse":40,"text":"He poureth contempt upon princes, and causeth them to wander in the wilderness, where there is no way."},{"verse":41,"text":"Yet setteth he the poor on high from affliction, and maketh him families like a flock."},{"verse":42,"text":"The righteous shall see it, and rejoice: and all iniquity shall stop her mouth."},{"verse":43,"text":"Whoso is wise, and will observe these things, even they shall understand the lovingkindness of the Lord. "}]},{"chapter":108,"verses":[{"verse":1,"text":"O God, my heart is fixed; I will sing and give praise, even with my glory."},{"verse":2,"text":"Awake, psaltery and harp: I myself will awake early."},{"verse":3,"text":"I will praise thee, O Lord, among the people: and I will sing praises unto thee among the nations."},{"verse":4,"text":"For thy mercy is great above the heavens: and thy truth reacheth unto the clouds."},{"verse":5,"text":"Be thou exalted, O God, above the heavens: and thy glory above all the earth;"},{"verse":6,"text":"That thy beloved may be delivered: save with thy right hand, and answer me."},{"verse":7,"text":"God hath spoken in his holiness; I will rejoice, I will divide Shechem, and mete out the valley of Succoth."},{"verse":8,"text":"Gilead is mine; Manasseh is mine; Ephraim also is the strength of mine head; Judah is my lawgiver;"},{"verse":9,"text":"Moab is my washpot; over Edom will I cast out my shoe; over Philistia will I triumph."},{"verse":10,"text":"Who will bring me into the strong city? who will lead me into Edom?"},{"verse":11,"text":"Wilt not thou, O God, who hast cast us off? and wilt not thou, O God, go forth with our hosts?"},{"verse":12,"text":"Give us help from trouble: for vain is the help of man."},{"verse":13,"text":"Through God we shall do valiantly: for he it is that shall tread down our enemies. "}]},{"chapter":109,"verses":[{"verse":1,"text":"Hold not thy peace, O God of my praise;"},{"verse":2,"text":"For the mouth of the wicked and the mouth of the deceitful are opened against me: they have spoken against me with a lying tongue."},{"verse":3,"text":"They compassed me about also with words of hatred; and fought against me without a cause."},{"verse":4,"text":"For my love they are my adversaries: but I give myself unto prayer."},{"verse":5,"text":"And they have rewarded me evil for good, and hatred for my love."},{"verse":6,"text":"Set thou a wicked man over him: and let Satan stand at his right hand."},{"verse":7,"text":"When he shall be judged, let him be condemned: and let his prayer become sin."},{"verse":8,"text":"Let his days be few; and let another take his office."},{"verse":9,"text":"Let his children be fatherless, and his wife a widow."},{"verse":10,"text":"Let his children be continually vagabonds, and beg: let them seek their bread also out of their desolate places."},{"verse":11,"text":"Let the extortioner catch all that he hath; and let the strangers spoil his labour."},{"verse":12,"text":"Let there be none to extend mercy unto him: neither let there be any to favour his fatherless children."},{"verse":13,"text":"Let his posterity be cut off; and in the generation following let their name be blotted out."},{"verse":14,"text":"Let the iniquity of his fathers be remembered with the Lord; and let not the sin of his mother be blotted out."},{"verse":15,"text":"Let them be before the Lord continually, that he may cut off the memory of them from the earth."},{"verse":16,"text":"Because that he remembered not to shew mercy, but persecuted the poor and needy man, that he might even slay the broken in heart."},{"verse":17,"text":"As he loved cursing, so let it come unto him: as he delighted not in blessing, so let it be far from him."},{"verse":18,"text":"As he clothed himself with cursing like as with his garment, so let it come into his bowels like water, and like oil into his bones."},{"verse":19,"text":"Let it be unto him as the garment which covereth him, and for a girdle wherewith he is girded continually."},{"verse":20,"text":"Let this be the reward of mine adversaries from the Lord, and of them that speak evil against my soul."},{"verse":21,"text":"But do thou for me, O God the Lord, for thy name’s sake: because thy mercy is good, deliver thou me."},{"verse":22,"text":"For I am poor and needy, and my heart is wounded within me."},{"verse":23,"text":"I am gone like the shadow when it declineth: I am tossed up and down as the locust."},{"verse":24,"text":"My knees are weak through fasting; and my flesh faileth of fatness."},{"verse":25,"text":"I became also a reproach unto them: when they looked upon me they shaked their heads."},{"verse":26,"text":"Help me, O Lord my God: O save me according to thy mercy:"},{"verse":27,"text":"That they may know that this is thy hand; that thou, Lord, hast done it."},{"verse":28,"text":"Let them curse, but bless thou: when they arise, let them be ashamed; but let thy servant rejoice."},{"verse":29,"text":"Let mine adversaries be clothed with shame, and let them cover themselves with their own confusion, as with a mantle."},{"verse":30,"text":"I will greatly praise the Lord with my mouth; yea, I will praise him among the multitude."},{"verse":31,"text":"For he shall stand at the right hand of the poor, to save him from those that condemn his soul. "}]},{"chapter":110,"verses":[{"verse":1,"text":"The Lord said unto my Lord, Sit thou at my right hand, until I make thine enemies thy footstool."},{"verse":2,"text":"The Lord shall send the rod of thy strength out of Zion: rule thou in the midst of thine enemies."},{"verse":3,"text":"Thy people shall be willing in the day of thy power, in the beauties of holiness from the womb of the morning: thou hast the dew of thy youth."},{"verse":4,"text":"The Lord hath sworn, and will not repent, Thou art a priest for ever after the order of Melchizedek."},{"verse":5,"text":"The Lord at thy right hand shall strike through kings in the day of his wrath."},{"verse":6,"text":"He shall judge among the heathen, he shall fill the places with the dead bodies; he shall wound the heads over many countries."},{"verse":7,"text":"He shall drink of the brook in the way: therefore shall he lift up the head. "}]},{"chapter":111,"verses":[{"verse":1,"text":"Praise ye the Lord. I will praise the Lord with my whole heart, in the assembly of the upright, and in the congregation."},{"verse":2,"text":"The works of the Lord are great, sought out of all them that have pleasure therein."},{"verse":3,"text":"His work is honourable and glorious: and his righteousness endureth for ever."},{"verse":4,"text":"He hath made his wonderful works to be remembered: the Lord is gracious and full of compassion."},{"verse":5,"text":"He hath given meat unto them that fear him: he will ever be mindful of his covenant."},{"verse":6,"text":"He hath shewed his people the power of his works, that he may give them the heritage of the heathen."},{"verse":7,"text":"The works of his hands are verity and judgment; all his commandments are sure."},{"verse":8,"text":"They stand fast for ever and ever, and are done in truth and uprightness."},{"verse":9,"text":"He sent redemption unto his people: he hath commanded his covenant for ever: holy and reverend is his name."},{"verse":10,"text":"The fear of the Lord is the beginning of wisdom: a good understanding have all they that do his commandments: his praise endureth for ever. "}]},{"chapter":112,"verses":[{"verse":1,"text":"Praise ye the Lord. Blessed is the man that feareth the Lord, that delighteth greatly in his commandments."},{"verse":2,"text":"His seed shall be mighty upon earth: the generation of the upright shall be blessed."},{"verse":3,"text":"Wealth and riches shall be in his house: and his righteousness endureth for ever."},{"verse":4,"text":"Unto the upright there ariseth light in the darkness: he is gracious, and full of compassion, and righteous."},{"verse":5,"text":"A good man sheweth favour, and lendeth: he will guide his affairs with discretion."},{"verse":6,"text":"Surely he shall not be moved for ever: the righteous shall be in everlasting remembrance."},{"verse":7,"text":"He shall not be afraid of evil tidings: his heart is fixed, trusting in the Lord."},{"verse":8,"text":"His heart is established, he shall not be afraid, until he see his desire upon his enemies."},{"verse":9,"text":"He hath dispersed, he hath given to the poor; his righteousness endureth for ever; his horn shall be exalted with honour."},{"verse":10,"text":"The wicked shall see it, and be grieved; he shall gnash with his teeth, and melt away: the desire of the wicked shall perish. "}]},{"chapter":113,"verses":[{"verse":1,"text":"Praise ye the Lord. Praise, O ye servants of the Lord, praise the name of the Lord."},{"verse":2,"text":"Blessed be the name of the Lord from this time forth and for evermore."},{"verse":3,"text":"From the rising of the sun unto the going down of the same the Lord’s name is to be praised."},{"verse":4,"text":"The Lord is high above all nations, and his glory above the heavens."},{"verse":5,"text":"Who is like unto the Lord our God, who dwelleth on high,"},{"verse":6,"text":"Who humbleth himself to behold the things that are in heaven, and in the earth!"},{"verse":7,"text":"He raiseth up the poor out of the dust, and lifteth the needy out of the dunghill;"},{"verse":8,"text":"That he may set him with princes, even with the princes of his people."},{"verse":9,"text":"He maketh the barren woman to keep house, and to be a joyful mother of children. Praise ye the Lord. "}]},{"chapter":114,"verses":[{"verse":1,"text":"When Israel went out of Egypt, the house of Jacob from a people of strange language;"},{"verse":2,"text":"Judah was his sanctuary, and Israel his dominion."},{"verse":3,"text":"The sea saw it, and fled: Jordan was driven back."},{"verse":4,"text":"The mountains skipped like rams, and the little hills like lambs."},{"verse":5,"text":"What ailed thee, O thou sea, that thou fleddest? thou Jordan, that thou wast driven back?"},{"verse":6,"text":"Ye mountains, that ye skipped like rams; and ye little hills, like lambs?"},{"verse":7,"text":"Tremble, thou earth, at the presence of the Lord, at the presence of the God of Jacob;"},{"verse":8,"text":"Which turned the rock into a standing water, the flint into a fountain of waters. "}]},{"chapter":115,"verses":[{"verse":1,"text":"Not unto us, O Lord, not unto us, but unto thy name give glory, for thy mercy, and for thy truth’s sake."},{"verse":2,"text":"Wherefore should the heathen say, Where is now their God?"},{"verse":3,"text":"But our God is in the heavens: he hath done whatsoever he hath pleased."},{"verse":4,"text":"Their idols are silver and gold, the work of men’s hands."},{"verse":5,"text":"They have mouths, but they speak not: eyes have they, but they see not:"},{"verse":6,"text":"They have ears, but they hear not: noses have they, but they smell not:"},{"verse":7,"text":"They have hands, but they handle not: feet have they, but they walk not: neither speak they through their throat."},{"verse":8,"text":"They that make them are like unto them; so is every one that trusteth in them."},{"verse":9,"text":"O Israel, trust thou in the Lord: he is their help and their shield."},{"verse":10,"text":"O house of Aaron, trust in the Lord: he is their help and their shield."},{"verse":11,"text":"Ye that fear the Lord, trust in the Lord: he is their help and their shield."},{"verse":12,"text":"The Lord hath been mindful of us: he will bless us; he will bless the house of Israel; he will bless the house of Aaron."},{"verse":13,"text":"He will bless them that fear the Lord, both small and great."},{"verse":14,"text":"The Lord shall increase you more and more, you and your children."},{"verse":15,"text":"Ye are blessed of the Lord which made heaven and earth."},{"verse":16,"text":"The heaven, even the heavens, are the Lord’s: but the earth hath he given to the children of men."},{"verse":17,"text":"The dead praise not the Lord, neither any that go down into silence."},{"verse":18,"text":"But we will bless the Lord from this time forth and for evermore. Praise the Lord. "}]},{"chapter":116,"verses":[{"verse":1,"text":"I love the Lord, because he hath heard my voice and my supplications."},{"verse":2,"text":"Because he hath inclined his ear unto me, therefore will I call upon him as long as I live."},{"verse":3,"text":"The sorrows of death compassed me, and the pains of hell gat hold upon me: I found trouble and sorrow."},{"verse":4,"text":"Then called I upon the name of the Lord; O Lord, I beseech thee, deliver my soul."},{"verse":5,"text":"Gracious is the Lord, and righteous; yea, our God is merciful."},{"verse":6,"text":"The Lord preserveth the simple: I was brought low, and he helped me."},{"verse":7,"text":"Return unto thy rest, O my soul; for the Lord hath dealt bountifully with thee."},{"verse":8,"text":"For thou hast delivered my soul from death, mine eyes from tears, and my feet from falling."},{"verse":9,"text":"I will walk before the Lord in the land of the living."},{"verse":10,"text":"I believed, therefore have I spoken: I was greatly afflicted:"},{"verse":11,"text":"I said in my haste, All men are liars."},{"verse":12,"text":"What shall I render unto the Lord for all his benefits toward me?"},{"verse":13,"text":"I will take the cup of salvation, and call upon the name of the Lord."},{"verse":14,"text":"I will pay my vows unto the Lord now in the presence of all his people."},{"verse":15,"text":"Precious in the sight of the Lord is the death of his saints."},{"verse":16,"text":"O Lord, truly I am thy servant; I am thy servant, and the son of thine handmaid: thou hast loosed my bonds."},{"verse":17,"text":"I will offer to thee the sacrifice of thanksgiving, and will call upon the name of the Lord."},{"verse":18,"text":"I will pay my vows unto the Lord now in the presence of all his people,"},{"verse":19,"text":"In the courts of the Lord’s house, in the midst of thee, O Jerusalem. Praise ye the Lord. "}]},{"chapter":117,"verses":[{"verse":1,"text":"O praise the Lord, all ye nations: praise him, all ye people."},{"verse":2,"text":"For his merciful kindness is great toward us: and the truth of the Lord endureth for ever. Praise ye the Lord. "}]},{"chapter":118,"verses":[{"verse":1,"text":"O give thanks unto the Lord; for he is good: because his mercy endureth for ever."},{"verse":2,"text":"Let Israel now say, that his mercy endureth for ever."},{"verse":3,"text":"Let the house of Aaron now say, that his mercy endureth for ever."},{"verse":4,"text":"Let them now that fear the Lord say, that his mercy endureth for ever."},{"verse":5,"text":"I called upon the Lord in distress: the Lord answered me, and set me in a large place."},{"verse":6,"text":"The Lord is on my side; I will not fear: what can man do unto me?"},{"verse":7,"text":"The Lord taketh my part with them that help me: therefore shall I see my desire upon them that hate me."},{"verse":8,"text":"It is better to trust in the Lord than to put confidence in man."},{"verse":9,"text":"It is better to trust in the Lord than to put confidence in princes."},{"verse":10,"text":"All nations compassed me about: but in the name of the Lord will I destroy them."},{"verse":11,"text":"They compassed me about; yea, they compassed me about: but in the name of the Lord I will destroy them."},{"verse":12,"text":"They compassed me about like bees; they are quenched as the fire of thorns: for in the name of the Lord I will destroy them."},{"verse":13,"text":"Thou hast thrust sore at me that I might fall: but the Lord helped me."},{"verse":14,"text":"The Lord is my strength and song, and is become my salvation."},{"verse":15,"text":"The voice of rejoicing and salvation is in the tabernacles of the righteous: the right hand of the Lord doeth valiantly."},{"verse":16,"text":"The right hand of the Lord is exalted: the right hand of the Lord doeth valiantly."},{"verse":17,"text":"I shall not die, but live, and declare the works of the Lord."},{"verse":18,"text":"The Lord hath chastened me sore: but he hath not given me over unto death."},{"verse":19,"text":"Open to me the gates of righteousness: I will go into them, and I will praise the Lord:"},{"verse":20,"text":"This gate of the Lord, into which the righteous shall enter."},{"verse":21,"text":"I will praise thee: for thou hast heard me, and art become my salvation."},{"verse":22,"text":"The stone which the builders refused is become the head stone of the corner."},{"verse":23,"text":"This is the Lord’s doing; it is marvellous in our eyes."},{"verse":24,"text":"This is the day which the Lord hath made; we will rejoice and be glad in it."},{"verse":25,"text":"Save now, I beseech thee, O Lord: O Lord, I beseech thee, send now prosperity."},{"verse":26,"text":"Blessed be he that cometh in the name of the Lord: we have blessed you out of the house of the Lord."},{"verse":27,"text":"God is the Lord, which hath shewed us light: bind the sacrifice with cords, even unto the horns of the altar."},{"verse":28,"text":"Thou art my God, and I will praise thee: thou art my God, I will exalt thee."},{"verse":29,"text":"O give thanks unto the Lord; for he is good: for his mercy endureth for ever. "}]},{"chapter":119,"verses":[{"verse":1,"text":" Blessed are the undefiled in the way, who walk in the law of the Lord."},{"verse":2,"text":"Blessed are they that keep his testimonies, and that seek him with the whole heart."},{"verse":3,"text":"They also do no iniquity: they walk in his ways."},{"verse":4,"text":"Thou hast commanded us to keep thy precepts diligently."},{"verse":5,"text":"O that my ways were directed to keep thy statutes!"},{"verse":6,"text":"Then shall I not be ashamed, when I have respect unto all thy commandments."},{"verse":7,"text":"I will praise thee with uprightness of heart, when I shall have learned thy righteous judgments."},{"verse":8,"text":"I will keep thy statutes: O forsake me not utterly."},{"verse":9,"text":" Wherewithal shall a young man cleanse his way? by taking heed thereto according to thy word."},{"verse":10,"text":"With my whole heart have I sought thee: O let me not wander from thy commandments."},{"verse":11,"text":"Thy word have I hid in mine heart, that I might not sin against thee."},{"verse":12,"text":"Blessed art thou, O Lord: teach me thy statutes."},{"verse":13,"text":"With my lips have I declared all the judgments of thy mouth."},{"verse":14,"text":"I have rejoiced in the way of thy testimonies, as much as in all riches."},{"verse":15,"text":"I will meditate in thy precepts, and have respect unto thy ways."},{"verse":16,"text":"I will delight myself in thy statutes: I will not forget thy word."},{"verse":17,"text":" Deal bountifully with thy servant, that I may live, and keep thy word."},{"verse":18,"text":"Open thou mine eyes, that I may behold wondrous things out of thy law."},{"verse":19,"text":"I am a stranger in the earth: hide not thy commandments from me."},{"verse":20,"text":"My soul breaketh for the longing that it hath unto thy judgments at all times."},{"verse":21,"text":"Thou hast rebuked the proud that are cursed, which do err from thy commandments."},{"verse":22,"text":"Remove from me reproach and contempt; for I have kept thy testimonies."},{"verse":23,"text":"Princes also did sit and speak against me: but thy servant did meditate in thy statutes."},{"verse":24,"text":"Thy testimonies also are my delight and my counsellors."},{"verse":25,"text":" My soul cleaveth unto the dust: quicken thou me according to thy word."},{"verse":26,"text":"I have declared my ways, and thou heardest me: teach me thy statutes."},{"verse":27,"text":"Make me to understand the way of thy precepts: so shall I talk of thy wondrous works."},{"verse":28,"text":"My soul melteth for heaviness: strengthen thou me according unto thy word."},{"verse":29,"text":"Remove from me the way of lying: and grant me thy law graciously."},{"verse":30,"text":"I have chosen the way of truth: thy judgments have I laid before me."},{"verse":31,"text":"I have stuck unto thy testimonies: O Lord, put me not to shame."},{"verse":32,"text":"I will run the way of thy commandments, when thou shalt enlarge my heart."},{"verse":33,"text":" Teach me, O Lord, the way of thy statutes; and I shall keep it unto the end."},{"verse":34,"text":"Give me understanding, and I shall keep thy law; yea, I shall observe it with my whole heart."},{"verse":35,"text":"Make me to go in the path of thy commandments; for therein do I delight."},{"verse":36,"text":"Incline my heart unto thy testimonies, and not to covetousness."},{"verse":37,"text":"Turn away mine eyes from beholding vanity; and quicken thou me in thy way."},{"verse":38,"text":"Stablish thy word unto thy servant, who is devoted to thy fear."},{"verse":39,"text":"Turn away my reproach which I fear: for thy judgments are good."},{"verse":40,"text":"Behold, I have longed after thy precepts: quicken me in thy righteousness."},{"verse":41,"text":" Let thy mercies come also unto me, O Lord, even thy salvation, according to thy word."},{"verse":42,"text":"So shall I have wherewith to answer him that reproacheth me: for I trust in thy word."},{"verse":43,"text":"And take not the word of truth utterly out of my mouth; for I have hoped in thy judgments."},{"verse":44,"text":"So shall I keep thy law continually for ever and ever."},{"verse":45,"text":"And I will walk at liberty: for I seek thy precepts."},{"verse":46,"text":"I will speak of thy testimonies also before kings, and will not be ashamed."},{"verse":47,"text":"And I will delight myself in thy commandments, which I have loved."},{"verse":48,"text":"My hands also will I lift up unto thy commandments, which I have loved; and I will meditate in thy statutes."},{"verse":49,"text":" Remember the word unto thy servant, upon which thou hast caused me to hope."},{"verse":50,"text":"This is my comfort in my affliction: for thy word hath quickened me."},{"verse":51,"text":"The proud have had me greatly in derision: yet have I not declined from thy law."},{"verse":52,"text":"I remembered thy judgments of old, O Lord; and have comforted myself."},{"verse":53,"text":"Horror hath taken hold upon me because of the wicked that forsake thy law."},{"verse":54,"text":"Thy statutes have been my songs in the house of my pilgrimage."},{"verse":55,"text":"I have remembered thy name, O Lord, in the night, and have kept thy law."},{"verse":56,"text":"This I had, because I kept thy precepts."},{"verse":57,"text":" Thou art my portion, O Lord: I have said that I would keep thy words."},{"verse":58,"text":"I intreated thy favour with my whole heart: be merciful unto me according to thy word."},{"verse":59,"text":"I thought on my ways, and turned my feet unto thy testimonies."},{"verse":60,"text":"I made haste, and delayed not to keep thy commandments."},{"verse":61,"text":"The bands of the wicked have robbed me: but I have not forgotten thy law."},{"verse":62,"text":"At midnight I will rise to give thanks unto thee because of thy righteous judgments."},{"verse":63,"text":"I am a companion of all them that fear thee, and of them that keep thy precepts."},{"verse":64,"text":"The earth, O Lord, is full of thy mercy: teach me thy statutes."},{"verse":65,"text":" Thou hast dealt well with thy servant, O Lord, according unto thy word."},{"verse":66,"text":"Teach me good judgment and knowledge: for I have believed thy commandments."},{"verse":67,"text":"Before I was afflicted I went astray: but now have I kept thy word."},{"verse":68,"text":"Thou art good, and doest good; teach me thy statutes."},{"verse":69,"text":"The proud have forged a lie against me: but I will keep thy precepts with my whole heart."},{"verse":70,"text":"Their heart is as fat as grease; but I delight in thy law."},{"verse":71,"text":"It is good for me that I have been afflicted; that I might learn thy statutes."},{"verse":72,"text":"The law of thy mouth is better unto me than thousands of gold and silver."},{"verse":73,"text":" Thy hands have made me and fashioned me: give me understanding, that I may learn thy commandments."},{"verse":74,"text":"They that fear thee will be glad when they see me; because I have hoped in thy word."},{"verse":75,"text":"I know, O Lord, that thy judgments are right, and that thou in faithfulness hast afflicted me."},{"verse":76,"text":"Let, I pray thee, thy merciful kindness be for my comfort, according to thy word unto thy servant."},{"verse":77,"text":"Let thy tender mercies come unto me, that I may live: for thy law is my delight."},{"verse":78,"text":"Let the proud be ashamed; for they dealt perversely with me without a cause: but I will meditate in thy precepts."},{"verse":79,"text":"Let those that fear thee turn unto me, and those that have known thy testimonies."},{"verse":80,"text":"Let my heart be sound in thy statutes; that I be not ashamed."},{"verse":81,"text":" My soul fainteth for thy salvation: but I hope in thy word."},{"verse":82,"text":"Mine eyes fail for thy word, saying, When wilt thou comfort me?"},{"verse":83,"text":"For I am become like a bottle in the smoke; yet do I not forget thy statutes."},{"verse":84,"text":"How many are the days of thy servant? when wilt thou execute judgment on them that persecute me?"},{"verse":85,"text":"The proud have digged pits for me, which are not after thy law."},{"verse":86,"text":"All thy commandments are faithful: they persecute me wrongfully; help thou me."},{"verse":87,"text":"They had almost consumed me upon earth; but I forsook not thy precepts."},{"verse":88,"text":"Quicken me after thy lovingkindness; so shall I keep the testimony of thy mouth."},{"verse":89,"text":" For ever, O Lord, thy word is settled in heaven."},{"verse":90,"text":"Thy faithfulness is unto all generations: thou hast established the earth, and it abideth."},{"verse":91,"text":"They continue this day according to thine ordinances: for all are thy servants."},{"verse":92,"text":"Unless thy law had been my delights, I should then have perished in mine affliction."},{"verse":93,"text":"I will never forget thy precepts: for with them thou hast quickened me."},{"verse":94,"text":"I am thine, save me; for I have sought thy precepts."},{"verse":95,"text":"The wicked have waited for me to destroy me: but I will consider thy testimonies."},{"verse":96,"text":"I have seen an end of all perfection: but thy commandment is exceeding broad."},{"verse":97,"text":" O how love I thy law! it is my meditation all the day."},{"verse":98,"text":"Thou through thy commandments hast made me wiser than mine enemies: for they are ever with me."},{"verse":99,"text":"I have more understanding than all my teachers: for thy testimonies are my meditation."},{"verse":100,"text":"I understand more than the ancients, because I keep thy precepts."},{"verse":101,"text":"I have refrained my feet from every evil way, that I might keep thy word."},{"verse":102,"text":"I have not departed from thy judgments: for thou hast taught me."},{"verse":103,"text":"How sweet are thy words unto my taste! yea, sweeter than honey to my mouth!"},{"verse":104,"text":"Through thy precepts I get understanding: therefore I hate every false way."},{"verse":105,"text":" Thy word is a lamp unto my feet, and a light unto my path."},{"verse":106,"text":"I have sworn, and I will perform it, that I will keep thy righteous judgments."},{"verse":107,"text":"I am afflicted very much: quicken me, O Lord, according unto thy word."},{"verse":108,"text":"Accept, I beseech thee, the freewill offerings of my mouth, O Lord, and teach me thy judgments."},{"verse":109,"text":"My soul is continually in my hand: yet do I not forget thy law."},{"verse":110,"text":"The wicked have laid a snare for me: yet I erred not from thy precepts."},{"verse":111,"text":"Thy testimonies have I taken as an heritage for ever: for they are the rejoicing of my heart."},{"verse":112,"text":"I have inclined mine heart to perform thy statutes alway, even unto the end."},{"verse":113,"text":" I hate vain thoughts: but thy law do I love."},{"verse":114,"text":"Thou art my hiding place and my shield: I hope in thy word."},{"verse":115,"text":"Depart from me, ye evildoers: for I will keep the commandments of my God."},{"verse":116,"text":"Uphold me according unto thy word, that I may live: and let me not be ashamed of my hope."},{"verse":117,"text":"Hold thou me up, and I shall be safe: and I will have respect unto thy statutes continually."},{"verse":118,"text":"Thou hast trodden down all them that err from thy statutes: for their deceit is falsehood."},{"verse":119,"text":"Thou puttest away all the wicked of the earth like dross: therefore I love thy testimonies."},{"verse":120,"text":"My flesh trembleth for fear of thee; and I am afraid of thy judgments."},{"verse":121,"text":" I have done judgment and justice: leave me not to mine oppressors."},{"verse":122,"text":"Be surety for thy servant for good: let not the proud oppress me."},{"verse":123,"text":"Mine eyes fail for thy salvation, and for the word of thy righteousness."},{"verse":124,"text":"Deal with thy servant according unto thy mercy, and teach me thy statutes."},{"verse":125,"text":"I am thy servant; give me understanding, that I may know thy testimonies."},{"verse":126,"text":"It is time for thee, Lord, to work: for they have made void thy law."},{"verse":127,"text":"Therefore I love thy commandments above gold; yea, above fine gold."},{"verse":128,"text":"Therefore I esteem all thy precepts concerning all things to be right; and I hate every false way."},{"verse":129,"text":" Thy testimonies are wonderful: therefore doth my soul keep them."},{"verse":130,"text":"The entrance of thy words giveth light; it giveth understanding unto the simple."},{"verse":131,"text":"I opened my mouth, and panted: for I longed for thy commandments."},{"verse":132,"text":"Look thou upon me, and be merciful unto me, as thou usest to do unto those that love thy name."},{"verse":133,"text":"Order my steps in thy word: and let not any iniquity have dominion over me."},{"verse":134,"text":"Deliver me from the oppression of man: so will I keep thy precepts."},{"verse":135,"text":"Make thy face to shine upon thy servant; and teach me thy statutes."},{"verse":136,"text":"Rivers of waters run down mine eyes, because they keep not thy law."},{"verse":137,"text":" Righteous art thou, O Lord, and upright are thy judgments."},{"verse":138,"text":"Thy testimonies that thou hast commanded are righteous and very faithful."},{"verse":139,"text":"My zeal hath consumed me, because mine enemies have forgotten thy words."},{"verse":140,"text":"Thy word is very pure: therefore thy servant loveth it."},{"verse":141,"text":"I am small and despised: yet do not I forget thy precepts."},{"verse":142,"text":"Thy righteousness is an everlasting righteousness, and thy law is the truth."},{"verse":143,"text":"Trouble and anguish have taken hold on me: yet thy commandments are my delights."},{"verse":144,"text":"The righteousness of thy testimonies is everlasting: give me understanding, and I shall live."},{"verse":145,"text":" I cried with my whole heart; hear me, O Lord: I will keep thy statutes."},{"verse":146,"text":"I cried unto thee; save me, and I shall keep thy testimonies."},{"verse":147,"text":"I prevented the dawning of the morning, and cried: I hoped in thy word."},{"verse":148,"text":"Mine eyes prevent the night watches, that I might meditate in thy word."},{"verse":149,"text":"Hear my voice according unto thy lovingkindness: O Lord, quicken me according to thy judgment."},{"verse":150,"text":"They draw nigh that follow after mischief: they are far from thy law."},{"verse":151,"text":"Thou art near, O Lord; and all thy commandments are truth."},{"verse":152,"text":"Concerning thy testimonies, I have known of old that thou hast founded them for ever."},{"verse":153,"text":" Consider mine affliction, and deliver me: for I do not forget thy law."},{"verse":154,"text":"Plead my cause, and deliver me: quicken me according to thy word."},{"verse":155,"text":"Salvation is far from the wicked: for they seek not thy statutes."},{"verse":156,"text":"Great are thy tender mercies, O Lord: quicken me according to thy judgments."},{"verse":157,"text":"Many are my persecutors and mine enemies; yet do I not decline from thy testimonies."},{"verse":158,"text":"I beheld the transgressors, and was grieved; because they kept not thy word."},{"verse":159,"text":"Consider how I love thy precepts: quicken me, O Lord, according to thy lovingkindness."},{"verse":160,"text":"Thy word is true from the beginning: and every one of thy righteous judgments endureth for ever."},{"verse":161,"text":" Princes have persecuted me without a cause: but my heart standeth in awe of thy word."},{"verse":162,"text":"I rejoice at thy word, as one that findeth great spoil."},{"verse":163,"text":"I hate and abhor lying: but thy law do I love."},{"verse":164,"text":"Seven times a day do I praise thee because of thy righteous judgments."},{"verse":165,"text":"Great peace have they which love thy law: and nothing shall offend them."},{"verse":166,"text":"Lord, I have hoped for thy salvation, and done thy commandments."},{"verse":167,"text":"My soul hath kept thy testimonies; and I love them exceedingly."},{"verse":168,"text":"I have kept thy precepts and thy testimonies: for all my ways are before thee."},{"verse":169,"text":" Let my cry come near before thee, O Lord: give me understanding according to thy word."},{"verse":170,"text":"Let my supplication come before thee: deliver me according to thy word."},{"verse":171,"text":"My lips shall utter praise, when thou hast taught me thy statutes."},{"verse":172,"text":"My tongue shall speak of thy word: for all thy commandments are righteousness."},{"verse":173,"text":"Let thine hand help me; for I have chosen thy precepts."},{"verse":174,"text":"I have longed for thy salvation, O Lord; and thy law is my delight."},{"verse":175,"text":"Let my soul live, and it shall praise thee; and let thy judgments help me."},{"verse":176,"text":"I have gone astray like a lost sheep; seek thy servant; for I do not forget thy commandments. "}]},{"chapter":120,"verses":[{"verse":1,"text":"In my distress I cried unto the Lord, and he heard me."},{"verse":2,"text":"Deliver my soul, O Lord, from lying lips, and from a deceitful tongue."},{"verse":3,"text":"What shall be given unto thee? or what shall be done unto thee, thou false tongue?"},{"verse":4,"text":"Sharp arrows of the mighty, with coals of juniper."},{"verse":5,"text":"Woe is me, that I sojourn in Mesech, that I dwell in the tents of Kedar!"},{"verse":6,"text":"My soul hath long dwelt with him that hateth peace."},{"verse":7,"text":"I am for peace: but when I speak, they are for war. "}]},{"chapter":121,"verses":[{"verse":1,"text":"I will lift up mine eyes unto the hills, from whence cometh my help."},{"verse":2,"text":"My help cometh from the Lord, which made heaven and earth."},{"verse":3,"text":"He will not suffer thy foot to be moved: he that keepeth thee will not slumber."},{"verse":4,"text":"Behold, he that keepeth Israel shall neither slumber nor sleep."},{"verse":5,"text":"The Lord is thy keeper: the Lord is thy shade upon thy right hand."},{"verse":6,"text":"The sun shall not smite thee by day, nor the moon by night."},{"verse":7,"text":"The Lord shall preserve thee from all evil: he shall preserve thy soul."},{"verse":8,"text":"The Lord shall preserve thy going out and thy coming in from this time forth, and even for evermore. "}]},{"chapter":122,"verses":[{"verse":1,"text":"I was glad when they said unto me, Let us go into the house of the Lord."},{"verse":2,"text":"Our feet shall stand within thy gates, O Jerusalem."},{"verse":3,"text":"Jerusalem is builded as a city that is compact together:"},{"verse":4,"text":"Whither the tribes go up, the tribes of the Lord, unto the testimony of Israel, to give thanks unto the name of the Lord."},{"verse":5,"text":"For there are set thrones of judgment, the thrones of the house of David."},{"verse":6,"text":"Pray for the peace of Jerusalem: they shall prosper that love thee."},{"verse":7,"text":"Peace be within thy walls, and prosperity within thy palaces."},{"verse":8,"text":"For my brethren and companions’ sakes, I will now say, Peace be within thee."},{"verse":9,"text":"Because of the house of the Lord our God I will seek thy good. "}]},{"chapter":123,"verses":[{"verse":1,"text":"Unto thee lift I up mine eyes, O thou that dwellest in the heavens."},{"verse":2,"text":"Behold, as the eyes of servants look unto the hand of their masters, and as the eyes of a maiden unto the hand of her mistress; so our eyes wait upon the Lord our God, until that he have mercy upon us."},{"verse":3,"text":"Have mercy upon us, O Lord, have mercy upon us: for we are exceedingly filled with contempt."},{"verse":4,"text":"Our soul is exceedingly filled with the scorning of those that are at ease, and with the contempt of the proud. "}]},{"chapter":124,"verses":[{"verse":1,"text":"If it had not been the Lord who was on our side, now may Israel say;"},{"verse":2,"text":"If it had not been the Lord who was on our side, when men rose up against us:"},{"verse":3,"text":"Then they had swallowed us up quick, when their wrath was kindled against us:"},{"verse":4,"text":"Then the waters had overwhelmed us, the stream had gone over our soul:"},{"verse":5,"text":"Then the proud waters had gone over our soul."},{"verse":6,"text":"Blessed be the Lord, who hath not given us as a prey to their teeth."},{"verse":7,"text":"Our soul is escaped as a bird out of the snare of the fowlers: the snare is broken, and we are escaped."},{"verse":8,"text":"Our help is in the name of the Lord, who made heaven and earth. "}]},{"chapter":125,"verses":[{"verse":1,"text":"They that trust in the Lord shall be as mount Zion, which cannot be removed, but abideth for ever."},{"verse":2,"text":"As the mountains are round about Jerusalem, so the Lord is round about his people from henceforth even for ever."},{"verse":3,"text":"For the rod of the wicked shall not rest upon the lot of the righteous; lest the righteous put forth their hands unto iniquity."},{"verse":4,"text":"Do good, O Lord, unto those that be good, and to them that are upright in their hearts."},{"verse":5,"text":"As for such as turn aside unto their crooked ways, the Lord shall lead them forth with the workers of iniquity: but peace shall be upon Israel. "}]},{"chapter":126,"verses":[{"verse":1,"text":"When the Lord turned again the captivity of Zion, we were like them that dream."},{"verse":2,"text":"Then was our mouth filled with laughter, and our tongue with singing: then said they among the heathen, The Lord hath done great things for them."},{"verse":3,"text":"The Lord hath done great things for us; whereof we are glad."},{"verse":4,"text":"Turn again our captivity, O Lord, as the streams in the south."},{"verse":5,"text":"They that sow in tears shall reap in joy."},{"verse":6,"text":"He that goeth forth and weepeth, bearing precious seed, shall doubtless come again with rejoicing, bringing his sheaves with him. "}]},{"chapter":127,"verses":[{"verse":1,"text":"Except the Lord build the house, they labour in vain that build it: except the Lord keep the city, the watchman waketh but in vain."},{"verse":2,"text":"It is vain for you to rise up early, to sit up late, to eat the bread of sorrows: for so he giveth his beloved sleep."},{"verse":3,"text":"Lo, children are an heritage of the Lord: and the fruit of the womb is his reward."},{"verse":4,"text":"As arrows are in the hand of a mighty man; so are children of the youth."},{"verse":5,"text":"Happy is the man that hath his quiver full of them: they shall not be ashamed, but they shall speak with the enemies in the gate. "}]},{"chapter":128,"verses":[{"verse":1,"text":"Blessed is every one that feareth the Lord; that walketh in his ways."},{"verse":2,"text":"For thou shalt eat the labour of thine hands: happy shalt thou be, and it shall be well with thee."},{"verse":3,"text":"Thy wife shall be as a fruitful vine by the sides of thine house: thy children like olive plants round about thy table."},{"verse":4,"text":"Behold, that thus shall the man be blessed that feareth the Lord."},{"verse":5,"text":"The Lord shall bless thee out of Zion: and thou shalt see the good of Jerusalem all the days of thy life."},{"verse":6,"text":"Yea, thou shalt see thy children’s children, and peace upon Israel. "}]},{"chapter":129,"verses":[{"verse":1,"text":"Many a time have they afflicted me from my youth, may Israel now say:"},{"verse":2,"text":"Many a time have they afflicted me from my youth: yet they have not prevailed against me."},{"verse":3,"text":"The plowers plowed upon my back: they made long their furrows."},{"verse":4,"text":"The Lord is righteous: he hath cut asunder the cords of the wicked."},{"verse":5,"text":"Let them all be confounded and turned back that hate Zion."},{"verse":6,"text":"Let them be as the grass upon the housetops, which withereth afore it groweth up:"},{"verse":7,"text":"Wherewith the mower filleth not his hand; nor he that bindeth sheaves his bosom."},{"verse":8,"text":"Neither do they which go by say, The blessing of the Lord be upon you: we bless you in the name of the Lord. "}]},{"chapter":130,"verses":[{"verse":1,"text":"Out of the depths have I cried unto thee, O Lord."},{"verse":2,"text":"Lord, hear my voice: let thine ears be attentive to the voice of my supplications."},{"verse":3,"text":"If thou, Lord, shouldest mark iniquities, O Lord, who shall stand?"},{"verse":4,"text":"But there is forgiveness with thee, that thou mayest be feared."},{"verse":5,"text":"I wait for the Lord, my soul doth wait, and in his word do I hope."},{"verse":6,"text":"My soul waiteth for the Lord more than they that watch for the morning: I say, more than they that watch for the morning."},{"verse":7,"text":"Let Israel hope in the Lord: for with the Lord there is mercy, and with him is plenteous redemption."},{"verse":8,"text":"And he shall redeem Israel from all his iniquities. "}]},{"chapter":131,"verses":[{"verse":1,"text":"Lord, my heart is not haughty, nor mine eyes lofty: neither do I exercise myself in great matters, or in things too high for me."},{"verse":2,"text":"Surely I have behaved and quieted myself, as a child that is weaned of his mother: my soul is even as a weaned child."},{"verse":3,"text":"Let Israel hope in the Lord from henceforth and for ever. "}]},{"chapter":132,"verses":[{"verse":1,"text":"Lord, remember David, and all his afflictions:"},{"verse":2,"text":"How he sware unto the Lord, and vowed unto the mighty God of Jacob;"},{"verse":3,"text":"Surely I will not come into the tabernacle of my house, nor go up into my bed;"},{"verse":4,"text":"I will not give sleep to mine eyes, or slumber to mine eyelids,"},{"verse":5,"text":"Until I find out a place for the Lord, an habitation for the mighty God of Jacob."},{"verse":6,"text":"Lo, we heard of it at Ephratah: we found it in the fields of the wood."},{"verse":7,"text":"We will go into his tabernacles: we will worship at his footstool."},{"verse":8,"text":"Arise, O Lord, into thy rest; thou, and the ark of thy strength."},{"verse":9,"text":"Let thy priests be clothed with righteousness; and let thy saints shout for joy."},{"verse":10,"text":"For thy servant David’s sake turn not away the face of thine anointed."},{"verse":11,"text":"The Lord hath sworn in truth unto David; he will not turn from it; Of the fruit of thy body will I set upon thy throne."},{"verse":12,"text":"If thy children will keep my covenant and my testimony that I shall teach them, their children shall also sit upon thy throne for evermore."},{"verse":13,"text":"For the Lord hath chosen Zion; he hath desired it for his habitation."},{"verse":14,"text":"This is my rest for ever: here will I dwell; for I have desired it."},{"verse":15,"text":"I will abundantly bless her provision: I will satisfy her poor with bread."},{"verse":16,"text":"I will also clothe her priests with salvation: and her saints shall shout aloud for joy."},{"verse":17,"text":"There will I make the horn of David to bud: I have ordained a lamp for mine anointed."},{"verse":18,"text":"His enemies will I clothe with shame: but upon himself shall his crown flourish. "}]},{"chapter":133,"verses":[{"verse":1,"text":"Behold, how good and how pleasant it is for brethren to dwell together in unity!"},{"verse":2,"text":"It is like the precious ointment upon the head, that ran down upon the beard, even Aaron’s beard: that went down to the skirts of his garments;"},{"verse":3,"text":"As the dew of Hermon, and as the dew that descended upon the mountains of Zion: for there the Lord commanded the blessing, even life for evermore. "}]},{"chapter":134,"verses":[{"verse":1,"text":"Behold, bless ye the Lord, all ye servants of the Lord, which by night stand in the house of the Lord."},{"verse":2,"text":"Lift up your hands in the sanctuary, and bless the Lord."},{"verse":3,"text":"The Lord that made heaven and earth bless thee out of Zion. "}]},{"chapter":135,"verses":[{"verse":1,"text":"Praise ye the Lord. Praise ye the name of the Lord; praise him, O ye servants of the Lord."},{"verse":2,"text":"Ye that stand in the house of the Lord, in the courts of the house of our God,"},{"verse":3,"text":"Praise the Lord; for the Lord is good: sing praises unto his name; for it is pleasant."},{"verse":4,"text":"For the Lord hath chosen Jacob unto himself, and Israel for his peculiar treasure."},{"verse":5,"text":"For I know that the Lord is great, and that our Lord is above all gods."},{"verse":6,"text":"Whatsoever the Lord pleased, that did he in heaven, and in earth, in the seas, and all deep places."},{"verse":7,"text":"He causeth the vapours to ascend from the ends of the earth; he maketh lightnings for the rain; he bringeth the wind out of his treasuries."},{"verse":8,"text":"Who smote the firstborn of Egypt, both of man and beast."},{"verse":9,"text":"Who sent tokens and wonders into the midst of thee, O Egypt, upon Pharaoh, and upon all his servants."},{"verse":10,"text":"Who smote great nations, and slew mighty kings;"},{"verse":11,"text":"Sihon king of the Amorites, and Og king of Bashan, and all the kingdoms of Canaan:"},{"verse":12,"text":"And gave their land for an heritage, an heritage unto Israel his people."},{"verse":13,"text":"Thy name, O Lord, endureth for ever; and thy memorial, O Lord, throughout all generations."},{"verse":14,"text":"For the Lord will judge his people, and he will repent himself concerning his servants."},{"verse":15,"text":"The idols of the heathen are silver and gold, the work of men’s hands."},{"verse":16,"text":"They have mouths, but they speak not; eyes have they, but they see not;"},{"verse":17,"text":"They have ears, but they hear not; neither is there any breath in their mouths."},{"verse":18,"text":"They that make them are like unto them: so is every one that trusteth in them."},{"verse":19,"text":"Bless the Lord, O house of Israel: bless the Lord, O house of Aaron:"},{"verse":20,"text":"Bless the Lord, O house of Levi: ye that fear the Lord, bless the Lord."},{"verse":21,"text":"Blessed be the Lord out of Zion, which dwelleth at Jerusalem. Praise ye the Lord. "}]},{"chapter":136,"verses":[{"verse":1,"text":"O give thanks unto the Lord; for he is good: for his mercy endureth for ever."},{"verse":2,"text":"O give thanks unto the God of gods: for his mercy endureth for ever."},{"verse":3,"text":"O give thanks to the Lord of lords: for his mercy endureth for ever."},{"verse":4,"text":"To him who alone doeth great wonders: for his mercy endureth for ever."},{"verse":5,"text":"To him that by wisdom made the heavens: for his mercy endureth for ever."},{"verse":6,"text":"To him that stretched out the earth above the waters: for his mercy endureth for ever."},{"verse":7,"text":"To him that made great lights: for his mercy endureth for ever:"},{"verse":8,"text":"The sun to rule by day: for his mercy endureth for ever:"},{"verse":9,"text":"The moon and stars to rule by night: for his mercy endureth for ever."},{"verse":10,"text":"To him that smote Egypt in their firstborn: for his mercy endureth for ever:"},{"verse":11,"text":"And brought out Israel from among them: for his mercy endureth for ever:"},{"verse":12,"text":"With a strong hand, and with a stretched out arm: for his mercy endureth for ever."},{"verse":13,"text":"To him which divided the Red sea into parts: for his mercy endureth for ever:"},{"verse":14,"text":"And made Israel to pass through the midst of it: for his mercy endureth for ever:"},{"verse":15,"text":"But overthrew Pharaoh and his host in the Red sea: for his mercy endureth for ever."},{"verse":16,"text":"To him which led his people through the wilderness: for his mercy endureth for ever."},{"verse":17,"text":"To him which smote great kings: for his mercy endureth for ever:"},{"verse":18,"text":"And slew famous kings: for his mercy endureth for ever:"},{"verse":19,"text":"Sihon king of the Amorites: for his mercy endureth for ever:"},{"verse":20,"text":"And Og the king of Bashan: for his mercy endureth for ever:"},{"verse":21,"text":"And gave their land for an heritage: for his mercy endureth for ever:"},{"verse":22,"text":"Even an heritage unto Israel his servant: for his mercy endureth for ever."},{"verse":23,"text":"Who remembered us in our low estate: for his mercy endureth for ever:"},{"verse":24,"text":"And hath redeemed us from our enemies: for his mercy endureth for ever."},{"verse":25,"text":"Who giveth food to all flesh: for his mercy endureth for ever."},{"verse":26,"text":"O give thanks unto the God of heaven: for his mercy endureth for ever. "}]},{"chapter":137,"verses":[{"verse":1,"text":"By the rivers of Babylon, there we sat down, yea, we wept, when we remembered Zion."},{"verse":2,"text":"We hanged our harps upon the willows in the midst thereof."},{"verse":3,"text":"For there they that carried us away captive required of us a song; and they that wasted us required of us mirth, saying, Sing us one of the songs of Zion."},{"verse":4,"text":"How shall we sing the Lord’s song in a strange land?"},{"verse":5,"text":"If I forget thee, O Jerusalem, let my right hand forget her cunning."},{"verse":6,"text":"If I do not remember thee, let my tongue cleave to the roof of my mouth; if I prefer not Jerusalem above my chief joy."},{"verse":7,"text":"Remember, O Lord, the children of Edom in the day of Jerusalem; who said, Rase it, rase it, even to the foundation thereof."},{"verse":8,"text":"O daughter of Babylon, who art to be destroyed; happy shall he be, that rewardeth thee as thou hast served us."},{"verse":9,"text":"Happy shall he be, that taketh and dasheth thy little ones against the stones. "}]},{"chapter":138,"verses":[{"verse":1,"text":"I will praise thee with my whole heart: before the gods will I sing praise unto thee."},{"verse":2,"text":"I will worship toward thy holy temple, and praise thy name for thy lovingkindness and for thy truth: for thou hast magnified thy word above all thy name."},{"verse":3,"text":"In the day when I cried thou answeredst me, and strengthenedst me with strength in my soul."},{"verse":4,"text":"All the kings of the earth shall praise thee, O Lord, when they hear the words of thy mouth."},{"verse":5,"text":"Yea, they shall sing in the ways of the Lord: for great is the glory of the Lord."},{"verse":6,"text":"Though the Lord be high, yet hath he respect unto the lowly: but the proud he knoweth afar off."},{"verse":7,"text":"Though I walk in the midst of trouble, thou wilt revive me: thou shalt stretch forth thine hand against the wrath of mine enemies, and thy right hand shall save me."},{"verse":8,"text":"The Lord will perfect that which concerneth me: thy mercy, O Lord, endureth for ever: forsake not the works of thine own hands. "}]},{"chapter":139,"verses":[{"verse":1,"text":"O Lord, thou hast searched me, and known me."},{"verse":2,"text":"Thou knowest my downsitting and mine uprising, thou understandest my thought afar off."},{"verse":3,"text":"Thou compassest my path and my lying down, and art acquainted with all my ways."},{"verse":4,"text":"For there is not a word in my tongue, but, lo, O Lord, thou knowest it altogether."},{"verse":5,"text":"Thou hast beset me behind and before, and laid thine hand upon me."},{"verse":6,"text":"Such knowledge is too wonderful for me; it is high, I cannot attain unto it."},{"verse":7,"text":"Whither shall I go from thy spirit? or whither shall I flee from thy presence?"},{"verse":8,"text":"If I ascend up into heaven, thou art there: if I make my bed in hell, behold, thou art there."},{"verse":9,"text":"If I take the wings of the morning, and dwell in the uttermost parts of the sea;"},{"verse":10,"text":"Even there shall thy hand lead me, and thy right hand shall hold me."},{"verse":11,"text":"If I say, Surely the darkness shall cover me; even the night shall be light about me."},{"verse":12,"text":"Yea, the darkness hideth not from thee; but the night shineth as the day: the darkness and the light are both alike to thee."},{"verse":13,"text":"For thou hast possessed my reins: thou hast covered me in my mother’s womb."},{"verse":14,"text":"I will praise thee; for I am fearfully and wonderfully made: marvellous are thy works; and that my soul knoweth right well."},{"verse":15,"text":"My substance was not hid from thee, when I was made in secret, and curiously wrought in the lowest parts of the earth."},{"verse":16,"text":"Thine eyes did see my substance, yet being unperfect; and in thy book all my members were written, which in continuance were fashioned, when as yet there was none of them."},{"verse":17,"text":"How precious also are thy thoughts unto me, O God! how great is the sum of them!"},{"verse":18,"text":"If I should count them, they are more in number than the sand: when I awake, I am still with thee."},{"verse":19,"text":"Surely thou wilt slay the wicked, O God: depart from me therefore, ye bloody men."},{"verse":20,"text":"For they speak against thee wickedly, and thine enemies take thy name in vain."},{"verse":21,"text":"Do not I hate them, O Lord, that hate thee? and am not I grieved with those that rise up against thee?"},{"verse":22,"text":"I hate them with perfect hatred: I count them mine enemies."},{"verse":23,"text":"Search me, O God, and know my heart: try me, and know my thoughts:"},{"verse":24,"text":"And see if there be any wicked way in me, and lead me in the way everlasting. "}]},{"chapter":140,"verses":[{"verse":1,"text":"Deliver me, O Lord, from the evil man: preserve me from the violent man;"},{"verse":2,"text":"Which imagine mischiefs in their heart; continually are they gathered together for war."},{"verse":3,"text":"They have sharpened their tongues like a serpent; adders’ poison is under their lips. Selah."},{"verse":4,"text":"Keep me, O Lord, from the hands of the wicked; preserve me from the violent man; who have purposed to overthrow my goings."},{"verse":5,"text":"The proud have hid a snare for me, and cords; they have spread a net by the wayside; they have set gins for me. Selah."},{"verse":6,"text":"I said unto the Lord, Thou art my God: hear the voice of my supplications, O Lord."},{"verse":7,"text":"O God the Lord, the strength of my salvation, thou hast covered my head in the day of battle."},{"verse":8,"text":"Grant not, O Lord, the desires of the wicked: further not his wicked device; lest they exalt themselves. Selah."},{"verse":9,"text":"As for the head of those that compass me about, let the mischief of their own lips cover them."},{"verse":10,"text":"Let burning coals fall upon them: let them be cast into the fire; into deep pits, that they rise not up again."},{"verse":11,"text":"Let not an evil speaker be established in the earth: evil shall hunt the violent man to overthrow him."},{"verse":12,"text":"I know that the Lord will maintain the cause of the afflicted, and the right of the poor."},{"verse":13,"text":"Surely the righteous shall give thanks unto thy name: the upright shall dwell in thy presence. "}]},{"chapter":141,"verses":[{"verse":1,"text":"Lord, I cry unto thee: make haste unto me; give ear unto my voice, when I cry unto thee."},{"verse":2,"text":"Let my prayer be set forth before thee as incense; and the lifting up of my hands as the evening sacrifice."},{"verse":3,"text":"Set a watch, O Lord, before my mouth; keep the door of my lips."},{"verse":4,"text":"Incline not my heart to any evil thing, to practise wicked works with men that work iniquity: and let me not eat of their dainties."},{"verse":5,"text":"Let the righteous smite me; it shall be a kindness: and let him reprove me; it shall be an excellent oil, which shall not break my head: for yet my prayer also shall be in their calamities."},{"verse":6,"text":"When their judges are overthrown in stony places, they shall hear my words; for they are sweet."},{"verse":7,"text":"Our bones are scattered at the grave’s mouth, as when one cutteth and cleaveth wood upon the earth."},{"verse":8,"text":"But mine eyes are unto thee, O God the Lord: in thee is my trust; leave not my soul destitute."},{"verse":9,"text":"Keep me from the snares which they have laid for me, and the gins of the workers of iniquity."},{"verse":10,"text":"Let the wicked fall into their own nets, whilst that I withal escape. "}]},{"chapter":142,"verses":[{"verse":1,"text":"I cried unto the Lord with my voice; with my voice unto the Lord did I make my supplication."},{"verse":2,"text":"I poured out my complaint before him; I shewed before him my trouble."},{"verse":3,"text":"When my spirit was overwhelmed within me, then thou knewest my path. In the way wherein I walked have they privily laid a snare for me."},{"verse":4,"text":"I looked on my right hand, and beheld, but there was no man that would know me: refuge failed me; no man cared for my soul."},{"verse":5,"text":"I cried unto thee, O Lord: I said, Thou art my refuge and my portion in the land of the living."},{"verse":6,"text":"Attend unto my cry; for I am brought very low: deliver me from my persecutors; for they are stronger than I."},{"verse":7,"text":"Bring my soul out of prison, that I may praise thy name: the righteous shall compass me about; for thou shalt deal bountifully with me. "}]},{"chapter":143,"verses":[{"verse":1,"text":"Hear my prayer, O Lord, give ear to my supplications: in thy faithfulness answer me, and in thy righteousness."},{"verse":2,"text":"And enter not into judgment with thy servant: for in thy sight shall no man living be justified."},{"verse":3,"text":"For the enemy hath persecuted my soul; he hath smitten my life down to the ground; he hath made me to dwell in darkness, as those that have been long dead."},{"verse":4,"text":"Therefore is my spirit overwhelmed within me; my heart within me is desolate."},{"verse":5,"text":"I remember the days of old; I meditate on all thy works; I muse on the work of thy hands."},{"verse":6,"text":"I stretch forth my hands unto thee: my soul thirsteth after thee, as a thirsty land. Selah."},{"verse":7,"text":"Hear me speedily, O Lord: my spirit faileth: hide not thy face from me, lest I be like unto them that go down into the pit."},{"verse":8,"text":"Cause me to hear thy lovingkindness in the morning; for in thee do I trust: cause me to know the way wherein I should walk; for I lift up my soul unto thee."},{"verse":9,"text":"Deliver me, O Lord, from mine enemies: I flee unto thee to hide me."},{"verse":10,"text":"Teach me to do thy will; for thou art my God: thy spirit is good; lead me into the land of uprightness."},{"verse":11,"text":"Quicken me, O Lord, for thy name’s sake: for thy righteousness’ sake bring my soul out of trouble."},{"verse":12,"text":"And of thy mercy cut off mine enemies, and destroy all them that afflict my soul: for I am thy servant. "}]},{"chapter":144,"verses":[{"verse":1,"text":"Blessed be the Lord my strength, which teacheth my hands to war, and my fingers to fight:"},{"verse":2,"text":"My goodness, and my fortress; my high tower, and my deliverer; my shield, and he in whom I trust; who subdueth my people under me."},{"verse":3,"text":"Lord, what is man, that thou takest knowledge of him! or the son of man, that thou makest account of him!"},{"verse":4,"text":"Man is like to vanity: his days are as a shadow that passeth away."},{"verse":5,"text":"Bow thy heavens, O Lord, and come down: touch the mountains, and they shall smoke."},{"verse":6,"text":"Cast forth lightning, and scatter them: shoot out thine arrows, and destroy them."},{"verse":7,"text":"Send thine hand from above; rid me, and deliver me out of great waters, from the hand of strange children;"},{"verse":8,"text":"Whose mouth speaketh vanity, and their right hand is a right hand of falsehood."},{"verse":9,"text":"I will sing a new song unto thee, O God: upon a psaltery and an instrument of ten strings will I sing praises unto thee."},{"verse":10,"text":"It is he that giveth salvation unto kings: who delivereth David his servant from the hurtful sword."},{"verse":11,"text":"Rid me, and deliver me from the hand of strange children, whose mouth speaketh vanity, and their right hand is a right hand of falsehood:"},{"verse":12,"text":"That our sons may be as plants grown up in their youth; that our daughters may be as corner stones, polished after the similitude of a palace:"},{"verse":13,"text":"That our garners may be full, affording all manner of store: that our sheep may bring forth thousands and ten thousands in our streets:"},{"verse":14,"text":"That our oxen may be strong to labour; that there be no breaking in, nor going out; that there be no complaining in our streets."},{"verse":15,"text":"Happy is that people, that is in such a case: yea, happy is that people, whose God is the Lord. "}]},{"chapter":145,"verses":[{"verse":1,"text":"I will extol thee, my God, O king; and I will bless thy name for ever and ever."},{"verse":2,"text":"Every day will I bless thee; and I will praise thy name for ever and ever."},{"verse":3,"text":"Great is the Lord, and greatly to be praised; and his greatness is unsearchable."},{"verse":4,"text":"One generation shall praise thy works to another, and shall declare thy mighty acts."},{"verse":5,"text":"I will speak of the glorious honour of thy majesty, and of thy wondrous works."},{"verse":6,"text":"And men shall speak of the might of thy terrible acts: and I will declare thy greatness."},{"verse":7,"text":"They shall abundantly utter the memory of thy great goodness, and shall sing of thy righteousness."},{"verse":8,"text":"The Lord is gracious, and full of compassion; slow to anger, and of great mercy."},{"verse":9,"text":"The Lord is good to all: and his tender mercies are over all his works."},{"verse":10,"text":"All thy works shall praise thee, O Lord; and thy saints shall bless thee."},{"verse":11,"text":"They shall speak of the glory of thy kingdom, and talk of thy power;"},{"verse":12,"text":"To make known to the sons of men his mighty acts, and the glorious majesty of his kingdom."},{"verse":13,"text":"Thy kingdom is an everlasting kingdom, and thy dominion endureth throughout all generations."},{"verse":14,"text":"The Lord upholdeth all that fall, and raiseth up all those that be bowed down."},{"verse":15,"text":"The eyes of all wait upon thee; and thou givest them their meat in due season."},{"verse":16,"text":"Thou openest thine hand, and satisfiest the desire of every living thing."},{"verse":17,"text":"The Lord is righteous in all his ways, and holy in all his works."},{"verse":18,"text":"The Lord is nigh unto all them that call upon him, to all that call upon him in truth."},{"verse":19,"text":"He will fulfil the desire of them that fear him: he also will hear their cry, and will save them."},{"verse":20,"text":"The Lord preserveth all them that love him: but all the wicked will he destroy."},{"verse":21,"text":"My mouth shall speak the praise of the Lord: and let all flesh bless his holy name for ever and ever. "}]},{"chapter":146,"verses":[{"verse":1,"text":"Praise ye the Lord. Praise the Lord, O my soul."},{"verse":2,"text":"While I live will I praise the Lord: I will sing praises unto my God while I have any being."},{"verse":3,"text":"Put not your trust in princes, nor in the son of man, in whom there is no help."},{"verse":4,"text":"His breath goeth forth, he returneth to his earth; in that very day his thoughts perish."},{"verse":5,"text":"Happy is he that hath the God of Jacob for his help, whose hope is in the Lord his God:"},{"verse":6,"text":"Which made heaven, and earth, the sea, and all that therein is: which keepeth truth for ever:"},{"verse":7,"text":"Which executeth judgment for the oppressed: which giveth food to the hungry. The Lord looseth the prisoners:"},{"verse":8,"text":"The Lord openeth the eyes of the blind: the Lord raiseth them that are bowed down: the Lord loveth the righteous:"},{"verse":9,"text":"The Lord preserveth the strangers; he relieveth the fatherless and widow: but the way of the wicked he turneth upside down."},{"verse":10,"text":"The Lord shall reign for ever, even thy God, O Zion, unto all generations. Praise ye the Lord. "}]},{"chapter":147,"verses":[{"verse":1,"text":"Praise ye the Lord: for it is good to sing praises unto our God; for it is pleasant; and praise is comely."},{"verse":2,"text":"The Lord doth build up Jerusalem: he gathereth together the outcasts of Israel."},{"verse":3,"text":"He healeth the broken in heart, and bindeth up their wounds."},{"verse":4,"text":"He telleth the number of the stars; he calleth them all by their names."},{"verse":5,"text":"Great is our Lord, and of great power: his understanding is infinite."},{"verse":6,"text":"The Lord lifteth up the meek: he casteth the wicked down to the ground."},{"verse":7,"text":"Sing unto the Lord with thanksgiving; sing praise upon the harp unto our God:"},{"verse":8,"text":"Who covereth the heaven with clouds, who prepareth rain for the earth, who maketh grass to grow upon the mountains."},{"verse":9,"text":"He giveth to the beast his food, and to the young ravens which cry."},{"verse":10,"text":"He delighteth not in the strength of the horse: he taketh not pleasure in the legs of a man."},{"verse":11,"text":"The Lord taketh pleasure in them that fear him, in those that hope in his mercy."},{"verse":12,"text":"Praise the Lord, O Jerusalem; praise thy God, O Zion."},{"verse":13,"text":"For he hath strengthened the bars of thy gates; he hath blessed thy children within thee."},{"verse":14,"text":"He maketh peace in thy borders, and filleth thee with the finest of the wheat."},{"verse":15,"text":"He sendeth forth his commandment upon earth: his word runneth very swiftly."},{"verse":16,"text":"He giveth snow like wool: he scattereth the hoarfrost like ashes."},{"verse":17,"text":"He casteth forth his ice like morsels: who can stand before his cold?"},{"verse":18,"text":"He sendeth out his word, and melteth them: he causeth his wind to blow, and the waters flow."},{"verse":19,"text":"He sheweth his word unto Jacob, his statutes and his judgments unto Israel."},{"verse":20,"text":"He hath not dealt so with any nation: and as for his judgments, they have not known them. Praise ye the Lord. "}]},{"chapter":148,"verses":[{"verse":1,"text":"Praise ye the Lord. Praise ye the Lord from the heavens: praise him in the heights."},{"verse":2,"text":"Praise ye him, all his angels: praise ye him, all his hosts."},{"verse":3,"text":"Praise ye him, sun and moon: praise him, all ye stars of light."},{"verse":4,"text":"Praise him, ye heavens of heavens, and ye waters that be above the heavens."},{"verse":5,"text":"Let them praise the name of the Lord: for he commanded, and they were created."},{"verse":6,"text":"He hath also stablished them for ever and ever: he hath made a decree which shall not pass."},{"verse":7,"text":"Praise the Lord from the earth, ye dragons, and all deeps:"},{"verse":8,"text":"Fire, and hail; snow, and vapour; stormy wind fulfilling his word:"},{"verse":9,"text":"Mountains, and all hills; fruitful trees, and all cedars:"},{"verse":10,"text":"Beasts, and all cattle; creeping things, and flying fowl:"},{"verse":11,"text":"Kings of the earth, and all people; princes, and all judges of the earth:"},{"verse":12,"text":"Both young men, and maidens; old men, and children:"},{"verse":13,"text":"Let them praise the name of the Lord: for his name alone is excellent; his glory is above the earth and heaven."},{"verse":14,"text":"He also exalteth the horn of his people, the praise of all his saints; even of the children of Israel, a people near unto him. Praise ye the Lord. "}]},{"chapter":149,"verses":[{"verse":1,"text":"Praise ye the Lord. Sing unto the Lord a new song, and his praise in the congregation of saints."},{"verse":2,"text":"Let Israel rejoice in him that made him: let the children of Zion be joyful in their King."},{"verse":3,"text":"Let them praise his name in the dance: let them sing praises unto him with the timbrel and harp."},{"verse":4,"text":"For the Lord taketh pleasure in his people: he will beautify the meek with salvation."},{"verse":5,"text":"Let the saints be joyful in glory: let them sing aloud upon their beds."},{"verse":6,"text":"Let the high praises of God be in their mouth, and a twoedged sword in their hand;"},{"verse":7,"text":"To execute vengeance upon the heathen, and punishments upon the people;"},{"verse":8,"text":"To bind their kings with chains, and their nobles with fetters of iron;"},{"verse":9,"text":"To execute upon them the judgment written: this honour have all his saints. Praise ye the Lord. "}]},{"chapter":150,"verses":[{"verse":1,"text":"Praise ye the Lord. Praise God in his sanctuary: praise him in the firmament of his power."},{"verse":2,"text":"Praise him for his mighty acts: praise him according to his excellent greatness."},{"verse":3,"text":"Praise him with the sound of the trumpet: praise him with the psaltery and harp."},{"verse":4,"text":"Praise him with the timbrel and dance: praise him with stringed instruments and organs."},{"verse":5,"text":"Praise him upon the loud cymbals: praise him upon the high sounding cymbals."},{"verse":6,"text":"Let every thing that hath breath praise the Lord. Praise ye the Lord.  "}]}]},{"name":"Proverbs","chapters":[{"chapter":1,"verses":[{"verse":1,"text":"The proverbs of Solomon the son of David, king of Israel;"},{"verse":2,"text":"To know wisdom and instruction; to perceive the words of understanding;"},{"verse":3,"text":"To receive the instruction of wisdom, justice, and judgment, and equity;"},{"verse":4,"text":"To give subtilty to the simple, to the young man knowledge and discretion."},{"verse":5,"text":"A wise man will hear, and will increase learning; and a man of understanding shall attain unto wise counsels:"},{"verse":6,"text":"To understand a proverb, and the interpretation; the words of the wise, and their dark sayings."},{"verse":7,"text":"The fear of the Lord is the beginning of knowledge: but fools despise wisdom and instruction."},{"verse":8,"text":"My son, hear the instruction of thy father, and forsake not the law of thy mother:"},{"verse":9,"text":"For they shall be an ornament of grace unto thy head, and chains about thy neck."},{"verse":10,"text":"My son, if sinners entice thee, consent thou not."},{"verse":11,"text":"If they say, Come with us, let us lay wait for blood, let us lurk privily for the innocent without cause:"},{"verse":12,"text":"Let us swallow them up alive as the grave; and whole, as those that go down into the pit:"},{"verse":13,"text":"We shall find all precious substance, we shall fill our houses with spoil:"},{"verse":14,"text":"Cast in thy lot among us; let us all have one purse:"},{"verse":15,"text":"My son, walk not thou in the way with them; refrain thy foot from their path:"},{"verse":16,"text":"For their feet run to evil, and make haste to shed blood."},{"verse":17,"text":"Surely in vain the net is spread in the sight of any bird."},{"verse":18,"text":"And they lay wait for their own blood; they lurk privily for their own lives."},{"verse":19,"text":"So are the ways of every one that is greedy of gain; which taketh away the life of the owners thereof."},{"verse":20,"text":"Wisdom crieth without; she uttereth her voice in the streets:"},{"verse":21,"text":"She crieth in the chief place of concourse, in the openings of the gates: in the city she uttereth her words, saying,"},{"verse":22,"text":"How long, ye simple ones, will ye love simplicity? and the scorners delight in their scorning, and fools hate knowledge?"},{"verse":23,"text":"Turn you at my reproof: behold, I will pour out my spirit unto you, I will make known my words unto you."},{"verse":24,"text":"Because I have called, and ye refused; I have stretched out my hand, and no man regarded;"},{"verse":25,"text":"But ye have set at nought all my counsel, and would none of my reproof:"},{"verse":26,"text":"I also will laugh at your calamity; I will mock when your fear cometh;"},{"verse":27,"text":"When your fear cometh as desolation, and your destruction cometh as a whirlwind; when distress and anguish cometh upon you."},{"verse":28,"text":"Then shall they call upon me, but I will not answer; they shall seek me early, but they shall not find me:"},{"verse":29,"text":"For that they hated knowledge, and did not choose the fear of the Lord:"},{"verse":30,"text":"They would none of my counsel: they despised all my reproof."},{"verse":31,"text":"Therefore shall they eat of the fruit of their own way, and be filled with their own devices."},{"verse":32,"text":"For the turning away of the simple shall slay them, and the prosperity of fools shall destroy them."},{"verse":33,"text":"But whoso hearkeneth unto me shall dwell safely, and shall be quiet from fear of evil. "}]},{"chapter":2,"verses":[{"verse":1,"text":"My son, if thou wilt receive my words, and hide my commandments with thee;"},{"verse":2,"text":"So that thou incline thine ear unto wisdom, and apply thine heart to understanding;"},{"verse":3,"text":"Yea, if thou criest after knowledge, and liftest up thy voice for understanding;"},{"verse":4,"text":"If thou seekest her as silver, and searchest for her as for hid treasures;"},{"verse":5,"text":"Then shalt thou understand the fear of the Lord, and find the knowledge of God."},{"verse":6,"text":"For the Lord giveth wisdom: out of his mouth cometh knowledge and understanding."},{"verse":7,"text":"He layeth up sound wisdom for the righteous: he is a buckler to them that walk uprightly."},{"verse":8,"text":"He keepeth the paths of judgment, and preserveth the way of his saints."},{"verse":9,"text":"Then shalt thou understand righteousness, and judgment, and equity; yea, every good path."},{"verse":10,"text":"When wisdom entereth into thine heart, and knowledge is pleasant unto thy soul;"},{"verse":11,"text":"Discretion shall preserve thee, understanding shall keep thee:"},{"verse":12,"text":"To deliver thee from the way of the evil man, from the man that speaketh froward things;"},{"verse":13,"text":"Who leave the paths of uprightness, to walk in the ways of darkness;"},{"verse":14,"text":"Who rejoice to do evil, and delight in the frowardness of the wicked;"},{"verse":15,"text":"Whose ways are crooked, and they froward in their paths:"},{"verse":16,"text":"To deliver thee from the strange woman, even from the stranger which flattereth with her words;"},{"verse":17,"text":"Which forsaketh the guide of her youth, and forgetteth the covenant of her God."},{"verse":18,"text":"For her house inclineth unto death, and her paths unto the dead."},{"verse":19,"text":"None that go unto her return again, neither take they hold of the paths of life."},{"verse":20,"text":"That thou mayest walk in the way of good men, and keep the paths of the righteous."},{"verse":21,"text":"For the upright shall dwell in the land, and the perfect shall remain in it."},{"verse":22,"text":"But the wicked shall be cut off from the earth, and the transgressors shall be rooted out of it. "}]},{"chapter":3,"verses":[{"verse":1,"text":"My son, forget not my law; but let thine heart keep my commandments:"},{"verse":2,"text":"For length of days, and long life, and peace, shall they add to thee."},{"verse":3,"text":"Let not mercy and truth forsake thee: bind them about thy neck; write them upon the table of thine heart:"},{"verse":4,"text":"So shalt thou find favour and good understanding in the sight of God and man."},{"verse":5,"text":"Trust in the Lord with all thine heart; and lean not unto thine own understanding."},{"verse":6,"text":"In all thy ways acknowledge him, and he shall direct thy paths."},{"verse":7,"text":"Be not wise in thine own eyes: fear the Lord, and depart from evil."},{"verse":8,"text":"It shall be health to thy navel, and marrow to thy bones."},{"verse":9,"text":"Honour the Lord with thy substance, and with the firstfruits of all thine increase:"},{"verse":10,"text":"So shall thy barns be filled with plenty, and thy presses shall burst out with new wine."},{"verse":11,"text":"My son, despise not the chastening of the Lord; neither be weary of his correction:"},{"verse":12,"text":"For whom the Lord loveth he correcteth; even as a father the son in whom he delighteth."},{"verse":13,"text":"Happy is the man that findeth wisdom, and the man that getteth understanding."},{"verse":14,"text":"For the merchandise of it is better than the merchandise of silver, and the gain thereof than fine gold."},{"verse":15,"text":"She is more precious than rubies: and all the things thou canst desire are not to be compared unto her."},{"verse":16,"text":"Length of days is in her right hand; and in her left hand riches and honour."},{"verse":17,"text":"Her ways are ways of pleasantness, and all her paths are peace."},{"verse":18,"text":"She is a tree of life to them that lay hold upon her: and happy is every one that retaineth her."},{"verse":19,"text":"The Lord by wisdom hath founded the earth; by understanding hath he established the heavens."},{"verse":20,"text":"By his knowledge the depths are broken up, and the clouds drop down the dew."},{"verse":21,"text":"My son, let not them depart from thine eyes: keep sound wisdom and discretion:"},{"verse":22,"text":"So shall they be life unto thy soul, and grace to thy neck."},{"verse":23,"text":"Then shalt thou walk in thy way safely, and thy foot shall not stumble."},{"verse":24,"text":"When thou liest down, thou shalt not be afraid: yea, thou shalt lie down, and thy sleep shall be sweet."},{"verse":25,"text":"Be not afraid of sudden fear, neither of the desolation of the wicked, when it cometh."},{"verse":26,"text":"For the Lord shall be thy confidence, and shall keep thy foot from being taken."},{"verse":27,"text":"Withhold not good from them to whom it is due, when it is in the power of thine hand to do it."},{"verse":28,"text":"Say not unto thy neighbour, Go, and come again, and to morrow I will give; when thou hast it by thee."},{"verse":29,"text":"Devise not evil against thy neighbour, seeing he dwelleth securely by thee."},{"verse":30,"text":"Strive not with a man without cause, if he have done thee no harm."},{"verse":31,"text":"Envy thou not the oppressor, and choose none of his ways."},{"verse":32,"text":"For the froward is abomination to the Lord: but his secret is with the righteous."},{"verse":33,"text":"The curse of the Lord is in the house of the wicked: but he blesseth the habitation of the just."},{"verse":34,"text":"Surely he scorneth the scorners: but he giveth grace unto the lowly."},{"verse":35,"text":"The wise shall inherit glory: but shame shall be the promotion of fools. "}]},{"chapter":4,"verses":[{"verse":1,"text":"Hear, ye children, the instruction of a father, and attend to know understanding."},{"verse":2,"text":"For I give you good doctrine, forsake ye not my law."},{"verse":3,"text":"For I was my father’s son, tender and only beloved in the sight of my mother."},{"verse":4,"text":"He taught me also, and said unto me, Let thine heart retain my words: keep my commandments, and live."},{"verse":5,"text":"Get wisdom, get understanding: forget it not; neither decline from the words of my mouth."},{"verse":6,"text":"Forsake her not, and she shall preserve thee: love her, and she shall keep thee."},{"verse":7,"text":"Wisdom is the principal thing; therefore get wisdom: and with all thy getting get understanding."},{"verse":8,"text":"Exalt her, and she shall promote thee: she shall bring thee to honour, when thou dost embrace her."},{"verse":9,"text":"She shall give to thine head an ornament of grace: a crown of glory shall she deliver to thee."},{"verse":10,"text":"Hear, O my son, and receive my sayings; and the years of thy life shall be many."},{"verse":11,"text":"I have taught thee in the way of wisdom; I have led thee in right paths."},{"verse":12,"text":"When thou goest, thy steps shall not be straitened; and when thou runnest, thou shalt not stumble."},{"verse":13,"text":"Take fast hold of instruction; let her not go: keep her; for she is thy life."},{"verse":14,"text":"Enter not into the path of the wicked, and go not in the way of evil men."},{"verse":15,"text":"Avoid it, pass not by it, turn from it, and pass away."},{"verse":16,"text":"For they sleep not, except they have done mischief; and their sleep is taken away, unless they cause some to fall."},{"verse":17,"text":"For they eat the bread of wickedness, and drink the wine of violence."},{"verse":18,"text":"But the path of the just is as the shining light, that shineth more and more unto the perfect day."},{"verse":19,"text":"The way of the wicked is as darkness: they know not at what they stumble."},{"verse":20,"text":"My son, attend to my words; incline thine ear unto my sayings."},{"verse":21,"text":"Let them not depart from thine eyes; keep them in the midst of thine heart."},{"verse":22,"text":"For they are life unto those that find them, and health to all their flesh."},{"verse":23,"text":"Keep thy heart with all diligence; for out of it are the issues of life."},{"verse":24,"text":"Put away from thee a froward mouth, and perverse lips put far from thee."},{"verse":25,"text":"Let thine eyes look right on, and let thine eyelids look straight before thee."},{"verse":26,"text":"Ponder the path of thy feet, and let all thy ways be established."},{"verse":27,"text":"Turn not to the right hand nor to the left: remove thy foot from evil. "}]},{"chapter":5,"verses":[{"verse":1,"text":"My son, attend unto my wisdom, and bow thine ear to my understanding:"},{"verse":2,"text":"That thou mayest regard discretion, and that thy lips may keep knowledge."},{"verse":3,"text":"For the lips of a strange woman drop as an honeycomb, and her mouth is smoother than oil:"},{"verse":4,"text":"But her end is bitter as wormwood, sharp as a twoedged sword."},{"verse":5,"text":"Her feet go down to death; her steps take hold on hell."},{"verse":6,"text":"Lest thou shouldest ponder the path of life, her ways are moveable, that thou canst not know them."},{"verse":7,"text":"Hear me now therefore, O ye children, and depart not from the words of my mouth."},{"verse":8,"text":"Remove thy way far from her, and come not nigh the door of her house:"},{"verse":9,"text":"Lest thou give thine honour unto others, and thy years unto the cruel:"},{"verse":10,"text":"Lest strangers be filled with thy wealth; and thy labours be in the house of a stranger;"},{"verse":11,"text":"And thou mourn at the last, when thy flesh and thy body are consumed,"},{"verse":12,"text":"And say, How have I hated instruction, and my heart despised reproof;"},{"verse":13,"text":"And have not obeyed the voice of my teachers, nor inclined mine ear to them that instructed me!"},{"verse":14,"text":"I was almost in all evil in the midst of the congregation and assembly."},{"verse":15,"text":"Drink waters out of thine own cistern, and running waters out of thine own well."},{"verse":16,"text":"Let thy fountains be dispersed abroad, and rivers of waters in the streets."},{"verse":17,"text":"Let them be only thine own, and not strangers’ with thee."},{"verse":18,"text":"Let thy fountain be blessed: and rejoice with the wife of thy youth."},{"verse":19,"text":"Let her be as the loving hind and pleasant roe; let her breasts satisfy thee at all times; and be thou ravished always with her love."},{"verse":20,"text":"And why wilt thou, my son, be ravished with a strange woman, and embrace the bosom of a stranger?"},{"verse":21,"text":"For the ways of man are before the eyes of the Lord, and he pondereth all his goings."},{"verse":22,"text":"His own iniquities shall take the wicked himself, and he shall be holden with the cords of his sins."},{"verse":23,"text":"He shall die without instruction; and in the greatness of his folly he shall go astray. "}]},{"chapter":6,"verses":[{"verse":1,"text":"My son, if thou be surety for thy friend, if thou hast stricken thy hand with a stranger,"},{"verse":2,"text":"Thou art snared with the words of thy mouth, thou art taken with the words of thy mouth."},{"verse":3,"text":"Do this now, my son, and deliver thyself, when thou art come into the hand of thy friend; go, humble thyself, and make sure thy friend."},{"verse":4,"text":"Give not sleep to thine eyes, nor slumber to thine eyelids."},{"verse":5,"text":"Deliver thyself as a roe from the hand of the hunter, and as a bird from the hand of the fowler."},{"verse":6,"text":"Go to the ant, thou sluggard; consider her ways, and be wise:"},{"verse":7,"text":"Which having no guide, overseer, or ruler,"},{"verse":8,"text":"Provideth her meat in the summer, and gathereth her food in the harvest."},{"verse":9,"text":"How long wilt thou sleep, O sluggard? when wilt thou arise out of thy sleep?"},{"verse":10,"text":"Yet a little sleep, a little slumber, a little folding of the hands to sleep:"},{"verse":11,"text":"So shall thy poverty come as one that travelleth, and thy want as an armed man."},{"verse":12,"text":"A naughty person, a wicked man, walketh with a froward mouth."},{"verse":13,"text":"He winketh with his eyes, he speaketh with his feet, he teacheth with his fingers;"},{"verse":14,"text":"Frowardness is in his heart, he deviseth mischief continually; he soweth discord."},{"verse":15,"text":"Therefore shall his calamity come suddenly; suddenly shall he be broken without remedy."},{"verse":16,"text":"These six things doth the Lord hate: yea, seven are an abomination unto him:"},{"verse":17,"text":"A proud look, a lying tongue, and hands that shed innocent blood,"},{"verse":18,"text":"An heart that deviseth wicked imaginations, feet that be swift in running to mischief,"},{"verse":19,"text":"A false witness that speaketh lies, and he that soweth discord among brethren."},{"verse":20,"text":"My son, keep thy father’s commandment, and forsake not the law of thy mother:"},{"verse":21,"text":"Bind them continually upon thine heart, and tie them about thy neck."},{"verse":22,"text":"When thou goest, it shall lead thee; when thou sleepest, it shall keep thee; and when thou awakest, it shall talk with thee."},{"verse":23,"text":"For the commandment is a lamp; and the law is light; and reproofs of instruction are the way of life:"},{"verse":24,"text":"To keep thee from the evil woman, from the flattery of the tongue of a strange woman."},{"verse":25,"text":"Lust not after her beauty in thine heart; neither let her take thee with her eyelids."},{"verse":26,"text":"For by means of a whorish woman a man is brought to a piece of bread: and the adulteress will hunt for the precious life."},{"verse":27,"text":"Can a man take fire in his bosom, and his clothes not be burned?"},{"verse":28,"text":"Can one go upon hot coals, and his feet not be burned?"},{"verse":29,"text":"So he that goeth in to his neighbour’s wife; whosoever toucheth her shall not be innocent."},{"verse":30,"text":"Men do not despise a thief, if he steal to satisfy his soul when he is hungry;"},{"verse":31,"text":"But if he be found, he shall restore sevenfold; he shall give all the substance of his house."},{"verse":32,"text":"But whoso committeth adultery with a woman lacketh understanding: he that doeth it destroyeth his own soul."},{"verse":33,"text":"A wound and dishonour shall he get; and his reproach shall not be wiped away."},{"verse":34,"text":"For jealousy is the rage of a man: therefore he will not spare in the day of vengeance."},{"verse":35,"text":"He will not regard any ransom; neither will he rest content, though thou givest many gifts. "}]},{"chapter":7,"verses":[{"verse":1,"text":"My son, keep my words, and lay up my commandments with thee."},{"verse":2,"text":"Keep my commandments, and live; and my law as the apple of thine eye."},{"verse":3,"text":"Bind them upon thy fingers, write them upon the table of thine heart."},{"verse":4,"text":"Say unto wisdom, Thou art my sister; and call understanding thy kinswoman:"},{"verse":5,"text":"That they may keep thee from the strange woman, from the stranger which flattereth with her words."},{"verse":6,"text":"For at the window of my house I looked through my casement,"},{"verse":7,"text":"And beheld among the simple ones, I discerned among the youths, a young man void of understanding,"},{"verse":8,"text":"Passing through the street near her corner; and he went the way to her house,"},{"verse":9,"text":"In the twilight, in the evening, in the black and dark night:"},{"verse":10,"text":"And, behold, there met him a woman with the attire of an harlot, and subtil of heart."},{"verse":11,"text":"(She is loud and stubborn; her feet abide not in her house:"},{"verse":12,"text":"Now is she without, now in the streets, and lieth in wait at every corner.)"},{"verse":13,"text":"So she caught him, and kissed him, and with an impudent face said unto him,"},{"verse":14,"text":"I have peace offerings with me; this day have I payed my vows."},{"verse":15,"text":"Therefore came I forth to meet thee, diligently to seek thy face, and I have found thee."},{"verse":16,"text":"I have decked my bed with coverings of tapestry, with carved works, with fine linen of Egypt."},{"verse":17,"text":"I have perfumed my bed with myrrh, aloes, and cinnamon."},{"verse":18,"text":"Come, let us take our fill of love until the morning: let us solace ourselves with loves."},{"verse":19,"text":"For the goodman is not at home, he is gone a long journey:"},{"verse":20,"text":"He hath taken a bag of money with him, and will come home at the day appointed."},{"verse":21,"text":"With her much fair speech she caused him to yield, with the flattering of her lips she forced him."},{"verse":22,"text":"He goeth after her straightway, as an ox goeth to the slaughter, or as a fool to the correction of the stocks;"},{"verse":23,"text":"Till a dart strike through his liver; as a bird hasteth to the snare, and knoweth not that it is for his life."},{"verse":24,"text":"Hearken unto me now therefore, O ye children, and attend to the words of my mouth."},{"verse":25,"text":"Let not thine heart decline to her ways, go not astray in her paths."},{"verse":26,"text":"For she hath cast down many wounded: yea, many strong men have been slain by her."},{"verse":27,"text":"Her house is the way to hell, going down to the chambers of death. "}]},{"chapter":8,"verses":[{"verse":1,"text":"Doth not wisdom cry? and understanding put forth her voice?"},{"verse":2,"text":"She standeth in the top of high places, by the way in the places of the paths."},{"verse":3,"text":"She crieth at the gates, at the entry of the city, at the coming in at the doors."},{"verse":4,"text":"Unto you, O men, I call; and my voice is to the sons of man."},{"verse":5,"text":"O ye simple, understand wisdom: and, ye fools, be ye of an understanding heart."},{"verse":6,"text":"Hear; for I will speak of excellent things; and the opening of my lips shall be right things."},{"verse":7,"text":"For my mouth shall speak truth; and wickedness is an abomination to my lips."},{"verse":8,"text":"All the words of my mouth are in righteousness; there is nothing froward or perverse in them."},{"verse":9,"text":"They are all plain to him that understandeth, and right to them that find knowledge."},{"verse":10,"text":"Receive my instruction, and not silver; and knowledge rather than choice gold."},{"verse":11,"text":"For wisdom is better than rubies; and all the things that may be desired are not to be compared to it."},{"verse":12,"text":"I wisdom dwell with prudence, and find out knowledge of witty inventions."},{"verse":13,"text":"The fear of the Lord is to hate evil: pride, and arrogancy, and the evil way, and the froward mouth, do I hate."},{"verse":14,"text":"Counsel is mine, and sound wisdom: I am understanding; I have strength."},{"verse":15,"text":"By me kings reign, and princes decree justice."},{"verse":16,"text":"By me princes rule, and nobles, even all the judges of the earth."},{"verse":17,"text":"I love them that love me; and those that seek me early shall find me."},{"verse":18,"text":"Riches and honour are with me; yea, durable riches and righteousness."},{"verse":19,"text":"My fruit is better than gold, yea, than fine gold; and my revenue than choice silver."},{"verse":20,"text":"I lead in the way of righteousness, in the midst of the paths of judgment:"},{"verse":21,"text":"That I may cause those that love me to inherit substance; and I will fill their treasures."},{"verse":22,"text":"The Lord possessed me in the beginning of his way, before his works of old."},{"verse":23,"text":"I was set up from everlasting, from the beginning, or ever the earth was."},{"verse":24,"text":"When there were no depths, I was brought forth; when there were no fountains abounding with water."},{"verse":25,"text":"Before the mountains were settled, before the hills was I brought forth:"},{"verse":26,"text":"While as yet he had not made the earth, nor the fields, nor the highest part of the dust of the world."},{"verse":27,"text":"When he prepared the heavens, I was there: when he set a compass upon the face of the depth:"},{"verse":28,"text":"When he established the clouds above: when he strengthened the fountains of the deep:"},{"verse":29,"text":"When he gave to the sea his decree, that the waters should not pass his commandment: when he appointed the foundations of the earth:"},{"verse":30,"text":"Then I was by him, as one brought up with him: and I was daily his delight, rejoicing always before him;"},{"verse":31,"text":"Rejoicing in the habitable part of his earth; and my delights were with the sons of men."},{"verse":32,"text":"Now therefore hearken unto me, O ye children: for blessed are they that keep my ways."},{"verse":33,"text":"Hear instruction, and be wise, and refuse it not."},{"verse":34,"text":"Blessed is the man that heareth me, watching daily at my gates, waiting at the posts of my doors."},{"verse":35,"text":"For whoso findeth me findeth life, and shall obtain favour of the Lord."},{"verse":36,"text":"But he that sinneth against me wrongeth his own soul: all they that hate me love death. "}]},{"chapter":9,"verses":[{"verse":1,"text":"Wisdom hath builded her house, she hath hewn out her seven pillars:"},{"verse":2,"text":"She hath killed her beasts; she hath mingled her wine; she hath also furnished her table."},{"verse":3,"text":"She hath sent forth her maidens: she crieth upon the highest places of the city,"},{"verse":4,"text":"Whoso is simple, let him turn in hither: as for him that wanteth understanding, she saith to him,"},{"verse":5,"text":"Come, eat of my bread, and drink of the wine which I have mingled."},{"verse":6,"text":"Forsake the foolish, and live; and go in the way of understanding."},{"verse":7,"text":"He that reproveth a scorner getteth to himself shame: and he that rebuketh a wicked man getteth himself a blot."},{"verse":8,"text":"Reprove not a scorner, lest he hate thee: rebuke a wise man, and he will love thee."},{"verse":9,"text":"Give instruction to a wise man, and he will be yet wiser: teach a just man, and he will increase in learning."},{"verse":10,"text":"The fear of the Lord is the beginning of wisdom: and the knowledge of the holy is understanding."},{"verse":11,"text":"For by me thy days shall be multiplied, and the years of thy life shall be increased."},{"verse":12,"text":"If thou be wise, thou shalt be wise for thyself: but if thou scornest, thou alone shalt bear it."},{"verse":13,"text":"A foolish woman is clamorous: she is simple, and knoweth nothing."},{"verse":14,"text":"For she sitteth at the door of her house, on a seat in the high places of the city,"},{"verse":15,"text":"To call passengers who go right on their ways:"},{"verse":16,"text":"Whoso is simple, let him turn in hither: and as for him that wanteth understanding, she saith to him,"},{"verse":17,"text":"Stolen waters are sweet, and bread eaten in secret is pleasant."},{"verse":18,"text":"But he knoweth not that the dead are there; and that her guests are in the depths of hell. "}]},{"chapter":10,"verses":[{"verse":1,"text":"The proverbs of Solomon. A wise son maketh a glad father: but a foolish son is the heaviness of his mother."},{"verse":2,"text":"Treasures of wickedness profit nothing: but righteousness delivereth from death."},{"verse":3,"text":"The Lord will not suffer the soul of the righteous to famish: but he casteth away the substance of the wicked."},{"verse":4,"text":"He becometh poor that dealeth with a slack hand: but the hand of the diligent maketh rich."},{"verse":5,"text":"He that gathereth in summer is a wise son: but he that sleepeth in harvest is a son that causeth shame."},{"verse":6,"text":"Blessings are upon the head of the just: but violence covereth the mouth of the wicked."},{"verse":7,"text":"The memory of the just is blessed: but the name of the wicked shall rot."},{"verse":8,"text":"The wise in heart will receive commandments: but a prating fool shall fall."},{"verse":9,"text":"He that walketh uprightly walketh surely: but he that perverteth his ways shall be known."},{"verse":10,"text":"He that winketh with the eye causeth sorrow: but a prating fool shall fall."},{"verse":11,"text":"The mouth of a righteous man is a well of life: but violence covereth the mouth of the wicked."},{"verse":12,"text":"Hatred stirreth up strifes: but love covereth all sins."},{"verse":13,"text":"In the lips of him that hath understanding wisdom is found: but a rod is for the back of him that is void of understanding."},{"verse":14,"text":"Wise men lay up knowledge: but the mouth of the foolish is near destruction."},{"verse":15,"text":"The rich man’s wealth is his strong city: the destruction of the poor is their poverty."},{"verse":16,"text":"The labour of the righteous tendeth to life: the fruit of the wicked to sin."},{"verse":17,"text":"He is in the way of life that keepeth instruction: but he that refuseth reproof erreth."},{"verse":18,"text":"He that hideth hatred with lying lips, and he that uttereth a slander, is a fool."},{"verse":19,"text":"In the multitude of words there wanteth not sin: but he that refraineth his lips is wise."},{"verse":20,"text":"The tongue of the just is as choice silver: the heart of the wicked is little worth."},{"verse":21,"text":"The lips of the righteous feed many: but fools die for want of wisdom."},{"verse":22,"text":"The blessing of the Lord, it maketh rich, and he addeth no sorrow with it."},{"verse":23,"text":"It is as sport to a fool to do mischief: but a man of understanding hath wisdom."},{"verse":24,"text":"The fear of the wicked, it shall come upon him: but the desire of the righteous shall be granted."},{"verse":25,"text":"As the whirlwind passeth, so is the wicked no more: but the righteous is an everlasting foundation."},{"verse":26,"text":"As vinegar to the teeth, and as smoke to the eyes, so is the sluggard to them that send him."},{"verse":27,"text":"The fear of the Lord prolongeth days: but the years of the wicked shall be shortened."},{"verse":28,"text":"The hope of the righteous shall be gladness: but the expectation of the wicked shall perish."},{"verse":29,"text":"The way of the Lord is strength to the upright: but destruction shall be to the workers of iniquity."},{"verse":30,"text":"The righteous shall never be removed: but the wicked shall not inhabit the earth."},{"verse":31,"text":"The mouth of the just bringeth forth wisdom: but the froward tongue shall be cut out."},{"verse":32,"text":"The lips of the righteous know what is acceptable: but the mouth of the wicked speaketh frowardness. "}]},{"chapter":11,"verses":[{"verse":1,"text":"A false balance is abomination to the Lord: but a just weight is his delight."},{"verse":2,"text":"When pride cometh, then cometh shame: but with the lowly is wisdom."},{"verse":3,"text":"The integrity of the upright shall guide them: but the perverseness of transgressors shall destroy them."},{"verse":4,"text":"Riches profit not in the day of wrath: but righteousness delivereth from death."},{"verse":5,"text":"The righteousness of the perfect shall direct his way: but the wicked shall fall by his own wickedness."},{"verse":6,"text":"The righteousness of the upright shall deliver them: but transgressors shall be taken in their own naughtiness."},{"verse":7,"text":"When a wicked man dieth, his expectation shall perish: and the hope of unjust men perisheth."},{"verse":8,"text":"The righteous is delivered out of trouble, and the wicked cometh in his stead."},{"verse":9,"text":"An hypocrite with his mouth destroyeth his neighbour: but through knowledge shall the just be delivered."},{"verse":10,"text":"When it goeth well with the righteous, the city rejoiceth: and when the wicked perish, there is shouting."},{"verse":11,"text":"By the blessing of the upright the city is exalted: but it is overthrown by the mouth of the wicked."},{"verse":12,"text":"He that is void of wisdom despiseth his neighbour: but a man of understanding holdeth his peace."},{"verse":13,"text":"A talebearer revealeth secrets: but he that is of a faithful spirit concealeth the matter."},{"verse":14,"text":"Where no counsel is, the people fall: but in the multitude of counsellors there is safety."},{"verse":15,"text":"He that is surety for a stranger shall smart for it: and he that hateth suretiship is sure."},{"verse":16,"text":"A gracious woman retaineth honour: and strong men retain riches."},{"verse":17,"text":"The merciful man doeth good to his own soul: but he that is cruel troubleth his own flesh."},{"verse":18,"text":"The wicked worketh a deceitful work: but to him that soweth righteousness shall be a sure reward."},{"verse":19,"text":"As righteousness tendeth to life: so he that pursueth evil pursueth it to his own death."},{"verse":20,"text":"They that are of a froward heart are abomination to the Lord: but such as are upright in their way are his delight."},{"verse":21,"text":"Though hand join in hand, the wicked shall not be unpunished: but the seed of the righteous shall be delivered."},{"verse":22,"text":"As a jewel of gold in a swine’s snout, so is a fair woman which is without discretion."},{"verse":23,"text":"The desire of the righteous is only good: but the expectation of the wicked is wrath."},{"verse":24,"text":"There is that scattereth, and yet increaseth; and there is that withholdeth more than is meet, but it tendeth to poverty."},{"verse":25,"text":"The liberal soul shall be made fat: and he that watereth shall be watered also himself."},{"verse":26,"text":"He that withholdeth corn, the people shall curse him: but blessing shall be upon the head of him that selleth it."},{"verse":27,"text":"He that diligently seeketh good procureth favour: but he that seeketh mischief, it shall come unto him."},{"verse":28,"text":"He that trusteth in his riches shall fall: but the righteous shall flourish as a branch."},{"verse":29,"text":"He that troubleth his own house shall inherit the wind: and the fool shall be servant to the wise of heart."},{"verse":30,"text":"The fruit of the righteous is a tree of life; and he that winneth souls is wise."},{"verse":31,"text":"Behold, the righteous shall be recompensed in the earth: much more the wicked and the sinner. "}]},{"chapter":12,"verses":[{"verse":1,"text":"Whoso loveth instruction loveth knowledge: but he that hateth reproof is brutish."},{"verse":2,"text":"A good man obtaineth favour of the Lord: but a man of wicked devices will he condemn."},{"verse":3,"text":"A man shall not be established by wickedness: but the root of the righteous shall not be moved."},{"verse":4,"text":"A virtuous woman is a crown to her husband: but she that maketh ashamed is as rottenness in his bones."},{"verse":5,"text":"The thoughts of the righteous are right: but the counsels of the wicked are deceit."},{"verse":6,"text":"The words of the wicked are to lie in wait for blood: but the mouth of the upright shall deliver them."},{"verse":7,"text":"The wicked are overthrown, and are not: but the house of the righteous shall stand."},{"verse":8,"text":"A man shall be commended according to his wisdom: but he that is of a perverse heart shall be despised."},{"verse":9,"text":"He that is despised, and hath a servant, is better than he that honoureth himself, and lacketh bread."},{"verse":10,"text":"A righteous man regardeth the life of his beast: but the tender mercies of the wicked are cruel."},{"verse":11,"text":"He that tilleth his land shall be satisfied with bread: but he that followeth vain persons is void of understanding."},{"verse":12,"text":"The wicked desireth the net of evil men: but the root of the righteous yieldeth fruit."},{"verse":13,"text":"The wicked is snared by the transgression of his lips: but the just shall come out of trouble."},{"verse":14,"text":"A man shall be satisfied with good by the fruit of his mouth: and the recompence of a man’s hands shall be rendered unto him."},{"verse":15,"text":"The way of a fool is right in his own eyes: but he that hearkeneth unto counsel is wise."},{"verse":16,"text":"A fool’s wrath is presently known: but a prudent man covereth shame."},{"verse":17,"text":"He that speaketh truth sheweth forth righteousness: but a false witness deceit."},{"verse":18,"text":"There is that speaketh like the piercings of a sword: but the tongue of the wise is health."},{"verse":19,"text":"The lip of truth shall be established for ever: but a lying tongue is but for a moment."},{"verse":20,"text":"Deceit is in the heart of them that imagine evil: but to the counsellors of peace is joy."},{"verse":21,"text":"There shall no evil happen to the just: but the wicked shall be filled with mischief."},{"verse":22,"text":"Lying lips are abomination to the Lord: but they that deal truly are his delight."},{"verse":23,"text":"A prudent man concealeth knowledge: but the heart of fools proclaimeth foolishness."},{"verse":24,"text":"The hand of the diligent shall bear rule: but the slothful shall be under tribute."},{"verse":25,"text":"Heaviness in the heart of man maketh it stoop: but a good word maketh it glad."},{"verse":26,"text":"The righteous is more excellent than his neighbour: but the way of the wicked seduceth them."},{"verse":27,"text":"The slothful man roasteth not that which he took in hunting: but the substance of a diligent man is precious."},{"verse":28,"text":"In the way of righteousness is life; and in the pathway thereof there is no death. "}]},{"chapter":13,"verses":[{"verse":1,"text":"A wise son heareth his father’s instruction: but a scorner heareth not rebuke."},{"verse":2,"text":"A man shall eat good by the fruit of his mouth: but the soul of the transgressors shall eat violence."},{"verse":3,"text":"He that keepeth his mouth keepeth his life: but he that openeth wide his lips shall have destruction."},{"verse":4,"text":"The soul of the sluggard desireth, and hath nothing: but the soul of the diligent shall be made fat."},{"verse":5,"text":"A righteous man hateth lying: but a wicked man is loathsome, and cometh to shame."},{"verse":6,"text":"Righteousness keepeth him that is upright in the way: but wickedness overthroweth the sinner."},{"verse":7,"text":"There is that maketh himself rich, yet hath nothing: there is that maketh himself poor, yet hath great riches."},{"verse":8,"text":"The ransom of a man’s life are his riches: but the poor heareth not rebuke."},{"verse":9,"text":"The light of the righteous rejoiceth: but the lamp of the wicked shall be put out."},{"verse":10,"text":"Only by pride cometh contention: but with the well advised is wisdom."},{"verse":11,"text":"Wealth gotten by vanity shall be diminished: but he that gathereth by labour shall increase."},{"verse":12,"text":"Hope deferred maketh the heart sick: but when the desire cometh, it is a tree of life."},{"verse":13,"text":"Whoso despiseth the word shall be destroyed: but he that feareth the commandment shall be rewarded."},{"verse":14,"text":"The law of the wise is a fountain of life, to depart from the snares of death."},{"verse":15,"text":"Good understanding giveth favour: but the way of transgressors is hard."},{"verse":16,"text":"Every prudent man dealeth with knowledge: but a fool layeth open his folly."},{"verse":17,"text":"A wicked messenger falleth into mischief: but a faithful ambassador is health."},{"verse":18,"text":"Poverty and shame shall be to him that refuseth instruction: but he that regardeth reproof shall be honoured."},{"verse":19,"text":"The desire accomplished is sweet to the soul: but it is abomination to fools to depart from evil."},{"verse":20,"text":"He that walketh with wise men shall be wise: but a companion of fools shall be destroyed."},{"verse":21,"text":"Evil pursueth sinners: but to the righteous good shall be repayed."},{"verse":22,"text":"A good man leaveth an inheritance to his children’s children: and the wealth of the sinner is laid up for the just."},{"verse":23,"text":"Much food is in the tillage of the poor: but there is that is destroyed for want of judgment."},{"verse":24,"text":"He that spareth his rod hateth his son: but he that loveth him chasteneth him betimes."},{"verse":25,"text":"The righteous eateth to the satisfying of his soul: but the belly of the wicked shall want. "}]},{"chapter":14,"verses":[{"verse":1,"text":"Every wise woman buildeth her house: but the foolish plucketh it down with her hands."},{"verse":2,"text":"He that walketh in his uprightness feareth the Lord: but he that is perverse in his ways despiseth him."},{"verse":3,"text":"In the mouth of the foolish is a rod of pride: but the lips of the wise shall preserve them."},{"verse":4,"text":"Where no oxen are, the crib is clean: but much increase is by the strength of the ox."},{"verse":5,"text":"A faithful witness will not lie: but a false witness will utter lies."},{"verse":6,"text":"A scorner seeketh wisdom, and findeth it not: but knowledge is easy unto him that understandeth."},{"verse":7,"text":"Go from the presence of a foolish man, when thou perceivest not in him the lips of knowledge."},{"verse":8,"text":"The wisdom of the prudent is to understand his way: but the folly of fools is deceit."},{"verse":9,"text":"Fools make a mock at sin: but among the righteous there is favour."},{"verse":10,"text":"The heart knoweth his own bitterness; and a stranger doth not intermeddle with his joy."},{"verse":11,"text":"The house of the wicked shall be overthrown: but the tabernacle of the upright shall flourish."},{"verse":12,"text":"There is a way which seemeth right unto a man, but the end thereof are the ways of death."},{"verse":13,"text":"Even in laughter the heart is sorrowful; and the end of that mirth is heaviness."},{"verse":14,"text":"The backslider in heart shall be filled with his own ways: and a good man shall be satisfied from himself."},{"verse":15,"text":"The simple believeth every word: but the prudent man looketh well to his going."},{"verse":16,"text":"A wise man feareth, and departeth from evil: but the fool rageth, and is confident."},{"verse":17,"text":"He that is soon angry dealeth foolishly: and a man of wicked devices is hated."},{"verse":18,"text":"The simple inherit folly: but the prudent are crowned with knowledge."},{"verse":19,"text":"The evil bow before the good; and the wicked at the gates of the righteous."},{"verse":20,"text":"The poor is hated even of his own neighbour: but the rich hath many friends."},{"verse":21,"text":"He that despiseth his neighbour sinneth: but he that hath mercy on the poor, happy is he."},{"verse":22,"text":"Do they not err that devise evil? but mercy and truth shall be to them that devise good."},{"verse":23,"text":"In all labour there is profit: but the talk of the lips tendeth only to penury."},{"verse":24,"text":"The crown of the wise is their riches: but the foolishness of fools is folly."},{"verse":25,"text":"A true witness delivereth souls: but a deceitful witness speaketh lies."},{"verse":26,"text":"In the fear of the Lord is strong confidence: and his children shall have a place of refuge."},{"verse":27,"text":"The fear of the Lord is a fountain of life, to depart from the snares of death."},{"verse":28,"text":"In the multitude of people is the king’s honour: but in the want of people is the destruction of the prince."},{"verse":29,"text":"He that is slow to wrath is of great understanding: but he that is hasty of spirit exalteth folly."},{"verse":30,"text":"A sound heart is the life of the flesh: but envy the rottenness of the bones."},{"verse":31,"text":"He that oppresseth the poor reproacheth his Maker: but he that honoureth him hath mercy on the poor."},{"verse":32,"text":"The wicked is driven away in his wickedness: but the righteous hath hope in his death."},{"verse":33,"text":"Wisdom resteth in the heart of him that hath understanding: but that which is in the midst of fools is made known."},{"verse":34,"text":"Righteousness exalteth a nation: but sin is a reproach to any people."},{"verse":35,"text":"The king’s favour is toward a wise servant: but his wrath is against him that causeth shame. "}]},{"chapter":15,"verses":[{"verse":1,"text":"A soft answer turneth away wrath: but grievous words stir up anger."},{"verse":2,"text":"The tongue of the wise useth knowledge aright: but the mouth of fools poureth out foolishness."},{"verse":3,"text":"The eyes of the Lord are in every place, beholding the evil and the good."},{"verse":4,"text":"A wholesome tongue is a tree of life: but perverseness therein is a breach in the spirit."},{"verse":5,"text":"A fool despiseth his father’s instruction: but he that regardeth reproof is prudent."},{"verse":6,"text":"In the house of the righteous is much treasure: but in the revenues of the wicked is trouble."},{"verse":7,"text":"The lips of the wise disperse knowledge: but the heart of the foolish doeth not so."},{"verse":8,"text":"The sacrifice of the wicked is an abomination to the Lord: but the prayer of the upright is his delight."},{"verse":9,"text":"The way of the wicked is an abomination unto the Lord: but he loveth him that followeth after righteousness."},{"verse":10,"text":"Correction is grievous unto him that forsaketh the way: and he that hateth reproof shall die."},{"verse":11,"text":"Hell and destruction are before the Lord: how much more then the hearts of the children of men?"},{"verse":12,"text":"A scorner loveth not one that reproveth him: neither will he go unto the wise."},{"verse":13,"text":"A merry heart maketh a cheerful countenance: but by sorrow of the heart the spirit is broken."},{"verse":14,"text":"The heart of him that hath understanding seeketh knowledge: but the mouth of fools feedeth on foolishness."},{"verse":15,"text":"All the days of the afflicted are evil: but he that is of a merry heart hath a continual feast."},{"verse":16,"text":"Better is little with the fear of the Lord than great treasure and trouble therewith."},{"verse":17,"text":"Better is a dinner of herbs where love is, than a stalled ox and hatred therewith."},{"verse":18,"text":"A wrathful man stirreth up strife: but he that is slow to anger appeaseth strife."},{"verse":19,"text":"The way of the slothful man is as an hedge of thorns: but the way of the righteous is made plain."},{"verse":20,"text":"A wise son maketh a glad father: but a foolish man despiseth his mother."},{"verse":21,"text":"Folly is joy to him that is destitute of wisdom: but a man of understanding walketh uprightly."},{"verse":22,"text":"Without counsel purposes are disappointed: but in the multitude of counsellors they are established."},{"verse":23,"text":"A man hath joy by the answer of his mouth: and a word spoken in due season, how good is it!"},{"verse":24,"text":"The way of life is above to the wise, that he may depart from hell beneath."},{"verse":25,"text":"The Lord will destroy the house of the proud: but he will establish the border of the widow."},{"verse":26,"text":"The thoughts of the wicked are an abomination to the Lord: but the words of the pure are pleasant words."},{"verse":27,"text":"He that is greedy of gain troubleth his own house; but he that hateth gifts shall live."},{"verse":28,"text":"The heart of the righteous studieth to answer: but the mouth of the wicked poureth out evil things."},{"verse":29,"text":"The Lord is far from the wicked: but he heareth the prayer of the righteous."},{"verse":30,"text":"The light of the eyes rejoiceth the heart: and a good report maketh the bones fat."},{"verse":31,"text":"The ear that heareth the reproof of life abideth among the wise."},{"verse":32,"text":"He that refuseth instruction despiseth his own soul: but he that heareth reproof getteth understanding."},{"verse":33,"text":"The fear of the Lord is the instruction of wisdom; and before honour is humility. "}]},{"chapter":16,"verses":[{"verse":1,"text":"The preparations of the heart in man, and the answer of the tongue, is from the Lord."},{"verse":2,"text":"All the ways of a man are clean in his own eyes; but the Lord weigheth the spirits."},{"verse":3,"text":"Commit thy works unto the Lord, and thy thoughts shall be established."},{"verse":4,"text":"The Lord hath made all things for himself: yea, even the wicked for the day of evil."},{"verse":5,"text":"Every one that is proud in heart is an abomination to the Lord: though hand join in hand, he shall not be unpunished."},{"verse":6,"text":"By mercy and truth iniquity is purged: and by the fear of the Lord men depart from evil."},{"verse":7,"text":"When a man’s ways please the Lord, he maketh even his enemies to be at peace with him."},{"verse":8,"text":"Better is a little with righteousness than great revenues without right."},{"verse":9,"text":"A man’s heart deviseth his way: but the Lord directeth his steps."},{"verse":10,"text":"A divine sentence is in the lips of the king: his mouth transgresseth not in judgment."},{"verse":11,"text":"A just weight and balance are the Lord’s: all the weights of the bag are his work."},{"verse":12,"text":"It is an abomination to kings to commit wickedness: for the throne is established by righteousness."},{"verse":13,"text":"Righteous lips are the delight of kings; and they love him that speaketh right."},{"verse":14,"text":"The wrath of a king is as messengers of death: but a wise man will pacify it."},{"verse":15,"text":"In the light of the king’s countenance is life; and his favour is as a cloud of the latter rain."},{"verse":16,"text":"How much better is it to get wisdom than gold! and to get understanding rather to be chosen than silver!"},{"verse":17,"text":"The highway of the upright is to depart from evil: he that keepeth his way preserveth his soul."},{"verse":18,"text":"Pride goeth before destruction, and an haughty spirit before a fall."},{"verse":19,"text":"Better it is to be of an humble spirit with the lowly, than to divide the spoil with the proud."},{"verse":20,"text":"He that handleth a matter wisely shall find good: and whoso trusteth in the Lord, happy is he."},{"verse":21,"text":"The wise in heart shall be called prudent: and the sweetness of the lips increaseth learning."},{"verse":22,"text":"Understanding is a wellspring of life unto him that hath it: but the instruction of fools is folly."},{"verse":23,"text":"The heart of the wise teacheth his mouth, and addeth learning to his lips."},{"verse":24,"text":"Pleasant words are as an honeycomb, sweet to the soul, and health to the bones."},{"verse":25,"text":"There is a way that seemeth right unto a man, but the end thereof are the ways of death."},{"verse":26,"text":"He that laboureth laboureth for himself; for his mouth craveth it of him."},{"verse":27,"text":"An ungodly man diggeth up evil: and in his lips there is as a burning fire."},{"verse":28,"text":"A froward man soweth strife: and a whisperer separateth chief friends."},{"verse":29,"text":"A violent man enticeth his neighbour, and leadeth him into the way that is not good."},{"verse":30,"text":"He shutteth his eyes to devise froward things: moving his lips he bringeth evil to pass."},{"verse":31,"text":"The hoary head is a crown of glory, if it be found in the way of righteousness."},{"verse":32,"text":"He that is slow to anger is better than the mighty; and he that ruleth his spirit than he that taketh a city."},{"verse":33,"text":"The lot is cast into the lap; but the whole disposing thereof is of the Lord. "}]},{"chapter":17,"verses":[{"verse":1,"text":"Better is a dry morsel, and quietness therewith, than an house full of sacrifices with strife."},{"verse":2,"text":"A wise servant shall have rule over a son that causeth shame, and shall have part of the inheritance among the brethren."},{"verse":3,"text":"The fining pot is for silver, and the furnace for gold: but the Lord trieth the hearts."},{"verse":4,"text":"A wicked doer giveth heed to false lips; and a liar giveth ear to a naughty tongue."},{"verse":5,"text":"Whoso mocketh the poor reproacheth his Maker: and he that is glad at calamities shall not be unpunished."},{"verse":6,"text":"Children’s children are the crown of old men; and the glory of children are their fathers."},{"verse":7,"text":"Excellent speech becometh not a fool: much less do lying lips a prince."},{"verse":8,"text":"A gift is as a precious stone in the eyes of him that hath it: whithersoever it turneth, it prospereth."},{"verse":9,"text":"He that covereth a transgression seeketh love; but he that repeateth a matter separateth very friends."},{"verse":10,"text":"A reproof entereth more into a wise man than an hundred stripes into a fool."},{"verse":11,"text":"An evil man seeketh only rebellion: therefore a cruel messenger shall be sent against him."},{"verse":12,"text":"Let a bear robbed of her whelps meet a man, rather than a fool in his folly."},{"verse":13,"text":"Whoso rewardeth evil for good, evil shall not depart from his house."},{"verse":14,"text":"The beginning of strife is as when one letteth out water: therefore leave off contention, before it be meddled with."},{"verse":15,"text":"He that justifieth the wicked, and he that condemneth the just, even they both are abomination to the Lord."},{"verse":16,"text":"Wherefore is there a price in the hand of a fool to get wisdom, seeing he hath no heart to it?"},{"verse":17,"text":"A friend loveth at all times, and a brother is born for adversity."},{"verse":18,"text":"A man void of understanding striketh hands, and becometh surety in the presence of his friend."},{"verse":19,"text":"He loveth transgression that loveth strife: and he that exalteth his gate seeketh destruction."},{"verse":20,"text":"He that hath a froward heart findeth no good: and he that hath a perverse tongue falleth into mischief."},{"verse":21,"text":"He that begetteth a fool doeth it to his sorrow: and the father of a fool hath no joy."},{"verse":22,"text":"A merry heart doeth good like a medicine: but a broken spirit drieth the bones."},{"verse":23,"text":"A wicked man taketh a gift out of the bosom to pervert the ways of judgment."},{"verse":24,"text":"Wisdom is before him that hath understanding; but the eyes of a fool are in the ends of the earth."},{"verse":25,"text":"A foolish son is a grief to his father, and bitterness to her that bare him."},{"verse":26,"text":"Also to punish the just is not good, nor to strike princes for equity."},{"verse":27,"text":"He that hath knowledge spareth his words: and a man of understanding is of an excellent spirit."},{"verse":28,"text":"Even a fool, when he holdeth his peace, is counted wise: and he that shutteth his lips is esteemed a man of understanding. "}]},{"chapter":18,"verses":[{"verse":1,"text":"Through desire a man, having separated himself, seeketh and intermeddleth with all wisdom."},{"verse":2,"text":"A fool hath no delight in understanding, but that his heart may discover itself."},{"verse":3,"text":"When the wicked cometh, then cometh also contempt, and with ignominy reproach."},{"verse":4,"text":"The words of a man’s mouth are as deep waters, and the wellspring of wisdom as a flowing brook."},{"verse":5,"text":"It is not good to accept the person of the wicked, to overthrow the righteous in judgment."},{"verse":6,"text":"A fool’s lips enter into contention, and his mouth calleth for strokes."},{"verse":7,"text":"A fool’s mouth is his destruction, and his lips are the snare of his soul."},{"verse":8,"text":"The words of a talebearer are as wounds, and they go down into the innermost parts of the belly."},{"verse":9,"text":"He also that is slothful in his work is brother to him that is a great waster."},{"verse":10,"text":"The name of the Lord is a strong tower: the righteous runneth into it, and is safe."},{"verse":11,"text":"The rich man’s wealth is his strong city, and as an high wall in his own conceit."},{"verse":12,"text":"Before destruction the heart of man is haughty, and before honour is humility."},{"verse":13,"text":"He that answereth a matter before he heareth it, it is folly and shame unto him."},{"verse":14,"text":"The spirit of a man will sustain his infirmity; but a wounded spirit who can bear?"},{"verse":15,"text":"The heart of the prudent getteth knowledge; and the ear of the wise seeketh knowledge."},{"verse":16,"text":"A man’s gift maketh room for him, and bringeth him before great men."},{"verse":17,"text":"He that is first in his own cause seemeth just; but his neighbour cometh and searcheth him."},{"verse":18,"text":"The lot causeth contentions to cease, and parteth between the mighty."},{"verse":19,"text":"A brother offended is harder to be won than a strong city: and their contentions are like the bars of a castle."},{"verse":20,"text":"A man’s belly shall be satisfied with the fruit of his mouth; and with the increase of his lips shall he be filled."},{"verse":21,"text":"Death and life are in the power of the tongue: and they that love it shall eat the fruit thereof."},{"verse":22,"text":"Whoso findeth a wife findeth a good thing, and obtaineth favour of the Lord."},{"verse":23,"text":"The poor useth intreaties; but the rich answereth roughly."},{"verse":24,"text":"A man that hath friends must shew himself friendly: and there is a friend that sticketh closer than a brother. "}]},{"chapter":19,"verses":[{"verse":1,"text":"Better is the poor that walketh in his integrity, than he that is perverse in his lips, and is a fool."},{"verse":2,"text":"Also, that the soul be without knowledge, it is not good; and he that hasteth with his feet sinneth."},{"verse":3,"text":"The foolishness of man perverteth his way: and his heart fretteth against the Lord."},{"verse":4,"text":"Wealth maketh many friends; but the poor is separated from his neighbour."},{"verse":5,"text":"A false witness shall not be unpunished, and he that speaketh lies shall not escape."},{"verse":6,"text":"Many will intreat the favour of the prince: and every man is a friend to him that giveth gifts."},{"verse":7,"text":"All the brethren of the poor do hate him: how much more do his friends go far from him? he pursueth them with words, yet they are wanting to him."},{"verse":8,"text":"He that getteth wisdom loveth his own soul: he that keepeth understanding shall find good."},{"verse":9,"text":"A false witness shall not be unpunished, and he that speaketh lies shall perish."},{"verse":10,"text":"Delight is not seemly for a fool; much less for a servant to have rule over princes."},{"verse":11,"text":"The discretion of a man deferreth his anger; and it is his glory to pass over a transgression."},{"verse":12,"text":"The king’s wrath is as the roaring of a lion; but his favour is as dew upon the grass."},{"verse":13,"text":"A foolish son is the calamity of his father: and the contentions of a wife are a continual dropping."},{"verse":14,"text":"House and riches are the inheritance of fathers: and a prudent wife is from the Lord."},{"verse":15,"text":"Slothfulness casteth into a deep sleep; and an idle soul shall suffer hunger."},{"verse":16,"text":"He that keepeth the commandment keepeth his own soul; but he that despiseth his ways shall die."},{"verse":17,"text":"He that hath pity upon the poor lendeth unto the Lord; and that which he hath given will he pay him again."},{"verse":18,"text":"Chasten thy son while there is hope, and let not thy soul spare for his crying."},{"verse":19,"text":"A man of great wrath shall suffer punishment: for if thou deliver him, yet thou must do it again."},{"verse":20,"text":"Hear counsel, and receive instruction, that thou mayest be wise in thy latter end."},{"verse":21,"text":"There are many devices in a man’s heart; nevertheless the counsel of the Lord, that shall stand."},{"verse":22,"text":"The desire of a man is his kindness: and a poor man is better than a liar."},{"verse":23,"text":"The fear of the Lord tendeth to life: and he that hath it shall abide satisfied; he shall not be visited with evil."},{"verse":24,"text":"A slothful man hideth his hand in his bosom, and will not so much as bring it to his mouth again."},{"verse":25,"text":"Smite a scorner, and the simple will beware: and reprove one that hath understanding, and he will understand knowledge."},{"verse":26,"text":"He that wasteth his father, and chaseth away his mother, is a son that causeth shame, and bringeth reproach."},{"verse":27,"text":"Cease, my son, to hear the instruction that causeth to err from the words of knowledge."},{"verse":28,"text":"An ungodly witness scorneth judgment: and the mouth of the wicked devoureth iniquity."},{"verse":29,"text":"Judgments are prepared for scorners, and stripes for the back of fools. "}]},{"chapter":20,"verses":[{"verse":1,"text":"Wine is a mocker, strong drink is raging: and whosoever is deceived thereby is not wise."},{"verse":2,"text":"The fear of a king is as the roaring of a lion: whoso provoketh him to anger sinneth against his own soul."},{"verse":3,"text":"It is an honour for a man to cease from strife: but every fool will be meddling."},{"verse":4,"text":"The sluggard will not plow by reason of the cold; therefore shall he beg in harvest, and have nothing."},{"verse":5,"text":"Counsel in the heart of man is like deep water; but a man of understanding will draw it out."},{"verse":6,"text":"Most men will proclaim every one his own goodness: but a faithful man who can find?"},{"verse":7,"text":"The just man walketh in his integrity: his children are blessed after him."},{"verse":8,"text":"A king that sitteth in the throne of judgment scattereth away all evil with his eyes."},{"verse":9,"text":"Who can say, I have made my heart clean, I am pure from my sin?"},{"verse":10,"text":"Divers weights, and divers measures, both of them are alike abomination to the Lord."},{"verse":11,"text":"Even a child is known by his doings, whether his work be pure, and whether it be right."},{"verse":12,"text":"The hearing ear, and the seeing eye, the Lord hath made even both of them."},{"verse":13,"text":"Love not sleep, lest thou come to poverty; open thine eyes, and thou shalt be satisfied with bread."},{"verse":14,"text":"It is naught, it is naught, saith the buyer: but when he is gone his way, then he boasteth."},{"verse":15,"text":"There is gold, and a multitude of rubies: but the lips of knowledge are a precious jewel."},{"verse":16,"text":"Take his garment that is surety for a stranger: and take a pledge of him for a strange woman."},{"verse":17,"text":"Bread of deceit is sweet to a man; but afterwards his mouth shall be filled with gravel."},{"verse":18,"text":"Every purpose is established by counsel: and with good advice make war."},{"verse":19,"text":"He that goeth about as a talebearer revealeth secrets: therefore meddle not with him that flattereth with his lips."},{"verse":20,"text":"Whoso curseth his father or his mother, his lamp shall be put out in obscure darkness."},{"verse":21,"text":"An inheritance may be gotten hastily at the beginning; but the end thereof shall not be blessed."},{"verse":22,"text":"Say not thou, I will recompense evil; but wait on the Lord, and he shall save thee."},{"verse":23,"text":"Divers weights are an abomination unto the Lord; and a false balance is not good."},{"verse":24,"text":"Man’s goings are of the Lord; how can a man then understand his own way?"},{"verse":25,"text":"It is a snare to the man who devoureth that which is holy, and after vows to make enquiry."},{"verse":26,"text":"A wise king scattereth the wicked, and bringeth the wheel over them."},{"verse":27,"text":"The spirit of man is the candle of the Lord, searching all the inward parts of the belly."},{"verse":28,"text":"Mercy and truth preserve the king: and his throne is upholden by mercy."},{"verse":29,"text":"The glory of young men is their strength: and the beauty of old men is the gray head."},{"verse":30,"text":"The blueness of a wound cleanseth away evil: so do stripes the inward parts of the belly. "}]},{"chapter":21,"verses":[{"verse":1,"text":"The king’s heart is in the hand of the Lord, as the rivers of water: he turneth it whithersoever he will."},{"verse":2,"text":"Every way of a man is right in his own eyes: but the Lord pondereth the hearts."},{"verse":3,"text":"To do justice and judgment is more acceptable to the Lord than sacrifice."},{"verse":4,"text":"An high look, and a proud heart, and the plowing of the wicked, is sin."},{"verse":5,"text":"The thoughts of the diligent tend only to plenteousness; but of every one that is hasty only to want."},{"verse":6,"text":"The getting of treasures by a lying tongue is a vanity tossed to and fro of them that seek death."},{"verse":7,"text":"The robbery of the wicked shall destroy them; because they refuse to do judgment."},{"verse":8,"text":"The way of man is froward and strange: but as for the pure, his work is right."},{"verse":9,"text":"It is better to dwell in a corner of the housetop, than with a brawling woman in a wide house."},{"verse":10,"text":"The soul of the wicked desireth evil: his neighbour findeth no favour in his eyes."},{"verse":11,"text":"When the scorner is punished, the simple is made wise: and when the wise is instructed, he receiveth knowledge."},{"verse":12,"text":"The righteous man wisely considereth the house of the wicked: but God overthroweth the wicked for their wickedness."},{"verse":13,"text":"Whoso stoppeth his ears at the cry of the poor, he also shall cry himself, but shall not be heard."},{"verse":14,"text":"A gift in secret pacifieth anger: and a reward in the bosom strong wrath."},{"verse":15,"text":"It is joy to the just to do judgment: but destruction shall be to the workers of iniquity."},{"verse":16,"text":"The man that wandereth out of the way of understanding shall remain in the congregation of the dead."},{"verse":17,"text":"He that loveth pleasure shall be a poor man: he that loveth wine and oil shall not be rich."},{"verse":18,"text":"The wicked shall be a ransom for the righteous, and the transgressor for the upright."},{"verse":19,"text":"It is better to dwell in the wilderness, than with a contentious and an angry woman."},{"verse":20,"text":"There is treasure to be desired and oil in the dwelling of the wise; but a foolish man spendeth it up."},{"verse":21,"text":"He that followeth after righteousness and mercy findeth life, righteousness, and honour."},{"verse":22,"text":"A wise man scaleth the city of the mighty, and casteth down the strength of the confidence thereof."},{"verse":23,"text":"Whoso keepeth his mouth and his tongue keepeth his soul from troubles."},{"verse":24,"text":"Proud and haughty scorner is his name, who dealeth in proud wrath."},{"verse":25,"text":"The desire of the slothful killeth him; for his hands refuse to labour."},{"verse":26,"text":"He coveteth greedily all the day long: but the righteous giveth and spareth not."},{"verse":27,"text":"The sacrifice of the wicked is abomination: how much more, when he bringeth it with a wicked mind?"},{"verse":28,"text":"A false witness shall perish: but the man that heareth speaketh constantly."},{"verse":29,"text":"A wicked man hardeneth his face: but as for the upright, he directeth his way."},{"verse":30,"text":"There is no wisdom nor understanding nor counsel against the Lord."},{"verse":31,"text":"The horse is prepared against the day of battle: but safety is of the Lord. "}]},{"chapter":22,"verses":[{"verse":1,"text":"A good name is rather to be chosen than great riches, and loving favour rather than silver and gold."},{"verse":2,"text":"The rich and poor meet together: the Lord is the maker of them all."},{"verse":3,"text":"A prudent man foreseeth the evil, and hideth himself: but the simple pass on, and are punished."},{"verse":4,"text":"By humility and the fear of the Lord are riches, and honour, and life."},{"verse":5,"text":"Thorns and snares are in the way of the froward: he that doth keep his soul shall be far from them."},{"verse":6,"text":"Train up a child in the way he should go: and when he is old, he will not depart from it."},{"verse":7,"text":"The rich ruleth over the poor, and the borrower is servant to the lender."},{"verse":8,"text":"He that soweth iniquity shall reap vanity: and the rod of his anger shall fail."},{"verse":9,"text":"He that hath a bountiful eye shall be blessed; for he giveth of his bread to the poor."},{"verse":10,"text":"Cast out the scorner, and contention shall go out; yea, strife and reproach shall cease."},{"verse":11,"text":"He that loveth pureness of heart, for the grace of his lips the king shall be his friend."},{"verse":12,"text":"The eyes of the Lord preserve knowledge, and he overthroweth the words of the transgressor."},{"verse":13,"text":"The slothful man saith, There is a lion without, I shall be slain in the streets."},{"verse":14,"text":"The mouth of strange women is a deep pit: he that is abhorred of the Lord shall fall therein."},{"verse":15,"text":"Foolishness is bound in the heart of a child; but the rod of correction shall drive it far from him."},{"verse":16,"text":"He that oppresseth the poor to increase his riches, and he that giveth to the rich, shall surely come to want."},{"verse":17,"text":"Bow down thine ear, and hear the words of the wise, and apply thine heart unto my knowledge."},{"verse":18,"text":"For it is a pleasant thing if thou keep them within thee; they shall withal be fitted in thy lips."},{"verse":19,"text":"That thy trust may be in the Lord, I have made known to thee this day, even to thee."},{"verse":20,"text":"Have not I written to thee excellent things in counsels and knowledge,"},{"verse":21,"text":"That I might make thee know the certainty of the words of truth; that thou mightest answer the words of truth to them that send unto thee?"},{"verse":22,"text":"Rob not the poor, because he is poor: neither oppress the afflicted in the gate:"},{"verse":23,"text":"For the Lord will plead their cause, and spoil the soul of those that spoiled them."},{"verse":24,"text":"Make no friendship with an angry man; and with a furious man thou shalt not go:"},{"verse":25,"text":"Lest thou learn his ways, and get a snare to thy soul."},{"verse":26,"text":"Be not thou one of them that strike hands, or of them that are sureties for debts."},{"verse":27,"text":"If thou hast nothing to pay, why should he take away thy bed from under thee?"},{"verse":28,"text":"Remove not the ancient landmark, which thy fathers have set."},{"verse":29,"text":"Seest thou a man diligent in his business? he shall stand before kings; he shall not stand before mean men. "}]},{"chapter":23,"verses":[{"verse":1,"text":"When thou sittest to eat with a ruler, consider diligently what is before thee:"},{"verse":2,"text":"And put a knife to thy throat, if thou be a man given to appetite."},{"verse":3,"text":"Be not desirous of his dainties: for they are deceitful meat."},{"verse":4,"text":"Labour not to be rich: cease from thine own wisdom."},{"verse":5,"text":"Wilt thou set thine eyes upon that which is not? for riches certainly make themselves wings; they fly away as an eagle toward heaven."},{"verse":6,"text":"Eat thou not the bread of him that hath an evil eye, neither desire thou his dainty meats:"},{"verse":7,"text":"For as he thinketh in his heart, so is he: Eat and drink, saith he to thee; but his heart is not with thee."},{"verse":8,"text":"The morsel which thou hast eaten shalt thou vomit up, and lose thy sweet words."},{"verse":9,"text":"Speak not in the ears of a fool: for he will despise the wisdom of thy words."},{"verse":10,"text":"Remove not the old landmark; and enter not into the fields of the fatherless:"},{"verse":11,"text":"For their redeemer is mighty; he shall plead their cause with thee."},{"verse":12,"text":"Apply thine heart unto instruction, and thine ears to the words of knowledge."},{"verse":13,"text":"Withhold not correction from the child: for if thou beatest him with the rod, he shall not die."},{"verse":14,"text":"Thou shalt beat him with the rod, and shalt deliver his soul from hell."},{"verse":15,"text":"My son, if thine heart be wise, my heart shall rejoice, even mine."},{"verse":16,"text":"Yea, my reins shall rejoice, when thy lips speak right things."},{"verse":17,"text":"Let not thine heart envy sinners: but be thou in the fear of the Lord all the day long."},{"verse":18,"text":"For surely there is an end; and thine expectation shall not be cut off."},{"verse":19,"text":"Hear thou, my son, and be wise, and guide thine heart in the way."},{"verse":20,"text":"Be not among winebibbers; among riotous eaters of flesh:"},{"verse":21,"text":"For the drunkard and the glutton shall come to poverty: and drowsiness shall clothe a man with rags."},{"verse":22,"text":"Hearken unto thy father that begat thee, and despise not thy mother when she is old."},{"verse":23,"text":"Buy the truth, and sell it not; also wisdom, and instruction, and understanding."},{"verse":24,"text":"The father of the righteous shall greatly rejoice: and he that begetteth a wise child shall have joy of him."},{"verse":25,"text":"Thy father and thy mother shall be glad, and she that bare thee shall rejoice."},{"verse":26,"text":"My son, give me thine heart, and let thine eyes observe my ways."},{"verse":27,"text":"For a whore is a deep ditch; and a strange woman is a narrow pit."},{"verse":28,"text":"She also lieth in wait as for a prey, and increaseth the transgressors among men."},{"verse":29,"text":"Who hath woe? who hath sorrow? who hath contentions? who hath babbling? who hath wounds without cause? who hath redness of eyes?"},{"verse":30,"text":"They that tarry long at the wine; they that go to seek mixed wine."},{"verse":31,"text":"Look not thou upon the wine when it is red, when it giveth his colour in the cup, when it moveth itself aright."},{"verse":32,"text":"At the last it biteth like a serpent, and stingeth like an adder."},{"verse":33,"text":"Thine eyes shall behold strange women, and thine heart shall utter perverse things."},{"verse":34,"text":"Yea, thou shalt be as he that lieth down in the midst of the sea, or as he that lieth upon the top of a mast."},{"verse":35,"text":"They have stricken me, shalt thou say, and I was not sick; they have beaten me, and I felt it not: when shall I awake? I will seek it yet again. "}]},{"chapter":24,"verses":[{"verse":1,"text":"Be not thou envious against evil men, neither desire to be with them."},{"verse":2,"text":"For their heart studieth destruction, and their lips talk of mischief."},{"verse":3,"text":"Through wisdom is an house builded; and by understanding it is established:"},{"verse":4,"text":"And by knowledge shall the chambers be filled with all precious and pleasant riches."},{"verse":5,"text":"A wise man is strong; yea, a man of knowledge increaseth strength."},{"verse":6,"text":"For by wise counsel thou shalt make thy war: and in multitude of counsellors there is safety."},{"verse":7,"text":"Wisdom is too high for a fool: he openeth not his mouth in the gate."},{"verse":8,"text":"He that deviseth to do evil shall be called a mischievous person."},{"verse":9,"text":"The thought of foolishness is sin: and the scorner is an abomination to men."},{"verse":10,"text":"If thou faint in the day of adversity, thy strength is small."},{"verse":11,"text":"If thou forbear to deliver them that are drawn unto death, and those that are ready to be slain;"},{"verse":12,"text":"If thou sayest, Behold, we knew it not; doth not he that pondereth the heart consider it? and he that keepeth thy soul, doth not he know it? and shall not he render to every man according to his works?"},{"verse":13,"text":"My son, eat thou honey, because it is good; and the honeycomb, which is sweet to thy taste:"},{"verse":14,"text":"So shall the knowledge of wisdom be unto thy soul: when thou hast found it, then there shall be a reward, and thy expectation shall not be cut off."},{"verse":15,"text":"Lay not wait, O wicked man, against the dwelling of the righteous; spoil not his resting place:"},{"verse":16,"text":"For a just man falleth seven times, and riseth up again: but the wicked shall fall into mischief."},{"verse":17,"text":"Rejoice not when thine enemy falleth, and let not thine heart be glad when he stumbleth:"},{"verse":18,"text":"Lest the Lord see it, and it displease him, and he turn away his wrath from him."},{"verse":19,"text":"Fret not thyself because of evil men, neither be thou envious at the wicked;"},{"verse":20,"text":"For there shall be no reward to the evil man; the candle of the wicked shall be put out."},{"verse":21,"text":"My son, fear thou the Lord and the king: and meddle not with them that are given to change:"},{"verse":22,"text":"For their calamity shall rise suddenly; and who knoweth the ruin of them both?"},{"verse":23,"text":"These things also belong to the wise. It is not good to have respect of persons in judgment."},{"verse":24,"text":"He that saith unto the wicked, Thou art righteous; him shall the people curse, nations shall abhor him:"},{"verse":25,"text":"But to them that rebuke him shall be delight, and a good blessing shall come upon them."},{"verse":26,"text":"Every man shall kiss his lips that giveth a right answer."},{"verse":27,"text":"Prepare thy work without, and make it fit for thyself in the field; and afterwards build thine house."},{"verse":28,"text":"Be not a witness against thy neighbour without cause; and deceive not with thy lips."},{"verse":29,"text":"Say not, I will do so to him as he hath done to me: I will render to the man according to his work."},{"verse":30,"text":"I went by the field of the slothful, and by the vineyard of the man void of understanding;"},{"verse":31,"text":"And, lo, it was all grown over with thorns, and nettles had covered the face thereof, and the stone wall thereof was broken down."},{"verse":32,"text":"Then I saw, and considered it well: I looked upon it, and received instruction."},{"verse":33,"text":"Yet a little sleep, a little slumber, a little folding of the hands to sleep:"},{"verse":34,"text":"So shall thy poverty come as one that travelleth; and thy want as an armed man. "}]},{"chapter":25,"verses":[{"verse":1,"text":"These are also proverbs of Solomon, which the men of Hezekiah king of Judah copied out."},{"verse":2,"text":"It is the glory of God to conceal a thing: but the honour of kings is to search out a matter."},{"verse":3,"text":"The heaven for height, and the earth for depth, and the heart of kings is unsearchable."},{"verse":4,"text":"Take away the dross from the silver, and there shall come forth a vessel for the finer."},{"verse":5,"text":"Take away the wicked from before the king, and his throne shall be established in righteousness."},{"verse":6,"text":"Put not forth thyself in the presence of the king, and stand not in the place of great men:"},{"verse":7,"text":"For better it is that it be said unto thee, Come up hither; than that thou shouldest be put lower in the presence of the prince whom thine eyes have seen."},{"verse":8,"text":"Go not forth hastily to strive, lest thou know not what to do in the end thereof, when thy neighbour hath put thee to shame."},{"verse":9,"text":"Debate thy cause with thy neighbour himself; and discover not a secret to another:"},{"verse":10,"text":"Lest he that heareth it put thee to shame, and thine infamy turn not away."},{"verse":11,"text":"A word fitly spoken is like apples of gold in pictures of silver."},{"verse":12,"text":"As an earring of gold, and an ornament of fine gold, so is a wise reprover upon an obedient ear."},{"verse":13,"text":"As the cold of snow in the time of harvest, so is a faithful messenger to them that send him: for he refresheth the soul of his masters."},{"verse":14,"text":"Whoso boasteth himself of a false gift is like clouds and wind without rain."},{"verse":15,"text":"By long forbearing is a prince persuaded, and a soft tongue breaketh the bone."},{"verse":16,"text":"Hast thou found honey? eat so much as is sufficient for thee, lest thou be filled therewith, and vomit it."},{"verse":17,"text":"Withdraw thy foot from thy neighbour’s house; lest he be weary of thee, and so hate thee."},{"verse":18,"text":"A man that beareth false witness against his neighbour is a maul, and a sword, and a sharp arrow."},{"verse":19,"text":"Confidence in an unfaithful man in time of trouble is like a broken tooth, and a foot out of joint."},{"verse":20,"text":"As he that taketh away a garment in cold weather, and as vinegar upon nitre, so is he that singeth songs to an heavy heart."},{"verse":21,"text":"If thine enemy be hungry, give him bread to eat; and if he be thirsty, give him water to drink:"},{"verse":22,"text":"For thou shalt heap coals of fire upon his head, and the Lord shall reward thee."},{"verse":23,"text":"The north wind driveth away rain: so doth an angry countenance a backbiting tongue."},{"verse":24,"text":"It is better to dwell in the corner of the housetop, than with a brawling woman and in a wide house."},{"verse":25,"text":"As cold waters to a thirsty soul, so is good news from a far country."},{"verse":26,"text":"A righteous man falling down before the wicked is as a troubled fountain, and a corrupt spring."},{"verse":27,"text":"It is not good to eat much honey: so for men to search their own glory is not glory."},{"verse":28,"text":"He that hath no rule over his own spirit is like a city that is broken down, and without walls. "}]},{"chapter":26,"verses":[{"verse":1,"text":"As snow in summer, and as rain in harvest, so honour is not seemly for a fool."},{"verse":2,"text":"As the bird by wandering, as the swallow by flying, so the curse causeless shall not come."},{"verse":3,"text":"A whip for the horse, a bridle for the ass, and a rod for the fool’s back."},{"verse":4,"text":"Answer not a fool according to his folly, lest thou also be like unto him."},{"verse":5,"text":"Answer a fool according to his folly, lest he be wise in his own conceit."},{"verse":6,"text":"He that sendeth a message by the hand of a fool cutteth off the feet, and drinketh damage."},{"verse":7,"text":"The legs of the lame are not equal: so is a parable in the mouth of fools."},{"verse":8,"text":"As he that bindeth a stone in a sling, so is he that giveth honour to a fool."},{"verse":9,"text":"As a thorn goeth up into the hand of a drunkard, so is a parable in the mouth of fools."},{"verse":10,"text":"The great God that formed all things both rewardeth the fool, and rewardeth transgressors."},{"verse":11,"text":"As a dog returneth to his vomit, so a fool returneth to his folly."},{"verse":12,"text":"Seest thou a man wise in his own conceit? there is more hope of a fool than of him."},{"verse":13,"text":"The slothful man saith, There is a lion in the way; a lion is in the streets."},{"verse":14,"text":"As the door turneth upon his hinges, so doth the slothful upon his bed."},{"verse":15,"text":"The slothful hideth his hand in his bosom; it grieveth him to bring it again to his mouth."},{"verse":16,"text":"The sluggard is wiser in his own conceit than seven men that can render a reason."},{"verse":17,"text":"He that passeth by, and meddleth with strife belonging not to him, is like one that taketh a dog by the ears."},{"verse":18,"text":"As a mad man who casteth firebrands, arrows, and death,"},{"verse":19,"text":"So is the man that deceiveth his neighbour, and saith, Am not I in sport?"},{"verse":20,"text":"Where no wood is, there the fire goeth out: so where there is no talebearer, the strife ceaseth."},{"verse":21,"text":"As coals are to burning coals, and wood to fire; so is a contentious man to kindle strife."},{"verse":22,"text":"The words of a talebearer are as wounds, and they go down into the innermost parts of the belly."},{"verse":23,"text":"Burning lips and a wicked heart are like a potsherd covered with silver dross."},{"verse":24,"text":"He that hateth dissembleth with his lips, and layeth up deceit within him;"},{"verse":25,"text":"When he speaketh fair, believe him not: for there are seven abominations in his heart."},{"verse":26,"text":"Whose hatred is covered by deceit, his wickedness shall be shewed before the whole congregation."},{"verse":27,"text":"Whoso diggeth a pit shall fall therein: and he that rolleth a stone, it will return upon him."},{"verse":28,"text":"A lying tongue hateth those that are afflicted by it; and a flattering mouth worketh ruin. "}]},{"chapter":27,"verses":[{"verse":1,"text":"Boast not thyself of to morrow; for thou knowest not what a day may bring forth."},{"verse":2,"text":"Let another man praise thee, and not thine own mouth; a stranger, and not thine own lips."},{"verse":3,"text":"A stone is heavy, and the sand weighty; but a fool’s wrath is heavier than them both."},{"verse":4,"text":"Wrath is cruel, and anger is outrageous; but who is able to stand before envy?"},{"verse":5,"text":"Open rebuke is better than secret love."},{"verse":6,"text":"Faithful are the wounds of a friend; but the kisses of an enemy are deceitful."},{"verse":7,"text":"The full soul loatheth an honeycomb; but to the hungry soul every bitter thing is sweet."},{"verse":8,"text":"As a bird that wandereth from her nest, so is a man that wandereth from his place."},{"verse":9,"text":"Ointment and perfume rejoice the heart: so doth the sweetness of a man’s friend by hearty counsel."},{"verse":10,"text":"Thine own friend, and thy father’s friend, forsake not; neither go into thy brother’s house in the day of thy calamity: for better is a neighbour that is near than a brother far off."},{"verse":11,"text":"My son, be wise, and make my heart glad, that I may answer him that reproacheth me."},{"verse":12,"text":"A prudent man foreseeth the evil, and hideth himself; but the simple pass on, and are punished."},{"verse":13,"text":"Take his garment that is surety for a stranger, and take a pledge of him for a strange woman."},{"verse":14,"text":"He that blesseth his friend with a loud voice, rising early in the morning, it shall be counted a curse to him."},{"verse":15,"text":"A continual dropping in a very rainy day and a contentious woman are alike."},{"verse":16,"text":"Whosoever hideth her hideth the wind, and the ointment of his right hand, which bewrayeth itself."},{"verse":17,"text":"Iron sharpeneth iron; so a man sharpeneth the countenance of his friend."},{"verse":18,"text":"Whoso keepeth the fig tree shall eat the fruit thereof: so he that waiteth on his master shall be honoured."},{"verse":19,"text":"As in water face answereth to face, so the heart of man to man."},{"verse":20,"text":"Hell and destruction are never full; so the eyes of man are never satisfied."},{"verse":21,"text":"As the fining pot for silver, and the furnace for gold; so is a man to his praise."},{"verse":22,"text":"Though thou shouldest bray a fool in a mortar among wheat with a pestle, yet will not his foolishness depart from him."},{"verse":23,"text":"Be thou diligent to know the state of thy flocks, and look well to thy herds."},{"verse":24,"text":"For riches are not for ever: and doth the crown endure to every generation?"},{"verse":25,"text":"The hay appeareth, and the tender grass sheweth itself, and herbs of the mountains are gathered."},{"verse":26,"text":"The lambs are for thy clothing, and the goats are the price of the field."},{"verse":27,"text":"And thou shalt have goats’ milk enough for thy food, for the food of thy household, and for the maintenance for thy maidens. "}]},{"chapter":28,"verses":[{"verse":1,"text":"The wicked flee when no man pursueth: but the righteous are bold as a lion."},{"verse":2,"text":"For the transgression of a land many are the princes thereof: but by a man of understanding and knowledge the state thereof shall be prolonged."},{"verse":3,"text":"A poor man that oppresseth the poor is like a sweeping rain which leaveth no food."},{"verse":4,"text":"They that forsake the law praise the wicked: but such as keep the law contend with them."},{"verse":5,"text":"Evil men understand not judgment: but they that seek the Lord understand all things."},{"verse":6,"text":"Better is the poor that walketh in his uprightness, than he that is perverse in his ways, though he be rich."},{"verse":7,"text":"Whoso keepeth the law is a wise son: but he that is a companion of riotous men shameth his father."},{"verse":8,"text":"He that by usury and unjust gain increaseth his substance, he shall gather it for him that will pity the poor."},{"verse":9,"text":"He that turneth away his ear from hearing the law, even his prayer shall be abomination."},{"verse":10,"text":"Whoso causeth the righteous to go astray in an evil way, he shall fall himself into his own pit: but the upright shall have good things in possession."},{"verse":11,"text":"The rich man is wise in his own conceit; but the poor that hath understanding searcheth him out."},{"verse":12,"text":"When righteous men do rejoice, there is great glory: but when the wicked rise, a man is hidden."},{"verse":13,"text":"He that covereth his sins shall not prosper: but whoso confesseth and forsaketh them shall have mercy."},{"verse":14,"text":"Happy is the man that feareth alway: but he that hardeneth his heart shall fall into mischief."},{"verse":15,"text":"As a roaring lion, and a ranging bear; so is a wicked ruler over the poor people."},{"verse":16,"text":"The prince that wanteth understanding is also a great oppressor: but he that hateth covetousness shall prolong his days."},{"verse":17,"text":"A man that doeth violence to the blood of any person shall flee to the pit; let no man stay him."},{"verse":18,"text":"Whoso walketh uprightly shall be saved: but he that is perverse in his ways shall fall at once."},{"verse":19,"text":"He that tilleth his land shall have plenty of bread: but he that followeth after vain persons shall have poverty enough."},{"verse":20,"text":"A faithful man shall abound with blessings: but he that maketh haste to be rich shall not be innocent."},{"verse":21,"text":"To have respect of persons is not good: for for a piece of bread that man will transgress."},{"verse":22,"text":"He that hasteth to be rich hath an evil eye, and considereth not that poverty shall come upon him."},{"verse":23,"text":"He that rebuketh a man afterwards shall find more favour than he that flattereth with the tongue."},{"verse":24,"text":"Whoso robbeth his father or his mother, and saith, It is no transgression; the same is the companion of a destroyer."},{"verse":25,"text":"He that is of a proud heart stirreth up strife: but he that putteth his trust in the Lord shall be made fat."},{"verse":26,"text":"He that trusteth in his own heart is a fool: but whoso walketh wisely, he shall be delivered."},{"verse":27,"text":"He that giveth unto the poor shall not lack: but he that hideth his eyes shall have many a curse."},{"verse":28,"text":"When the wicked rise, men hide themselves: but when they perish, the righteous increase. "}]},{"chapter":29,"verses":[{"verse":1,"text":"He, that being often reproved hardeneth his neck, shall suddenly be destroyed, and that without remedy."},{"verse":2,"text":"When the righteous are in authority, the people rejoice: but when the wicked beareth rule, the people mourn."},{"verse":3,"text":"Whoso loveth wisdom rejoiceth his father: but he that keepeth company with harlots spendeth his substance."},{"verse":4,"text":"The king by judgment establisheth the land: but he that receiveth gifts overthroweth it."},{"verse":5,"text":"A man that flattereth his neighbour spreadeth a net for his feet."},{"verse":6,"text":"In the transgression of an evil man there is a snare: but the righteous doth sing and rejoice."},{"verse":7,"text":"The righteous considereth the cause of the poor: but the wicked regardeth not to know it."},{"verse":8,"text":"Scornful men bring a city into a snare: but wise men turn away wrath."},{"verse":9,"text":"If a wise man contendeth with a foolish man, whether he rage or laugh, there is no rest."},{"verse":10,"text":"The bloodthirsty hate the upright: but the just seek his soul."},{"verse":11,"text":"A fool uttereth all his mind: but a wise man keepeth it in till afterwards."},{"verse":12,"text":"If a ruler hearken to lies, all his servants are wicked."},{"verse":13,"text":"The poor and the deceitful man meet together: the Lord lighteneth both their eyes."},{"verse":14,"text":"The king that faithfully judgeth the poor, his throne shall be established for ever."},{"verse":15,"text":"The rod and reproof give wisdom: but a child left to himself bringeth his mother to shame."},{"verse":16,"text":"When the wicked are multiplied, transgression increaseth: but the righteous shall see their fall."},{"verse":17,"text":"Correct thy son, and he shall give thee rest; yea, he shall give delight unto thy soul."},{"verse":18,"text":"Where there is no vision, the people perish: but he that keepeth the law, happy is he."},{"verse":19,"text":"A servant will not be corrected by words: for though he understand he will not answer."},{"verse":20,"text":"Seest thou a man that is hasty in his words? there is more hope of a fool than of him."},{"verse":21,"text":"He that delicately bringeth up his servant from a child shall have him become his son at the length."},{"verse":22,"text":"An angry man stirreth up strife, and a furious man aboundeth in transgression."},{"verse":23,"text":"A man’s pride shall bring him low: but honour shall uphold the humble in spirit."},{"verse":24,"text":"Whoso is partner with a thief hateth his own soul: he heareth cursing, and bewrayeth it not."},{"verse":25,"text":"The fear of man bringeth a snare: but whoso putteth his trust in the Lord shall be safe."},{"verse":26,"text":"Many seek the ruler’s favour; but every man’s judgment cometh from the Lord."},{"verse":27,"text":"An unjust man is an abomination to the just: and he that is upright in the way is abomination to the wicked. "}]},{"chapter":30,"verses":[{"verse":1,"text":"The words of Agur the son of Jakeh, even the prophecy: the man spake unto Ithiel, even unto Ithiel and Ucal,"},{"verse":2,"text":"Surely I am more brutish than any man, and have not the understanding of a man."},{"verse":3,"text":"I neither learned wisdom, nor have the knowledge of the holy."},{"verse":4,"text":"Who hath ascended up into heaven, or descended? who hath gathered the wind in his fists? who hath bound the waters in a garment? who hath established all the ends of the earth? what is his name, and what is his son’s name, if thou canst tell?"},{"verse":5,"text":"Every word of God is pure: he is a shield unto them that put their trust in him."},{"verse":6,"text":"Add thou not unto his words, lest he reprove thee, and thou be found a liar."},{"verse":7,"text":"Two things have I required of thee; deny me them not before I die:"},{"verse":8,"text":"Remove far from me vanity and lies: give me neither poverty nor riches; feed me with food convenient for me:"},{"verse":9,"text":"Lest I be full, and deny thee, and say, Who is the Lord? or lest I be poor, and steal, and take the name of my God in vain."},{"verse":10,"text":"Accuse not a servant unto his master, lest he curse thee, and thou be found guilty."},{"verse":11,"text":"There is a generation that curseth their father, and doth not bless their mother."},{"verse":12,"text":"There is a generation that are pure in their own eyes, and yet is not washed from their filthiness."},{"verse":13,"text":"There is a generation, O how lofty are their eyes! and their eyelids are lifted up."},{"verse":14,"text":"There is a generation, whose teeth are as swords, and their jaw teeth as knives, to devour the poor from off the earth, and the needy from among men."},{"verse":15,"text":"The horseleach hath two daughters, crying, Give, give. There are three things that are never satisfied, yea, four things say not, It is enough:"},{"verse":16,"text":"The grave; and the barren womb; the earth that is not filled with water; and the fire that saith not, It is enough."},{"verse":17,"text":"The eye that mocketh at his father, and despiseth to obey his mother, the ravens of the valley shall pick it out, and the young eagles shall eat it."},{"verse":18,"text":"There be three things which are too wonderful for me, yea, four which I know not:"},{"verse":19,"text":"The way of an eagle in the air; the way of a serpent upon a rock; the way of a ship in the midst of the sea; and the way of a man with a maid."},{"verse":20,"text":"Such is the way of an adulterous woman; she eateth, and wipeth her mouth, and saith, I have done no wickedness."},{"verse":21,"text":"For three things the earth is disquieted, and for four which it cannot bear:"},{"verse":22,"text":"For a servant when he reigneth; and a fool when he is filled with meat;"},{"verse":23,"text":"For an odious woman when she is married; and an handmaid that is heir to her mistress."},{"verse":24,"text":"There be four things which are little upon the earth, but they are exceeding wise:"},{"verse":25,"text":"The ants are a people not strong, yet they prepare their meat in the summer;"},{"verse":26,"text":"The conies are but a feeble folk, yet make they their houses in the rocks;"},{"verse":27,"text":"The locusts have no king, yet go they forth all of them by bands;"},{"verse":28,"text":"The spider taketh hold with her hands, and is in kings’ palaces."},{"verse":29,"text":"There be three things which go well, yea, four are comely in going:"},{"verse":30,"text":"A lion which is strongest among beasts, and turneth not away for any;"},{"verse":31,"text":"A greyhound; an he goat also; and a king, against whom there is no rising up."},{"verse":32,"text":"If thou hast done foolishly in lifting up thyself, or if thou hast thought evil, lay thine hand upon thy mouth."},{"verse":33,"text":"Surely the churning of milk bringeth forth butter, and the wringing of the nose bringeth forth blood: so the forcing of wrath bringeth forth strife. "}]},{"chapter":31,"verses":[{"verse":1,"text":"The words of king Lemuel, the prophecy that his mother taught him."},{"verse":2,"text":"What, my son? and what, the son of my womb? and what, the son of my vows?"},{"verse":3,"text":"Give not thy strength unto women, nor thy ways to that which destroyeth kings."},{"verse":4,"text":"It is not for kings, O Lemuel, it is not for kings to drink wine; nor for princes strong drink:"},{"verse":5,"text":"Lest they drink, and forget the law, and pervert the judgment of any of the afflicted."},{"verse":6,"text":"Give strong drink unto him that is ready to perish, and wine unto those that be of heavy hearts."},{"verse":7,"text":"Let him drink, and forget his poverty, and remember his misery no more."},{"verse":8,"text":"Open thy mouth for the dumb in the cause of all such as are appointed to destruction."},{"verse":9,"text":"Open thy mouth, judge righteously, and plead the cause of the poor and needy."},{"verse":10,"text":"Who can find a virtuous woman? for her price is far above rubies."},{"verse":11,"text":"The heart of her husband doth safely trust in her, so that he shall have no need of spoil."},{"verse":12,"text":"She will do him good and not evil all the days of her life."},{"verse":13,"text":"She seeketh wool, and flax, and worketh willingly with her hands."},{"verse":14,"text":"She is like the merchants’ ships; she bringeth her food from afar."},{"verse":15,"text":"She riseth also while it is yet night, and giveth meat to her household, and a portion to her maidens."},{"verse":16,"text":"She considereth a field, and buyeth it: with the fruit of her hands she planteth a vineyard."},{"verse":17,"text":"She girdeth her loins with strength, and strengtheneth her arms."},{"verse":18,"text":"She perceiveth that her merchandise is good: her candle goeth not out by night."},{"verse":19,"text":"She layeth her hands to the spindle, and her hands hold the distaff."},{"verse":20,"text":"She stretcheth out her hand to the poor; yea, she reacheth forth her hands to the needy."},{"verse":21,"text":"She is not afraid of the snow for her household: for all her household are clothed with scarlet."},{"verse":22,"text":"She maketh herself coverings of tapestry; her clothing is silk and purple."},{"verse":23,"text":"Her husband is known in the gates, when he sitteth among the elders of the land."},{"verse":24,"text":"She maketh fine linen, and selleth it; and delivereth girdles unto the merchant."},{"verse":25,"text":"Strength and honour are her clothing; and she shall rejoice in time to come."},{"verse":26,"text":"She openeth her mouth with wisdom; and in her tongue is the law of kindness."},{"verse":27,"text":"She looketh well to the ways of her household, and eateth not the bread of idleness."},{"verse":28,"text":"Her children arise up, and call her blessed; her husband also, and he praiseth her."},{"verse":29,"text":"Many daughters have done virtuously, but thou excellest them all."},{"verse":30,"text":"Favour is deceitful, and beauty is vain: but a woman that feareth the Lord, she shall be praised."},{"verse":31,"text":"Give her of the fruit of her hands; and let her own works praise her in the gates.  "}]}]},{"name":"Ecclesiastes","chapters":[{"chapter":1,"verses":[{"verse":1,"text":"The words of the Preacher, the son of David, king in Jerusalem."},{"verse":2,"text":"Vanity of vanities, saith the Preacher, vanity of vanities; all is vanity."},{"verse":3,"text":"What profit hath a man of all his labour which he taketh under the sun?"},{"verse":4,"text":"One generation passeth away, and another generation cometh: but the earth abideth for ever."},{"verse":5,"text":"The sun also ariseth, and the sun goeth down, and hasteth to his place where he arose."},{"verse":6,"text":"The wind goeth toward the south, and turneth about unto the north; it whirleth about continually, and the wind returneth again according to his circuits."},{"verse":7,"text":"All the rivers run into the sea; yet the sea is not full; unto the place from whence the rivers come, thither they return again."},{"verse":8,"text":"All things are full of labour; man cannot utter it: the eye is not satisfied with seeing, nor the ear filled with hearing."},{"verse":9,"text":"The thing that hath been, it is that which shall be; and that which is done is that which shall be done: and there is no new thing under the sun."},{"verse":10,"text":"Is there any thing whereof it may be said, See, this is new? it hath been already of old time, which was before us."},{"verse":11,"text":"There is no remembrance of former things; neither shall there be any remembrance of things that are to come with those that shall come after."},{"verse":12,"text":"I the Preacher was king over Israel in Jerusalem."},{"verse":13,"text":"And I gave my heart to seek and search out by wisdom concerning all things that are done under heaven: this sore travail hath God given to the sons of man to be exercised therewith."},{"verse":14,"text":"I have seen all the works that are done under the sun; and, behold, all is vanity and vexation of spirit."},{"verse":15,"text":"That which is crooked cannot be made straight: and that which is wanting cannot be numbered."},{"verse":16,"text":"I communed with mine own heart, saying, Lo, I am come to great estate, and have gotten more wisdom than all they that have been before me in Jerusalem: yea, my heart had great experience of wisdom and knowledge."},{"verse":17,"text":"And I gave my heart to know wisdom, and to know madness and folly: I perceived that this also is vexation of spirit."},{"verse":18,"text":"For in much wisdom is much grief: and he that increaseth knowledge increaseth sorrow. "}]},{"chapter":2,"verses":[{"verse":1,"text":"I said in mine heart, Go to now, I will prove thee with mirth, therefore enjoy pleasure: and, behold, this also is vanity."},{"verse":2,"text":"I said of laughter, It is mad: and of mirth, What doeth it?"},{"verse":3,"text":"I sought in mine heart to give myself unto wine, yet acquainting mine heart with wisdom; and to lay hold on folly, till I might see what was that good for the sons of men, which they should do under the heaven all the days of their life."},{"verse":4,"text":"I made me great works; I builded me houses; I planted me vineyards:"},{"verse":5,"text":"I made me gardens and orchards, and I planted trees in them of all kind of fruits:"},{"verse":6,"text":"I made me pools of water, to water therewith the wood that bringeth forth trees:"},{"verse":7,"text":"I got me servants and maidens, and had servants born in my house; also I had great possessions of great and small cattle above all that were in Jerusalem before me:"},{"verse":8,"text":"I gathered me also silver and gold, and the peculiar treasure of kings and of the provinces: I gat me men singers and women singers, and the delights of the sons of men, as musical instruments, and that of all sorts."},{"verse":9,"text":"So I was great, and increased more than all that were before me in Jerusalem: also my wisdom remained with me."},{"verse":10,"text":"And whatsoever mine eyes desired I kept not from them, I withheld not my heart from any joy; for my heart rejoiced in all my labour: and this was my portion of all my labour."},{"verse":11,"text":"Then I looked on all the works that my hands had wrought, and on the labour that I had laboured to do: and, behold, all was vanity and vexation of spirit, and there was no profit under the sun."},{"verse":12,"text":"And I turned myself to behold wisdom, and madness, and folly: for what can the man do that cometh after the king? even that which hath been already done."},{"verse":13,"text":"Then I saw that wisdom excelleth folly, as far as light excelleth darkness."},{"verse":14,"text":"The wise man’s eyes are in his head; but the fool walketh in darkness: and I myself perceived also that one event happeneth to them all."},{"verse":15,"text":"Then said I in my heart, As it happeneth to the fool, so it happeneth even to me; and why was I then more wise? Then I said in my heart, that this also is vanity."},{"verse":16,"text":"For there is no remembrance of the wise more than of the fool for ever; seeing that which now is in the days to come shall all be forgotten. And how dieth the wise man? as the fool."},{"verse":17,"text":"Therefore I hated life; because the work that is wrought under the sun is grievous unto me: for all is vanity and vexation of spirit."},{"verse":18,"text":"Yea, I hated all my labour which I had taken under the sun: because I should leave it unto the man that shall be after me."},{"verse":19,"text":"And who knoweth whether he shall be a wise man or a fool? yet shall he have rule over all my labour wherein I have laboured, and wherein I have shewed myself wise under the sun. This is also vanity."},{"verse":20,"text":"Therefore I went about to cause my heart to despair of all the labour which I took under the sun."},{"verse":21,"text":"For there is a man whose labour is in wisdom, and in knowledge, and in equity; yet to a man that hath not laboured therein shall he leave it for his portion. This also is vanity and a great evil."},{"verse":22,"text":"For what hath man of all his labour, and of the vexation of his heart, wherein he hath laboured under the sun?"},{"verse":23,"text":"For all his days are sorrows, and his travail grief; yea, his heart taketh not rest in the night. This is also vanity."},{"verse":24,"text":"There is nothing better for a man, than that he should eat and drink, and that he should make his soul enjoy good in his labour. This also I saw, that it was from the hand of God."},{"verse":25,"text":"For who can eat, or who else can hasten hereunto, more than I?"},{"verse":26,"text":"For God giveth to a man that is good in his sight wisdom, and knowledge, and joy: but to the sinner he giveth travail, to gather and to heap up, that he may give to him that is good before God. This also is vanity and vexation of spirit. "}]},{"chapter":3,"verses":[{"verse":1,"text":"To every thing there is a season, and a time to every purpose under the heaven:"},{"verse":2,"text":"A time to be born, and a time to die; a time to plant, and a time to pluck up that which is planted;"},{"verse":3,"text":"A time to kill, and a time to heal; a time to break down, and a time to build up;"},{"verse":4,"text":"A time to weep, and a time to laugh; a time to mourn, and a time to dance;"},{"verse":5,"text":"A time to cast away stones, and a time to gather stones together; a time to embrace, and a time to refrain from embracing;"},{"verse":6,"text":"A time to get, and a time to lose; a time to keep, and a time to cast away;"},{"verse":7,"text":"A time to rend, and a time to sew; a time to keep silence, and a time to speak;"},{"verse":8,"text":"A time to love, and a time to hate; a time of war, and a time of peace."},{"verse":9,"text":"What profit hath he that worketh in that wherein he laboureth?"},{"verse":10,"text":"I have seen the travail, which God hath given to the sons of men to be exercised in it."},{"verse":11,"text":"He hath made every thing beautiful in his time: also he hath set the world in their heart, so that no man can find out the work that God maketh from the beginning to the end."},{"verse":12,"text":"I know that there is no good in them, but for a man to rejoice, and to do good in his life."},{"verse":13,"text":"And also that every man should eat and drink, and enjoy the good of all his labour, it is the gift of God."},{"verse":14,"text":"I know that, whatsoever God doeth, it shall be for ever: nothing can be put to it, nor any thing taken from it: and God doeth it, that men should fear before him."},{"verse":15,"text":"That which hath been is now; and that which is to be hath already been; and God requireth that which is past."},{"verse":16,"text":"And moreover I saw under the sun the place of judgment, that wickedness was there; and the place of righteousness, that iniquity was there."},{"verse":17,"text":"I said in mine heart, God shall judge the righteous and the wicked: for there is a time there for every purpose and for every work."},{"verse":18,"text":"I said in mine heart concerning the estate of the sons of men, that God might manifest them, and that they might see that they themselves are beasts."},{"verse":19,"text":"For that which befalleth the sons of men befalleth beasts; even one thing befalleth them: as the one dieth, so dieth the other; yea, they have all one breath; so that a man hath no preeminence above a beast: for all is vanity."},{"verse":20,"text":"All go unto one place; all are of the dust, and all turn to dust again."},{"verse":21,"text":"Who knoweth the spirit of man that goeth upward, and the spirit of the beast that goeth downward to the earth?"},{"verse":22,"text":"Wherefore I perceive that there is nothing better, than that a man should rejoice in his own works; for that is his portion: for who shall bring him to see what shall be after him? "}]},{"chapter":4,"verses":[{"verse":1,"text":"So I returned, and considered all the oppressions that are done under the sun: and behold the tears of such as were oppressed, and they had no comforter; and on the side of their oppressors there was power; but they had no comforter."},{"verse":2,"text":"Wherefore I praised the dead which are already dead more than the living which are yet alive."},{"verse":3,"text":"Yea, better is he than both they, which hath not yet been, who hath not seen the evil work that is done under the sun."},{"verse":4,"text":"Again, I considered all travail, and every right work, that for this a man is envied of his neighbour. This is also vanity and vexation of spirit."},{"verse":5,"text":"The fool foldeth his hands together, and eateth his own flesh."},{"verse":6,"text":"Better is an handful with quietness, than both the hands full with travail and vexation of spirit."},{"verse":7,"text":"Then I returned, and I saw vanity under the sun."},{"verse":8,"text":"There is one alone, and there is not a second; yea, he hath neither child nor brother: yet is there no end of all his labour; neither is his eye satisfied with riches; neither saith he, For whom do I labour, and bereave my soul of good? This is also vanity, yea, it is a sore travail."},{"verse":9,"text":"Two are better than one; because they have a good reward for their labour."},{"verse":10,"text":"For if they fall, the one will lift up his fellow: but woe to him that is alone when he falleth; for he hath not another to help him up."},{"verse":11,"text":"Again, if two lie together, then they have heat: but how can one be warm alone?"},{"verse":12,"text":"And if one prevail against him, two shall withstand him; and a threefold cord is not quickly broken."},{"verse":13,"text":"Better is a poor and a wise child than an old and foolish king, who will no more be admonished."},{"verse":14,"text":"For out of prison he cometh to reign; whereas also he that is born in his kingdom becometh poor."},{"verse":15,"text":"I considered all the living which walk under the sun, with the second child that shall stand up in his stead."},{"verse":16,"text":"There is no end of all the people, even of all that have been before them: they also that come after shall not rejoice in him. Surely this also is vanity and vexation of spirit. "}]},{"chapter":5,"verses":[{"verse":1,"text":"Keep thy foot when thou goest to the house of God, and be more ready to hear, than to give the sacrifice of fools: for they consider not that they do evil."},{"verse":2,"text":"Be not rash with thy mouth, and let not thine heart be hasty to utter any thing before God: for God is in heaven, and thou upon earth: therefore let thy words be few."},{"verse":3,"text":"For a dream cometh through the multitude of business; and a fool’s voice is known by multitude of words."},{"verse":4,"text":"When thou vowest a vow unto God, defer not to pay it; for he hath no pleasure in fools: pay that which thou hast vowed."},{"verse":5,"text":"Better is it that thou shouldest not vow, than that thou shouldest vow and not pay."},{"verse":6,"text":"Suffer not thy mouth to cause thy flesh to sin; neither say thou before the angel, that it was an error: wherefore should God be angry at thy voice, and destroy the work of thine hands?"},{"verse":7,"text":"For in the multitude of dreams and many words there are also divers vanities: but fear thou God."},{"verse":8,"text":"If thou seest the oppression of the poor, and violent perverting of judgment and justice in a province, marvel not at the matter: for he that is higher than the highest regardeth; and there be higher than they."},{"verse":9,"text":"Moreover the profit of the earth is for all: the king himself is served by the field."},{"verse":10,"text":"He that loveth silver shall not be satisfied with silver; nor he that loveth abundance with increase: this is also vanity."},{"verse":11,"text":"When goods increase, they are increased that eat them: and what good is there to the owners thereof, saving the beholding of them with their eyes?"},{"verse":12,"text":"The sleep of a labouring man is sweet, whether he eat little or much: but the abundance of the rich will not suffer him to sleep."},{"verse":13,"text":"There is a sore evil which I have seen under the sun, namely, riches kept for the owners thereof to their hurt."},{"verse":14,"text":"But those riches perish by evil travail: and he begetteth a son, and there is nothing in his hand."},{"verse":15,"text":"As he came forth of his mother’s womb, naked shall he return to go as he came, and shall take nothing of his labour, which he may carry away in his hand."},{"verse":16,"text":"And this also is a sore evil, that in all points as he came, so shall he go: and what profit hath he that hath laboured for the wind?"},{"verse":17,"text":"All his days also he eateth in darkness, and he hath much sorrow and wrath with his sickness."},{"verse":18,"text":"Behold that which I have seen: it is good and comely for one to eat and to drink, and to enjoy the good of all his labour that he taketh under the sun all the days of his life, which God giveth him: for it is his portion."},{"verse":19,"text":"Every man also to whom God hath given riches and wealth, and hath given him power to eat thereof, and to take his portion, and to rejoice in his labour; this is the gift of God."},{"verse":20,"text":"For he shall not much remember the days of his life; because God answereth him in the joy of his heart. "}]},{"chapter":6,"verses":[{"verse":1,"text":"There is an evil which I have seen under the sun, and it is common among men:"},{"verse":2,"text":"A man to whom God hath given riches, wealth, and honour, so that he wanteth nothing for his soul of all that he desireth, yet God giveth him not power to eat thereof, but a stranger eateth it: this is vanity, and it is an evil disease."},{"verse":3,"text":"If a man beget an hundred children, and live many years, so that the days of his years be many, and his soul be not filled with good, and also that he have no burial; I say, that an untimely birth is better than he."},{"verse":4,"text":"For he cometh in with vanity, and departeth in darkness, and his name shall be covered with darkness."},{"verse":5,"text":"Moreover he hath not seen the sun, nor known any thing: this hath more rest than the other."},{"verse":6,"text":"Yea, though he live a thousand years twice told, yet hath he seen no good: do not all go to one place?"},{"verse":7,"text":"All the labour of man is for his mouth, and yet the appetite is not filled."},{"verse":8,"text":"For what hath the wise more than the fool? what hath the poor, that knoweth to walk before the living?"},{"verse":9,"text":"Better is the sight of the eyes than the wandering of the desire: this is also vanity and vexation of spirit."},{"verse":10,"text":"That which hath been is named already, and it is known that it is man: neither may he contend with him that is mightier than he."},{"verse":11,"text":"Seeing there be many things that increase vanity, what is man the better?"},{"verse":12,"text":"For who knoweth what is good for man in this life, all the days of his vain life which he spendeth as a shadow? for who can tell a man what shall be after him under the sun? "}]},{"chapter":7,"verses":[{"verse":1,"text":"A good name is better than precious ointment; and the day of death than the day of one’s birth."},{"verse":2,"text":"It is better to go to the house of mourning, than to go to the house of feasting: for that is the end of all men; and the living will lay it to his heart."},{"verse":3,"text":"Sorrow is better than laughter: for by the sadness of the countenance the heart is made better."},{"verse":4,"text":"The heart of the wise is in the house of mourning; but the heart of fools is in the house of mirth."},{"verse":5,"text":"It is better to hear the rebuke of the wise, than for a man to hear the song of fools."},{"verse":6,"text":"For as the crackling of thorns under a pot, so is the laughter of the fool: this also is vanity."},{"verse":7,"text":"Surely oppression maketh a wise man mad; and a gift destroyeth the heart."},{"verse":8,"text":"Better is the end of a thing than the beginning thereof: and the patient in spirit is better than the proud in spirit."},{"verse":9,"text":"Be not hasty in thy spirit to be angry: for anger resteth in the bosom of fools."},{"verse":10,"text":"Say not thou, What is the cause that the former days were better than these? for thou dost not enquire wisely concerning this."},{"verse":11,"text":"Wisdom is good with an inheritance: and by it there is profit to them that see the sun."},{"verse":12,"text":"For wisdom is a defence, and money is a defence: but the excellency of knowledge is, that wisdom giveth life to them that have it."},{"verse":13,"text":"Consider the work of God: for who can make that straight, which he hath made crooked?"},{"verse":14,"text":"In the day of prosperity be joyful, but in the day of adversity consider: God also hath set the one over against the other, to the end that man should find nothing after him."},{"verse":15,"text":"All things have I seen in the days of my vanity: there is a just man that perisheth in his righteousness, and there is a wicked man that prolongeth his life in his wickedness."},{"verse":16,"text":"Be not righteous over much; neither make thyself over wise: why shouldest thou destroy thyself?"},{"verse":17,"text":"Be not over much wicked, neither be thou foolish: why shouldest thou die before thy time?"},{"verse":18,"text":"It is good that thou shouldest take hold of this; yea, also from this withdraw not thine hand: for he that feareth God shall come forth of them all."},{"verse":19,"text":"Wisdom strengtheneth the wise more than ten mighty men which are in the city."},{"verse":20,"text":"For there is not a just man upon earth, that doeth good, and sinneth not."},{"verse":21,"text":"Also take no heed unto all words that are spoken; lest thou hear thy servant curse thee:"},{"verse":22,"text":"For oftentimes also thine own heart knoweth that thou thyself likewise hast cursed others."},{"verse":23,"text":"All this have I proved by wisdom: I said, I will be wise; but it was far from me."},{"verse":24,"text":"That which is far off, and exceeding deep, who can find it out?"},{"verse":25,"text":"I applied mine heart to know, and to search, and to seek out wisdom, and the reason of things, and to know the wickedness of folly, even of foolishness and madness:"},{"verse":26,"text":"And I find more bitter than death the woman, whose heart is snares and nets, and her hands as bands: whoso pleaseth God shall escape from her; but the sinner shall be taken by her."},{"verse":27,"text":"Behold, this have I found, saith the preacher, counting one by one, to find out the account:"},{"verse":28,"text":"Which yet my soul seeketh, but I find not: one man among a thousand have I found; but a woman among all those have I not found."},{"verse":29,"text":"Lo, this only have I found, that God hath made man upright; but they have sought out many inventions. "}]},{"chapter":8,"verses":[{"verse":1,"text":"Who is as the wise man? and who knoweth the interpretation of a thing? a man’s wisdom maketh his face to shine, and the boldness of his face shall be changed."},{"verse":2,"text":"I counsel thee to keep the king’s commandment, and that in regard of the oath of God."},{"verse":3,"text":"Be not hasty to go out of his sight: stand not in an evil thing; for he doeth whatsoever pleaseth him."},{"verse":4,"text":"Where the word of a king is, there is power: and who may say unto him, What doest thou?"},{"verse":5,"text":"Whoso keepeth the commandment shall feel no evil thing: and a wise man’s heart discerneth both time and judgment."},{"verse":6,"text":"Because to every purpose there is time and judgment, therefore the misery of man is great upon him."},{"verse":7,"text":"For he knoweth not that which shall be: for who can tell him when it shall be?"},{"verse":8,"text":"There is no man that hath power over the spirit to retain the spirit; neither hath he power in the day of death: and there is no discharge in that war; neither shall wickedness deliver those that are given to it."},{"verse":9,"text":"All this have I seen, and applied my heart unto every work that is done under the sun: there is a time wherein one man ruleth over another to his own hurt."},{"verse":10,"text":"And so I saw the wicked buried, who had come and gone from the place of the holy, and they were forgotten in the city where they had so done: this is also vanity."},{"verse":11,"text":"Because sentence against an evil work is not executed speedily, therefore the heart of the sons of men is fully set in them to do evil."},{"verse":12,"text":"Though a sinner do evil an hundred times, and his days be prolonged, yet surely I know that it shall be well with them that fear God, which fear before him:"},{"verse":13,"text":"But it shall not be well with the wicked, neither shall he prolong his days, which are as a shadow; because he feareth not before God."},{"verse":14,"text":"There is a vanity which is done upon the earth; that there be just men, unto whom it happeneth according to the work of the wicked; again, there be wicked men, to whom it happeneth according to the work of the righteous: I said that this also is vanity."},{"verse":15,"text":"Then I commended mirth, because a man hath no better thing under the sun, than to eat, and to drink, and to be merry: for that shall abide with him of his labour the days of his life, which God giveth him under the sun."},{"verse":16,"text":"When I applied mine heart to know wisdom, and to see the business that is done upon the earth: (for also there is that neither day nor night seeth sleep with his eyes:)"},{"verse":17,"text":"Then I beheld all the work of God, that a man cannot find out the work that is done under the sun: because though a man labour to seek it out, yet he shall not find it; yea further; though a wise man think to know it, yet shall he not be able to find it. "}]},{"chapter":9,"verses":[{"verse":1,"text":"For all this I considered in my heart even to declare all this, that the righteous, and the wise, and their works, are in the hand of God: no man knoweth either love or hatred by all that is before them."},{"verse":2,"text":"All things come alike to all: there is one event to the righteous, and to the wicked; to the good and to the clean, and to the unclean; to him that sacrificeth, and to him that sacrificeth not: as is the good, so is the sinner; and he that sweareth, as he that feareth an oath."},{"verse":3,"text":"This is an evil among all things that are done under the sun, that there is one event unto all: yea, also the heart of the sons of men is full of evil, and madness is in their heart while they live, and after that they go to the dead."},{"verse":4,"text":"For to him that is joined to all the living there is hope: for a living dog is better than a dead lion."},{"verse":5,"text":"For the living know that they shall die: but the dead know not any thing, neither have they any more a reward; for the memory of them is forgotten."},{"verse":6,"text":"Also their love, and their hatred, and their envy, is now perished; neither have they any more a portion for ever in any thing that is done under the sun."},{"verse":7,"text":"Go thy way, eat thy bread with joy, and drink thy wine with a merry heart; for God now accepteth thy works."},{"verse":8,"text":"Let thy garments be always white; and let thy head lack no ointment."},{"verse":9,"text":"Live joyfully with the wife whom thou lovest all the days of the life of thy vanity, which he hath given thee under the sun, all the days of thy vanity: for that is thy portion in this life, and in thy labour which thou takest under the sun."},{"verse":10,"text":"Whatsoever thy hand findeth to do, do it with thy might; for there is no work, nor device, nor knowledge, nor wisdom, in the grave, whither thou goest."},{"verse":11,"text":"I returned, and saw under the sun, that the race is not to the swift, nor the battle to the strong, neither yet bread to the wise, nor yet riches to men of understanding, nor yet favour to men of skill; but time and chance happeneth to them all."},{"verse":12,"text":"For man also knoweth not his time: as the fishes that are taken in an evil net, and as the birds that are caught in the snare; so are the sons of men snared in an evil time, when it falleth suddenly upon them."},{"verse":13,"text":"This wisdom have I seen also under the sun, and it seemed great unto me:"},{"verse":14,"text":"There was a little city, and few men within it; and there came a great king against it, and besieged it, and built great bulwarks against it:"},{"verse":15,"text":"Now there was found in it a poor wise man, and he by his wisdom delivered the city; yet no man remembered that same poor man."},{"verse":16,"text":"Then said I, Wisdom is better than strength: nevertheless the poor man’s wisdom is despised, and his words are not heard."},{"verse":17,"text":"The words of wise men are heard in quiet more than the cry of him that ruleth among fools."},{"verse":18,"text":"Wisdom is better than weapons of war: but one sinner destroyeth much good. "}]},{"chapter":10,"verses":[{"verse":1,"text":"Dead flies cause the ointment of the apothecary to send forth a stinking savour: so doth a little folly him that is in reputation for wisdom and honour."},{"verse":2,"text":"A wise man’s heart is at his right hand; but a fool’s heart at his left."},{"verse":3,"text":"Yea also, when he that is a fool walketh by the way, his wisdom faileth him, and he saith to every one that he is a fool."},{"verse":4,"text":"If the spirit of the ruler rise up against thee, leave not thy place; for yielding pacifieth great offences."},{"verse":5,"text":"There is an evil which I have seen under the sun, as an error which proceedeth from the ruler:"},{"verse":6,"text":"Folly is set in great dignity, and the rich sit in low place."},{"verse":7,"text":"I have seen servants upon horses, and princes walking as servants upon the earth."},{"verse":8,"text":"He that diggeth a pit shall fall into it; and whoso breaketh an hedge, a serpent shall bite him."},{"verse":9,"text":"Whoso removeth stones shall be hurt therewith; and he that cleaveth wood shall be endangered thereby."},{"verse":10,"text":"If the iron be blunt, and he do not whet the edge, then must he put to more strength: but wisdom is profitable to direct."},{"verse":11,"text":"Surely the serpent will bite without enchantment; and a babbler is no better."},{"verse":12,"text":"The words of a wise man’s mouth are gracious; but the lips of a fool will swallow up himself."},{"verse":13,"text":"The beginning of the words of his mouth is foolishness: and the end of his talk is mischievous madness."},{"verse":14,"text":"A fool also is full of words: a man cannot tell what shall be; and what shall be after him, who can tell him?"},{"verse":15,"text":"The labour of the foolish wearieth every one of them, because he knoweth not how to go to the city."},{"verse":16,"text":"Woe to thee, O land, when thy king is a child, and thy princes eat in the morning!"},{"verse":17,"text":"Blessed art thou, O land, when thy king is the son of nobles, and thy princes eat in due season, for strength, and not for drunkenness!"},{"verse":18,"text":"By much slothfulness the building decayeth; and through idleness of the hands the house droppeth through."},{"verse":19,"text":"A feast is made for laughter, and wine maketh merry: but money answereth all things."},{"verse":20,"text":"Curse not the king, no not in thy thought; and curse not the rich in thy bedchamber: for a bird of the air shall carry the voice, and that which hath wings shall tell the matter. "}]},{"chapter":11,"verses":[{"verse":1,"text":"Cast thy bread upon the waters: for thou shalt find it after many days."},{"verse":2,"text":"Give a portion to seven, and also to eight; for thou knowest not what evil shall be upon the earth."},{"verse":3,"text":"If the clouds be full of rain, they empty themselves upon the earth: and if the tree fall toward the south, or toward the north, in the place where the tree falleth, there it shall be."},{"verse":4,"text":"He that observeth the wind shall not sow; and he that regardeth the clouds shall not reap."},{"verse":5,"text":"As thou knowest not what is the way of the spirit, nor how the bones do grow in the womb of her that is with child: even so thou knowest not the works of God who maketh all."},{"verse":6,"text":"In the morning sow thy seed, and in the evening withhold not thine hand: for thou knowest not whether shall prosper, either this or that, or whether they both shall be alike good."},{"verse":7,"text":"Truly the light is sweet, and a pleasant thing it is for the eyes to behold the sun:"},{"verse":8,"text":"But if a man live many years, and rejoice in them all; yet let him remember the days of darkness; for they shall be many. All that cometh is vanity."},{"verse":9,"text":"Rejoice, O young man, in thy youth; and let thy heart cheer thee in the days of thy youth, and walk in the ways of thine heart, and in the sight of thine eyes: but know thou, that for all these things God will bring thee into judgment."},{"verse":10,"text":"Therefore remove sorrow from thy heart, and put away evil from thy flesh: for childhood and youth are vanity. "}]},{"chapter":12,"verses":[{"verse":1,"text":"Remember now thy Creator in the days of thy youth, while the evil days come not, nor the years draw nigh, when thou shalt say, I have no pleasure in them;"},{"verse":2,"text":"While the sun, or the light, or the moon, or the stars, be not darkened, nor the clouds return after the rain:"},{"verse":3,"text":"In the day when the keepers of the house shall tremble, and the strong men shall bow themselves, and the grinders cease because they are few, and those that look out of the windows be darkened,"},{"verse":4,"text":"And the doors shall be shut in the streets, when the sound of the grinding is low, and he shall rise up at the voice of the bird, and all the daughters of musick shall be brought low;"},{"verse":5,"text":"Also when they shall be afraid of that which is high, and fears shall be in the way, and the almond tree shall flourish, and the grasshopper shall be a burden, and desire shall fail: because man goeth to his long home, and the mourners go about the streets:"},{"verse":6,"text":"Or ever the silver cord be loosed, or the golden bowl be broken, or the pitcher be broken at the fountain, or the wheel broken at the cistern."},{"verse":7,"text":"Then shall the dust return to the earth as it was: and the spirit shall return unto God who gave it."},{"verse":8,"text":"Vanity of vanities, saith the preacher; all is vanity."},{"verse":9,"text":"And moreover, because the preacher was wise, he still taught the people knowledge; yea, he gave good heed, and sought out, and set in order many proverbs."},{"verse":10,"text":"The preacher sought to find out acceptable words: and that which was written was upright, even words of truth."},{"verse":11,"text":"The words of the wise are as goads, and as nails fastened by the masters of assemblies, which are given from one shepherd."},{"verse":12,"text":"And further, by these, my son, be admonished: of making many books there is no end; and much study is a weariness of the flesh."},{"verse":13,"text":"Let us hear the conclusion of the whole matter: Fear God, and keep his commandments: for this is the whole duty of man."},{"verse":14,"text":"For God shall bring every work into judgment, with every secret thing, whether it be good, or whether it be evil.  "}]}]},{"name":"Song of Solomon","chapters":[{"chapter":1,"verses":[{"verse":1,"text":"The song of songs, which is Solomon’s."},{"verse":2,"text":"Let him kiss me with the kisses of his mouth: for thy love is better than wine."},{"verse":3,"text":"Because of the savour of thy good ointments thy name is as ointment poured forth, therefore do the virgins love thee."},{"verse":4,"text":"Draw me, we will run after thee: the king hath brought me into his chambers: we will be glad and rejoice in thee, we will remember thy love more than wine: the upright love thee."},{"verse":5,"text":"I am black, but comely, O ye daughters of Jerusalem, as the tents of Kedar, as the curtains of Solomon."},{"verse":6,"text":"Look not upon me, because I am black, because the sun hath looked upon me: my mother’s children were angry with me; they made me the keeper of the vineyards; but mine own vineyard have I not kept."},{"verse":7,"text":"Tell me, O thou whom my soul loveth, where thou feedest, where thou makest thy flock to rest at noon: for why should I be as one that turneth aside by the flocks of thy companions?"},{"verse":8,"text":"If thou know not, O thou fairest among women, go thy way forth by the footsteps of the flock, and feed thy kids beside the shepherds’ tents."},{"verse":9,"text":"I have compared thee, O my love, to a company of horses in Pharaoh’s chariots."},{"verse":10,"text":"Thy cheeks are comely with rows of jewels, thy neck with chains of gold."},{"verse":11,"text":"We will make thee borders of gold with studs of silver."},{"verse":12,"text":"While the king sitteth at his table, my spikenard sendeth forth the smell thereof."},{"verse":13,"text":"A bundle of myrrh is my wellbeloved unto me; he shall lie all night betwixt my breasts."},{"verse":14,"text":"My beloved is unto me as a cluster of camphire in the vineyards of En–gedi."},{"verse":15,"text":"Behold, thou art fair, my love; behold, thou art fair; thou hast doves’ eyes."},{"verse":16,"text":"Behold, thou art fair, my beloved, yea, pleasant: also our bed is green."},{"verse":17,"text":"The beams of our house are cedar, and our rafters of fir. "}]},{"chapter":2,"verses":[{"verse":1,"text":"I am the rose of Sharon, and the lily of the valleys."},{"verse":2,"text":"As the lily among thorns, so is my love among the daughters."},{"verse":3,"text":"As the apple tree among the trees of the wood, so is my beloved among the sons. I sat down under his shadow with great delight, and his fruit was sweet to my taste."},{"verse":4,"text":"He brought me to the banqueting house, and his banner over me was love."},{"verse":5,"text":"Stay me with flagons, comfort me with apples: for I am sick of love."},{"verse":6,"text":"His left hand is under my head, and his right hand doth embrace me."},{"verse":7,"text":"I charge you, O ye daughters of Jerusalem, by the roes, and by the hinds of the field, that ye stir not up, nor awake my love, till he please."},{"verse":8,"text":"The voice of my beloved! behold, he cometh leaping upon the mountains, skipping upon the hills."},{"verse":9,"text":"My beloved is like a roe or a young hart: behold, he standeth behind our wall, he looketh forth at the windows, shewing himself through the lattice."},{"verse":10,"text":"My beloved spake, and said unto me, Rise up, my love, my fair one, and come away."},{"verse":11,"text":"For, lo, the winter is past, the rain is over and gone;"},{"verse":12,"text":"The flowers appear on the earth; the time of the singing of birds is come, and the voice of the turtle is heard in our land;"},{"verse":13,"text":"The fig tree putteth forth her green figs, and the vines with the tender grape give a good smell. Arise, my love, my fair one, and come away."},{"verse":14,"text":"O my dove, that art in the clefts of the rock, in the secret places of the stairs, let me see thy countenance, let me hear thy voice; for sweet is thy voice, and thy countenance is comely."},{"verse":15,"text":"Take us the foxes, the little foxes, that spoil the vines: for our vines have tender grapes."},{"verse":16,"text":"My beloved is mine, and I am his: he feedeth among the lilies."},{"verse":17,"text":"Until the day break, and the shadows flee away, turn, my beloved, and be thou like a roe or a young hart upon the mountains of Bether. "}]},{"chapter":3,"verses":[{"verse":1,"text":"By night on my bed I sought him whom my soul loveth: I sought him, but I found him not."},{"verse":2,"text":"I will rise now, and go about the city in the streets, and in the broad ways I will seek him whom my soul loveth: I sought him, but I found him not."},{"verse":3,"text":"The watchmen that go about the city found me: to whom I said, Saw ye him whom my soul loveth?"},{"verse":4,"text":"It was but a little that I passed from them, but I found him whom my soul loveth: I held him, and would not let him go, until I had brought him into my mother’s house, and into the chamber of her that conceived me."},{"verse":5,"text":"I charge you, O ye daughters of Jerusalem, by the roes, and by the hinds of the field, that ye stir not up, nor awake my love, till he please."},{"verse":6,"text":"Who is this that cometh out of the wilderness like pillars of smoke, perfumed with myrrh and frankincense, with all powders of the merchant?"},{"verse":7,"text":"Behold his bed, which is Solomon’s; threescore valiant men are about it, of the valiant of Israel."},{"verse":8,"text":"They all hold swords, being expert in war: every man hath his sword upon his thigh because of fear in the night."},{"verse":9,"text":"King Solomon made himself a chariot of the wood of Lebanon."},{"verse":10,"text":"He made the pillars thereof of silver, the bottom thereof of gold, the covering of it of purple, the midst thereof being paved with love, for the daughters of Jerusalem."},{"verse":11,"text":"Go forth, O ye daughters of Zion, and behold king Solomon with the crown wherewith his mother crowned him in the day of his espousals, and in the day of the gladness of his heart. "}]},{"chapter":4,"verses":[{"verse":1,"text":"Behold, thou art fair, my love; behold, thou art fair; thou hast doves’ eyes within thy locks: thy hair is as a flock of goats, that appear from mount Gilead."},{"verse":2,"text":"Thy teeth are like a flock of sheep that are even shorn, which came up from the washing; whereof every one bear twins, and none is barren among them."},{"verse":3,"text":"Thy lips are like a thread of scarlet, and thy speech is comely: thy temples are like a piece of a pomegranate within thy locks."},{"verse":4,"text":"Thy neck is like the tower of David builded for an armoury, whereon there hang a thousand bucklers, all shields of mighty men."},{"verse":5,"text":"Thy two breasts are like two young roes that are twins, which feed among the lilies."},{"verse":6,"text":"Until the day break, and the shadows flee away, I will get me to the mountain of myrrh, and to the hill of frankincense."},{"verse":7,"text":"Thou art all fair, my love; there is no spot in thee."},{"verse":8,"text":"Come with me from Lebanon, my spouse, with me from Lebanon: look from the top of Amana, from the top of Shenir and Hermon, from the lions’ dens, from the mountains of the leopards."},{"verse":9,"text":"Thou hast ravished my heart, my sister, my spouse; thou hast ravished my heart with one of thine eyes, with one chain of thy neck."},{"verse":10,"text":"How fair is thy love, my sister, my spouse! how much better is thy love than wine! and the smell of thine ointments than all spices!"},{"verse":11,"text":"Thy lips, O my spouse, drop as the honeycomb: honey and milk are under thy tongue; and the smell of thy garments is like the smell of Lebanon."},{"verse":12,"text":"A garden inclosed is my sister, my spouse; a spring shut up, a fountain sealed."},{"verse":13,"text":"Thy plants are an orchard of pomegranates, with pleasant fruits; camphire, with spikenard,"},{"verse":14,"text":"Spikenard and saffron; calamus and cinnamon, with all trees of frankincense; myrrh and aloes, with all the chief spices:"},{"verse":15,"text":"A fountain of gardens, a well of living waters, and streams from Lebanon."},{"verse":16,"text":"Awake, O north wind; and come, thou south; blow upon my garden, that the spices thereof may flow out. Let my beloved come into his garden, and eat his pleasant fruits. "}]},{"chapter":5,"verses":[{"verse":1,"text":"I am come into my garden, my sister, my spouse: I have gathered my myrrh with my spice; I have eaten my honeycomb with my honey; I have drunk my wine with my milk: eat, O friends; drink, yea, drink abundantly, O beloved."},{"verse":2,"text":"I sleep, but my heart waketh: it is the voice of my beloved that knocketh, saying, Open to me, my sister, my love, my dove, my undefiled: for my head is filled with dew, and my locks with the drops of the night."},{"verse":3,"text":"I have put off my coat; how shall I put it on? I have washed my feet; how shall I defile them?"},{"verse":4,"text":"My beloved put in his hand by the hole of the door, and my bowels were moved for him."},{"verse":5,"text":"I rose up to open to my beloved; and my hands dropped with myrrh, and my fingers with sweet smelling myrrh, upon the handles of the lock."},{"verse":6,"text":"I opened to my beloved; but my beloved had withdrawn himself, and was gone: my soul failed when he spake: I sought him, but I could not find him; I called him, but he gave me no answer."},{"verse":7,"text":"The watchmen that went about the city found me, they smote me, they wounded me; the keepers of the walls took away my veil from me."},{"verse":8,"text":"I charge you, O daughters of Jerusalem, if ye find my beloved, that ye tell him, that I am sick of love."},{"verse":9,"text":"What is thy beloved more than another beloved, O thou fairest among women? what is thy beloved more than another beloved, that thou dost so charge us?"},{"verse":10,"text":"My beloved is white and ruddy, the chiefest among ten thousand."},{"verse":11,"text":"His head is as the most fine gold, his locks are bushy, and black as a raven."},{"verse":12,"text":"His eyes are as the eyes of doves by the rivers of waters, washed with milk, and fitly set."},{"verse":13,"text":"His cheeks are as a bed of spices, as sweet flowers: his lips like lilies, dropping sweet smelling myrrh."},{"verse":14,"text":"His hands are as gold rings set with the beryl: his belly is as bright ivory overlaid with sapphires."},{"verse":15,"text":"His legs are as pillars of marble, set upon sockets of fine gold: his countenance is as Lebanon, excellent as the cedars."},{"verse":16,"text":"His mouth is most sweet: yea, he is altogether lovely. This is my beloved, and this is my friend, O daughters of Jerusalem. "}]},{"chapter":6,"verses":[{"verse":1,"text":"Whither is thy beloved gone, O thou fairest among women? whither is thy beloved turned aside? that we may seek him with thee."},{"verse":2,"text":"My beloved is gone down into his garden, to the beds of spices, to feed in the gardens, and to gather lilies."},{"verse":3,"text":"I am my beloved’s, and my beloved is mine: he feedeth among the lilies."},{"verse":4,"text":"Thou art beautiful, O my love, as Tirzah, comely as Jerusalem, terrible as an army with banners."},{"verse":5,"text":"Turn away thine eyes from me, for they have overcome me: thy hair is as a flock of goats that appear from Gilead."},{"verse":6,"text":"Thy teeth are as a flock of sheep which go up from the washing, whereof every one beareth twins, and there is not one barren among them."},{"verse":7,"text":"As a piece of a pomegranate are thy temples within thy locks."},{"verse":8,"text":"There are threescore queens, and fourscore concubines, and virgins without number."},{"verse":9,"text":"My dove, my undefiled is but one; she is the only one of her mother, she is the choice one of her that bare her. The daughters saw her, and blessed her; yea, the queens and the concubines, and they praised her."},{"verse":10,"text":"Who is she that looketh forth as the morning, fair as the moon, clear as the sun, and terrible as an army with banners?"},{"verse":11,"text":"I went down into the garden of nuts to see the fruits of the valley, and to see whether the vine flourished, and the pomegranates budded."},{"verse":12,"text":"Or ever I was aware, my soul made me like the chariots of Amminadib."},{"verse":13,"text":"Return, return, O Shulamite; return, return, that we may look upon thee. What will ye see in the Shulamite? As it were the company of two armies. "}]},{"chapter":7,"verses":[{"verse":1,"text":"How beautiful are thy feet with shoes, O prince’s daughter! the joints of thy thighs are like jewels, the work of the hands of a cunning workman."},{"verse":2,"text":"Thy navel is like a round goblet, which wanteth not liquor: thy belly is like an heap of wheat set about with lilies."},{"verse":3,"text":"Thy two breasts are like two young roes that are twins."},{"verse":4,"text":"Thy neck is as a tower of ivory; thine eyes like the fishpools in Heshbon, by the gate of Bath–rabbim: thy nose is as the tower of Lebanon which looketh toward Damascus."},{"verse":5,"text":"Thine head upon thee is like Carmel, and the hair of thine head like purple; the king is held in the galleries."},{"verse":6,"text":"How fair and how pleasant art thou, O love, for delights!"},{"verse":7,"text":"This thy stature is like to a palm tree, and thy breasts to clusters of grapes."},{"verse":8,"text":"I said, I will go up to the palm tree, I will take hold of the boughs thereof: now also thy breasts shall be as clusters of the vine, and the smell of thy nose like apples;"},{"verse":9,"text":"And the roof of thy mouth like the best wine for my beloved, that goeth down sweetly, causing the lips of those that are asleep to speak."},{"verse":10,"text":"I am my beloved’s, and his desire is toward me."},{"verse":11,"text":"Come, my beloved, let us go forth into the field; let us lodge in the villages."},{"verse":12,"text":"Let us get up early to the vineyards; let us see if the vine flourish, whether the tender grape appear, and the pomegranates bud forth: there will I give thee my loves."},{"verse":13,"text":"The mandrakes give a smell, and at our gates are all manner of pleasant fruits, new and old, which I have laid up for thee, O my beloved. "}]},{"chapter":8,"verses":[{"verse":1,"text":"O that thou wert as my brother, that sucked the breasts of my mother! when I should find thee without, I would kiss thee; yea, I should not be despised."},{"verse":2,"text":"I would lead thee, and bring thee into my mother’s house, who would instruct me: I would cause thee to drink of spiced wine of the juice of my pomegranate."},{"verse":3,"text":"His left hand should be under my head, and his right hand should embrace me."},{"verse":4,"text":"I charge you, O daughters of Jerusalem, that ye stir not up, nor awake my love, until he please."},{"verse":5,"text":"Who is this that cometh up from the wilderness, leaning upon her beloved? I raised thee up under the apple tree: there thy mother brought thee forth: there she brought thee forth that bare thee."},{"verse":6,"text":"Set me as a seal upon thine heart, as a seal upon thine arm: for love is strong as death; jealousy is cruel as the grave: the coals thereof are coals of fire, which hath a most vehement flame."},{"verse":7,"text":"Many waters cannot quench love, neither can the floods drown it: if a man would give all the substance of his house for love, it would utterly be contemned."},{"verse":8,"text":"We have a little sister, and she hath no breasts: what shall we do for our sister in the day when she shall be spoken for?"},{"verse":9,"text":"If she be a wall, we will build upon her a palace of silver: and if she be a door, we will inclose her with boards of cedar."},{"verse":10,"text":"I am a wall, and my breasts like towers: then was I in his eyes as one that found favour."},{"verse":11,"text":"Solomon had a vineyard at Baal–hamon; he let out the vineyard unto keepers; every one for the fruit thereof was to bring a thousand pieces of silver."},{"verse":12,"text":"My vineyard, which is mine, is before me: thou, O Solomon, must have a thousand, and those that keep the fruit thereof two hundred."},{"verse":13,"text":"Thou that dwellest in the gardens, the companions hearken to thy voice: cause me to hear it."},{"verse":14,"text":"Make haste, my beloved, and be thou like to a roe or to a young hart upon the mountains of spices.  "}]}]});
